INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (4406, 'Once a text editor is associated with a text format, you can configure it by clicking on the <em>Configure</em> link for this format. Depending on the specific text editor, you can configure it for example by adding buttons to its toolbar. Typically these buttons provide formatting or editing tools, and they often insert HTML tags into the field source. For details, see the help page of the specific text editor.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (4407, 'Using different text editors and formats', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (4408, 'If you change the text format on a text field, the text editor will change as well because the text editor configuration is associated with the individual text format. This allows the use of the same text editor with different options for different text formats. It also allows users to choose between text formats with different text editors if they are installed.', '', 'none');
