INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (4548, 'In the field settings you can define additional link text to be <em>optional</em> or <em>required</em> in any link field.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (4549, 'Displaying link text', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (4550, 'If link text has been submitted for a URL, then by default this link text is displayed as a link to the URL. If you want to display both the link text <em>and</em> the URL, choose the appropriate link format from the drop-down menu in the <em>Manage display</em> page. If you only want to display the URL even if link text has been submitted, choose <em>Link</em> as the format, and then change its <em>Format settings</em> to display <em>URL only</em>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (4551, 'Adding attributes to links', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (4552, 'You can add attributes to links, by changing the <em>Format settings</em> in the <em>Manage display</em> page. Adding <em>rel="nofollow"</em> notifies search engines that links should not be followed.', '', 'none');
