INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (4559, 'The Serialization module provides a service for serializing and deserializing data to and from formats such as JSON and XML.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (4560, 'Serialization is the process of converting data structures like arrays and objects into a string. This allows the data to be represented in a way that is easy to exchange and store (for example, for transmission over the Internet or for storage in a local file system). These representations can then be deserialized to get back to the original data structures.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (4561, 'The serializer splits this process into two parts. Normalization converts an object to a normalized array structure. Encoding takes that array and converts it to a string.', '', 'none');
