INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (4640, 'You can control the visibility of a block by restricting it to specific pages, content types, and/or roles by setting the appropriate options under <em>Visibility settings</em> of the block configuration.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (4641, 'Unless you''re experiencing problems with pagers related to this field, you should leave this at 0. If using multiple pagers on one page you may need to set this number to a higher value so as not to conflict within the ?page= array. Large values will add a lot of commas to your URLs, so avoid if possible.', '', 'none');
