INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (4647, 'Managing and displaying file fields', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (4648, 'Allowing file extensions', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (4649, 'In the field settings, you can define the allowed file extensions (for example <em>pdf docx psd</em>) for the files that will be uploaded with the file field.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (4650, 'Restricting the maximum file size', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (4651, 'The maximum file size that users can upload is limited by PHP settings of the server, but you can restrict by entering the desired value as the <em>Maximum upload size</em> setting. The maximum file size is automatically displayed to users in the help text of the file field.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (4652, 'Displaying files and descriptions', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (4653, 'In the field settings, you can allow users to toggle whether individual files are displayed. In the display settings, you can then choose one of the following formats: <ul><li><em>Generic file</em> displays links to the files and adds icons that symbolize the file extensions. If <em>descriptions</em> are enabled and have been submitted, then the description is displayed instead of the file name.</li><li><em>URL to file</em> displays the full path to the file as plain text.</li><li><em>Table of files</em> lists links to the files and the file sizes in a table.</li><li><em>RSS enclosure</em> only displays the first file, and only in a RSS feed, formatted according to the RSS 2.0 syntax for enclosures.</li></ul> A file can still be linked to directly by its URI even if it is not displayed.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (4654, 'Flag to control whether this file should be displayed when viewing content', '', 'none');
