INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (4682, 'The Views module provides a back end to fetch information from content, user accounts, taxonomy terms, and other entities from the database and present it to the user as a grid, HTML list, table, unformatted list, etc. The resulting displays are known generally as <em>views</em>.', '', 'none');
