INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (4684, 'The Views module adds functionality to some core administration pages. For example, <em>admin/content</em> uses Views to filter and sort content. With Views uninstalled, <em>admin/content</em> is more limited.', '', 'none');
