INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (4708, 'Influence is a numeric multiplier used in ordering search results. A higher number means the corresponding factor has more influence on search results; zero means the factor is ignored. Changing these numbers does not require the search index to be rebuilt. Changes take effect immediately.', '', 'none');
