INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (4746, 'Depending on the chosen entity type, additional filtering and sorting options are available for the list of entities that can be referred to, in the field settings. For example, the list of users can be filtered by role and sorted by name or ID.', '', 'none');
