INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5275, 'Comment type %label has been added.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5276, 'The comment author''s email address.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5277, 'Comment Type', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5278, 'The comment type.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5279, '%label is used by the %field field on your site. You can not remove this comment type until you have removed the field.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5280, '%label is used by 1 comment on your site. You can not remove this comment type until you have removed all of the %label comments.%label is used by @count comments on your site. You may not remove %label until you have removed all of the %label comments.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5281, 'Translating configuration text', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5282, 'Translating date formats', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5283, 'This page lists all configuration items on your site that have translatable text, like your site name, role names, etc.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5284, 'Allow other users to contact you via a personal contact form which keeps your email address hidden. Note that some privileged users such as site administrators are still able to contact you even if you choose to disable this feature.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5285, 'Example: ''webmaster@example.com'' or ''sales@example.com,support@example.com'' . To specify multiple recipients, separate each email address with a comma.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5260, 'Receive email notifications', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5271, 'Comment types', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5270, 'Administer comment types and settings', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5255, 'Unable to send email. Contact the site administrator if the problem persists.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5263, 'Show for the listed pages', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5264, 'Hide for the listed pages', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5258, '%name: the email address can not be longer than @max characters.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5265, 'Duplicate @display_title', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5256, 'Error sending email (from %from to %to with reply-to %reply).', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5286, '%recipient is an invalid email address.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5287, '%sender-name (@sender-from) sent %recipient-name an email.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5288, 'Enabling field translation', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5289, 'You can define which fields of a content entity can be translated. For example, you might want to translate the title and body field while leaving the image field untranslated. If you exclude a field from being translated, it will still show up in the content editing form, but any changes made to that field will be applied to <em>all</em> translations of that content.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5290, 'If translation is enabled you can translate a content entity via the Translate tab (or Translate link). The Translations page of a content entity gives an overview of the translation status for the current content and lets you add, edit, and delete its translations. This process is similar for every translatable content entity on your site.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5291, 'Changing the source language for a translation', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5292, 'When you add a new translation, the original text you are translating is displayed in the edit form as the <em>source</em>. If at least one translation of the original content already exists when you add a new translation, you can choose either the original content (default) or one of the other translations as the source, using the select list in the Source language section. After saving the translation, the chosen source language is then listed on the Translate tab of the content.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5293, 'Setting status of translations', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5294, 'If you edit a translation in one language you may want to set the status of the other translations as <em>out-of-date</em>. You can set this status by selecting the <em>Flag other translations as outdated</em> checkbox in the Translation section of the content editing form. The status will be visible on the Translations page.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5295, 'Managing and displaying date fields', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5296, 'Displaying dates', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5297, 'Jan', 'Abbreviated month name', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5298, 'Feb', 'Abbreviated month name', 'none');
