INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5337, 'You can add a language that is not provided in the drop-down list by choosing <em>Custom language</em> at the end of the list. You then have to configure its language code, name, and direction in the form provided.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5338, 'Configuring content languages', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5339, 'Adding a language switcher block', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5340, 'Making a block visible per language', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5341, 'Choosing user languages', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5342, 'Users can choose a <em>Site language</em> on their profile page. This language is used for email messages, and can be used by modules to determine a user''s language. It can also be used for interface text, if the <em>User</em> method is enabled as a <em>Detection and selection</em> method (see below). Administrative users can choose a separate <em>Administration pages language</em> for the interface text on administration pages. This configuration is only available on the user''s profile page if the <em>Account administration pages</em> method is enabled (see below).', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5343, '<em>URL</em> sets the interface language based on a path prefix or domain (for example specifying <em>de</em> for German would result in URLs like <em>example.com/de/contact</em>). The default language does not require a path prefix, but can have one assigned as well. If the language detection is done by domain name, a domain needs to be specified for each language.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5344, '<em>Session</em> determines the interface language from a request or session parameter (for example <em>example.com?language=de</em> would set the interface language to German based on the use of <em>de</em> as the <em>language</em> parameter).', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5345, '<em>User</em> follows the language configuration set on the user''s profile page.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5346, '<em>Account administration pages</em> follows the configuration set as <em>Administration pages language</em> on the profile page of an administrative user. This method is similar to the <em>User</em> method, but only sets the interface text language on administration pages, independent of the interface text language on other pages.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5347, '<em>Selected language</em> allows you to specify the site''s default language or a specific language as the fall-back language. This method should be listed last.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5348, 'The comment author''s email address from the comment form, if user is anonymous, and the ''Anonymous users may/must leave their contact information'' setting is turned on.', '', 'none');
