INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5743, 'Entities and entity types', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5744, 'Entity sub-types', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5745, 'Some content entity types are further grouped into sub-types (for example, you could have article and page content types within the main site content entity type, and tag and category vocabularies within the taxonomy term entity type); other entity types, such as user accounts, do not have sub-types. Programmers use the term <em>bundle</em> for entity sub-types.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5746, 'Fields and field types', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5747, 'Content entity types and sub-types store most of their text, file, and other information in <em>fields</em>. Fields are grouped by <em>field type</em>; field types define what type of data can be stored in that field, such as text, images, or taxonomy term references.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5748, 'Formatters and view modes', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5749, 'Content entity types and sub-types can have one or more <em>view modes</em>, used for displaying the entity items. For instance, a content item could be viewed in full content mode on its own page, teaser mode in a list, or RSS mode in a feed. In each view mode, each field can be hidden or displayed, and if it is displayed, you can choose and configure the <em>formatter</em> that is used to display the field. For instance, a long text field can be displayed trimmed or full-length, and taxonomy term reference fields can be displayed in plain text or linked to the taxonomy term page.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5750, 'Widgets and form modes', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5751, 'Content entity types and sub-types can have one or more <em>form modes</em>, used for editing. For instance, a content item could be edited in a compact format with only some fields editable, or a full format that allows all fields to be edited. In each form mode, each field can be hidden or displayed, and if it is displayed, you can choose and configure the <em>widget</em> that is used to edit the field. For instance, a taxonomy term reference field can be edited using a select list, radio buttons, or an autocomplete widget.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5752, 'Enabling field types, widgets, and formatters', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5753, 'Views entity field handler', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5754, 'Creating a field', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5803, 'You can also configure a default image that will be used if no image is uploaded in an image field. This default can be defined for all instances of the field in the field storage settings when you create a field, and the setting can be overridden for each entity sub-type that uses the field.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5804, 'Configuring displays and form displays', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5805, 'On the <em>Manage display</em> page, you can choose the image formatter, which determines the image style used to display the image in each display mode and whether or not to display the image as a link. On the <em>Manage form display</em> page, you can configure the image upload widget, including setting the preview image style shown on the entity edit form.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5700, 'Re-use an existing field', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5717, 'Tray @action.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5715, 'Whether or not the content related to a term is published.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5731, 'Disabled', 'Plural', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5686, 'Link to the @entity_label', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5714, 'Publish status', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5755, 'On the <em>Manage fields</em> page for your entity type or sub-type, you can add, configure, and delete fields for that entity type or sub-type. Each field has a <em>machine name</em>, which is used internally to identify the field and must be unique across an entity type; once a field is created, you cannot change the machine name. Most fields have two types of settings. The field-level settings depend on the field type, and affect how the data in the field is stored. Once they are set, they can no longer be changed; examples include how many data values are allowed for the field and where files are stored. The sub-type-level settings are specific to each entity sub-type the field is used on, and they can be changed later; examples include the field label, help text, default value, and whether the field is required or not. You can return to these settings by choosing the <em>Edit</em> link for the field from the <em>Manage fields</em> page.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5756, 'Re-using fields', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5757, 'Configuring field editing', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5758, 'On the <em>Manage form display</em> page of your entity type or sub-type, you can configure how the field data is edited by default and in each form mode. If your entity type has multiple form modes (on most sites, most entities do not), you can toggle between the form modes at the top of the page, and you can toggle whether each form mode uses the default settings or custom settings in the <em>Custom display settings</em> section. For each field in each form mode, you can select the widget to use for editing; some widgets have additional configuration options, such as the size for a text field, and these can be edited using the Edit button (which looks like a wheel). You can also change the order of the fields on the form. You can exclude a field from a form by choosing <em>Hidden</em> from the widget drop-down list, or by dragging it into the <em>Disabled</em> section.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5759, 'Configuring field display', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5760, 'On the <em>Manage display</em> page of your entity type or sub-type, you can configure how each field is displayed by default and in each view mode. If your entity type has multiple view modes, you can toggle between the view modes at the top of the page, and you can toggle whether each view mode uses the default settings or custom settings in the <em>Custom display settings</em> section. For each field in each view mode, you can choose whether and how to display the label of the field from the <em>Label</em> drop-down list. You can also select the formatter to use for display; some formatters have configuration options, which you can edit using the Edit button (which looks like a wheel). You can also change the display order of fields. You can exclude a field from a specific view mode by choosing <em>Hidden</em> from the formatter drop-down list, or by dragging it into the <em>Disabled</em> section.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5761, 'Configuring view and form modes', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5762, 'Listing fields', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5763, 'Images must be exactly <strong>@size</strong> pixels.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5764, 'Images must be larger than <strong>@min</strong> pixels. Images larger than <strong>@max</strong> pixels will be resized.', '', 'none');
