INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5795, 'Provided by Drupal core', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5796, 'As mentioned previously, some field types, widgets, and formatters are provided by Drupal core. Here are some notes on how to use some of these:', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5797, '<strong>Number fields</strong>: When you add a number field you can choose from three types: <em>decimal</em>, <em>float</em>, and <em>integer</em>. The <em>decimal</em> number field type allows users to enter exact decimal values, with fixed numbers of decimal places. The <em>float</em> number field type allows users to enter approximate decimal values. The <em>integer</em> number field type allows users to enter whole numbers, such as years (for example, 2012) or values (for example, 1, 2, 5, 305). It does not allow decimals.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5798, 'Defining image styles', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5799, 'Naming image styles', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5800, 'When you define an image style, you will need to choose a displayed name and a machine name. The displayed name is shown in administrative pages, and the machine name is used to generate the URL for accessing an image processed in that style. There are two common approaches to naming image styles: either based on the effects being applied (for example, <em>Square 85x85</em>), or based on where you plan to use it (for example, <em>Profile picture</em>).', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5801, 'Configuring image fields', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5802, 'The maximum file size that can be uploaded is limited by PHP settings of the server, but you can restrict it further by configuring a <em>Maximum upload size</em> in the field settings (this setting can be changed later). The maximum file size, either from PHP server settings or field configuration, is automatically displayed to users in the help text of the image field.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5788, 'The listed configuration will be updated.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5784, 'Enabled', 'Plural', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5768, 'The menu link language code.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5773, 'Trusted Host Settings', '', '11.3.5');
