INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5808, 'Language detection configuration saved.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5809, 'Language codes or other custom text to use as a path prefix for URL language detection. For the selected fallback language, this value may be left blank. <strong>Modifying this value may break existing URLs. Use with caution in a production environment.</strong> Example: Specifying "deutsch" as the path prefix code for German results in URLs like "example.com/deutsch/contact".', '', 'none');
