INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5875, 'Search looks for exact, case-insensitive keywords; keywords shorter than a minimum length are ignored.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5876, 'Use upper-case OR to get more results. Example: cat OR dog (content contains either "cat" or "dog").', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5877, 'You can use upper-case AND to require all words, but this is the same as the default behavior. Example: cat AND dog (same as cat dog, content must contain both "cat" and "dog").', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5878, 'Use quotes to search for a phrase. Example: "the cat eats mice".', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5879, 'You can precede keywords by - to exclude them; you must still have at least one "positive" keyword. Example: cat -dog (content must contain cat and cannot contain dog).', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5880, 'User is admin', '', 'none');
