INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5883, 'User search looks for user names and partial user names. Example: mar would match usernames mar, delmar, and maryjane.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5884, 'You can use * as a wildcard within your keyword. Example: m*r would match user names mar, delmar, and elementary.', '', 'none');
