INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5894, 'Are you sure you want to create a new %name @type?', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5895, 'Using the personal contact form', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5896, 'Site visitors can email registered users on your site by using the personal contact form, without knowing or learning the email address of the recipient. When a site visitor is viewing a user profile, the viewer will see a <em>Contact</em> tab or link, which leads to the personal contact form. The personal contact link is not shown when you are viewing your own profile, and users must have both <em>View user information</em> (to see user profiles) and <em>Use users'' personal contact forms</em> permission to see the link. The user whose profile is being viewed must also have their personal contact form enabled (this is a user account setting); viewers with <em>Administer users</em> permission can bypass this setting.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5897, 'Configuring contact forms', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5898, 'Linking to contact forms', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5899, 'Adding content to contact forms', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5900, '@label (Translation is not supported).', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5901, '@entity using @field_name', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5902, 'Relate each @entity with a @field_name set to the @label.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5903, 'Configuring form displays', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5904, 'Reference fields have several widgets available on the <em>Manage form display</em> page:', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5905, 'The <em>Check boxes/radio buttons</em> widget displays the existing entities for the entity type as check boxes or radio buttons based on the <em>Allowed number of values</em> set for the field.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5906, 'The <em>Select list</em> widget displays the existing entities in a drop-down list or scrolling list box based on the <em>Allowed number of values</em> setting for the field.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5907, 'The <em>Autocomplete</em> widget displays text fields in which users can type entity labels based on the <em>Allowed number of values</em>. The widget can be configured to display all entities that contain the typed characters or restricted to those starting with those characters.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5908, 'The <em>Autocomplete (Tags style)</em> widget displays a multi-text field in which users can type in a comma-separated list of entity labels.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5909, 'Your server is not capable of displaying file upload progress. File upload progress requires an Apache server running PHP with mod_php or Nginx with PHP-FPM.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5910, 'Your server is not capable of displaying file upload progress. File upload progress requires PHP be run with mod_php or PHP-FPM and not as FastCGI.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5911, 'Display download path', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5912, 'Display the filemime as icon', '', 'none');
