INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5916, 'Include tar in extension', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5917, 'If the part of the filename just before the extension is ''.tar'', include this in the extension output.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5918, 'Display the file download URI', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5919, 'Display an icon', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5920, 'The icon is representing the file type, instead of the MIME text (such as "image/jpeg")', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5921, 'Using text fields with text formats', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5922, 'Text fields that allow text formats are those with "formatted" in the description. These are <em>Text (formatted, long, with summary)</em>, <em>Text (formatted)</em>, and <em>Text (formatted, long)</em>. You cannot change the type of field once a field has been created.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5923, 'Setting the allowed link type', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5924, 'In the field settings you can define the allowed link type to be <em>internal links only</em>, <em>external links only</em>, or <em>both internal and external links</em>. <em>Internal links only</em> and <em>both internal and external links</em> options enable an autocomplete widget for internal links, so a user does not have to copy or remember a URL.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5925, 'Revisions allow you to track differences between multiple versions of your content, and revert to older versions.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5926, '@type %title has been reverted to the revision from %revision-date.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5927, 'Speeding up your site', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5928, 'Site default language code', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5929, 'Page caching', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5930, 'Allowing users to add new terms gradually builds a vocabulary as content is added and edited. Users can add new terms if either of the two <em>Autocomplete</em> widgets is chosen for the Taxonomy term reference field in the <em>Manage form display</em> page for the field. You will also need to enable the <em>Create referenced entities if they don''t already exist</em> option, and restrict the field to one vocabulary.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5931, 'If you choose <em>Text (plain)</em> or <em>Text (formatted)</em> as the field type on the <em>Manage fields</em> page, then a field with a single row is displayed. You can change the maximum text length in the <em>Field settings</em> when you set up the field.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5932, 'If you choose <em>Text (plain, long)</em>, <em>Text (formatted, long)</em>, or <em>Text (formatted, long, with summary)</em> on the <em>Manage fields</em> page, then users can insert text of unlimited length. On the <em>Manage form display</em> page, you can set the number of rows that are displayed to users.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5933, 'As an alternative to using a trimmed version of the text, you can enter a separate summary by choosing the <em>Text (formatted, long, with summary)</em> field type on the <em>Manage fields</em> page. Even when <em>Summary input</em> is enabled, and summaries are provided, you can display <em>trimmed</em> text nonetheless by choosing the appropriate format on the <em>Manage display</em> page.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5934, 'Link to the user', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5935, 'Display the user or author name.', '', 'none');
