INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5971, 'Xdebug settings', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5972, 'xdebug.max_nesting_level is set to %value.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5973, 'Set <code>xdebug.max_nesting_level=@level</code> in your PHP configuration as some pages in your Drupal site will not work when this setting is too low.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5974, 'Trimmed limit', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5975, 'If the summary is not set, the trimmed %label field will end at the last full sentence before this character limit.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5976, 'Trimmed limit: @trim_length characters', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5977, 'Working with multilingual views', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5978, 'If your site has multiple languages and translated entities, each result row in a view will contain one translation of each involved entity (a view can involve multiple entities if it uses relationships). You can use a filter to restrict your view to one language: without filtering, if an entity has three translations it will add three rows to the results; if you filter by language, at most one result will appear (it could be zero if that particular entity does not have a translation matching your language filter choice). If a view uses relationships, each entity in the relationship needs to be filtered separately. You can filter a view to a fixed language choice, such as English or Spanish, or to the language selected by the page the view is displayed on (the language that is selected for the page by the language detection settings either for Content or User interface).', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5979, 'Because each result row contains a specific translation of each entity, field-level filters are also relative to these entity translations. For example, if your view has a filter that specifies that the entity title should contain a particular English word, you will presumably filter out all rows containing Chinese translations, since they will not contain the English word. If your view also has a second filter specifying that the title should contain a particular Chinese word, and if you are using "And" logic for filtering, you will presumably end up with no results in the view, because there are probably not any entity translations containing both the English and Chinese words in the title.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5980, 'Independent of filtering, you can choose the display language (the language used to display the entities and their fields) via a setting on the display. Your language choices are the same as the filter language choices, with an additional choice of "Content language of view row" and "Original language of content in view row", which means to display each entity in the result row using the language that entity has or in which it was originally created. In theory, this would give you the flexibility to filter to French translations, for instance, and then display the results in Spanish. The more usual choices would be to use the same language choices for the display language and each entity filter in the view, or to use the Row language setting for the display.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5981, 'Entity link', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5982, 'Entity delete link', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5983, 'Entity edit link', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5991, 'Options such as paging, table sorting, and exposed filters will not initiate a page refresh.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5994, 'Per default the table is hidden for an empty view. With this option it is possible to show an empty table with the text in it.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5995, 'Cache tags', '', 'none');
