INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6155, 'The Ban module allows administrators to ban visits to their site from individual IP addresses. For more information, see the <a href=":url">online documentation for the Ban module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6156, 'Administrators can enter IP addresses to ban on the <a href=":bans">IP address bans</a> page.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6157, 'The HTTP Basic Authentication module supplies an <a href="http://en.wikipedia.org/wiki/Basic_access_authentication">HTTP Basic authentication</a> provider for web service requests. This authentication provider authenticates requests using the HTTP Basic Authentication username and password, as an alternative to using Drupal''s standard cookie-based authentication system. It is only useful if your site provides web services configured to use this type of authentication (for instance, the <a href=":rest_help">RESTful Web Services module</a>). For more information, see the <a href=":hba_do">online documentation for the HTTP Basic Authentication module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6158, 'The Block module allows you to place blocks in regions of your installed themes, and configure block settings. For more information, see the <a href=":blocks-documentation">online documentation for the Block module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6159, 'You can see where the regions are for the current theme by clicking the <em>Demonstrate block regions</em> link on the <a href=":blocks">Block layout page</a>. Regions are specific to each theme.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6160, 'To change the settings of an individual block click on the <em>Configure</em> link on the <a href=":blocks">Block layout page</a>. The available options vary depending on the module that provides the block. For all blocks you can change the block title and toggle whether to display it.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6161, 'The Breakpoint module keeps track of the height, width, and resolution breakpoints where a responsive design needs to change in order to respond to different devices being used to view the site. This module does not have a user interface. For more information, see the <a href=":docs">online documentation for the Breakpoint module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6162, '<a href=":w3">Media  queries</a> are a formal way to encode breakpoints. For instance, a width breakpoint at 40em would be written as the media query "(min-width: 40em)". Breakpoints are really just media queries with some additional meta-data, such as a name and multiplier information.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6163, 'The Comment module allows users to comment on site content, set commenting defaults and permissions, and moderate comments. For more information, see the <a href=":comment">online documentation for the Comment module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6164, 'Enabling commenting', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6165, 'Configuring commenting settings', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6166, 'Users with the appropriate permissions can override the default commenting settings of an entity type when they create an item of that type.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6167, 'Comments from users who have the <em>Skip comment approval</em> permission are published immediately. All other comments are placed in the <a href=":comment-approval">Unapproved comments</a> queue, until a user who has permission to <em>Administer comments and comment settings</em> publishes or deletes them. Published comments can be bulk managed on the <a href=":admin-comment">Published comments</a> administration page. When a comment has no replies, it remains editable by its author, as long as the author has <em>Edit own comments</em> permission.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6168, 'In reply to @parent_title by @parent_username', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6169, 'Name for @anonymous', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6170, '<a href=":login">Log in</a> or <a href=":register">register</a> to post comments', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6171, '<a href=":login">Log in</a> to post comments', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6172, 'Select the Comment type to use for this comment field. Manage the comment types from the <a href=":url">administration overview page</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6173, 'The Configuration Manager module provides a user interface for importing and exporting configuration changes between installations of your website in different environments. Configuration is stored in YAML format. For more information, see the <a href=":url">online documentation for the Configuration Manager module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6174, 'You can create and download an archive consisting of all your site''s configuration exported as <em>*.yml</em> files on the <a href=":url">Export</a> page.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6175, 'You can upload a full site configuration from an archive file on the <a href=":url">Import</a> page. When importing data from a different environment, the site and import files must have matching configuration values for UUID in the <em>system.site</em> configuration item. That means that your other environments should initially be set up as clones of the target site. Migrations are not supported.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6176, 'You can review differences between the active configuration and an imported configuration archive on the <a href=":synchronize">Synchronize</a> page to ensure that the changes are as expected, before finalizing the import. The Synchronize page also shows configuration items that would be added or removed.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6177, 'You can export a single configuration item by selecting a <em>Configuration type</em> and <em>Configuration name</em> on the <a href=":single-export">Single export</a> page. The configuration and its corresponding <em>*.yml file name</em> are then displayed on the page for you to copy.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6178, 'You can import a single configuration item by pasting it in YAML format into the form on the <a href=":single-import">Single import</a> page.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6179, 'Export and download the full configuration of this site as a gzipped tar file.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6180, 'Choose a configuration item to display its YAML structure.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6181, 'Import a single configuration item by pasting its YAML structure into the text field.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6182, 'Full archive', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6184, 'Staged', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6185, 'The following items in your active configuration have changes since the last import that may be lost on the next import.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6186, '@collection configuration collection', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6187, '@source_name to @target_name', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6188, 'The Configuration Translation module allows you to translate configuration text; for example, the site name, vocabularies, menus, or date formats. Together with the modules <a href=":language">Language</a>, <a href=":content-translation">Content Translation</a>, and <a href=":locale">Interface Translation</a>, it allows you to build multilingual websites. For more information, see the <a href=":doc_url">online documentation for the Configuration Translation module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6189, 'In order to translate configuration, the website must have at least two <a href=":url">languages</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6282, 'Interface translation export', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6460, 'View @display_title', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6190, 'Users with the <em>Translate user edited configuration</em> permission can access the configuration translation overview, and manage translations for specific languages. The <a href=":translation-page">Configuration translation</a> page shows a list of all configuration text that can be translated, either as individual items or as lists. After you click on <em>Translate</em>, you are provided with a list of all languages. You can <em>add</em> or <em>edit</em> a translation for a specific language. Users with specific configuration permissions can also <em>edit</em> the text for the site''s default language. For some configuration text items (for example for the site information), the specific translation pages can also be accessed directly from their configuration pages.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6191, 'You can choose to translate date formats on the <a href=":translation-page">Configuration translation</a> page. This allows you not only to translate the label text, but also to set a language-specific <em>PHP date format</em>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6192, '@label <span class="visually-hidden">(@source_language)</span>', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6193, 'The Contact module allows visitors to contact registered users on your site, using the personal contact form, and also allows you to set up site-wide contact forms. For more information, see the <a href=":contact">online documentation for the Contact module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6194, 'On the <a href=":contact_admin">Contact forms page</a>, you can configure the fields and display of the personal contact form, and you can set up one or more site-wide contact forms. Each site-wide contact form has a machine name, a label, and one or more defined recipients; when a site visitor submits the form, the field values are sent to those recipients.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6195, 'One site-wide contact form can be designated as the default contact form. If you choose to designate a default form, the <em>Contact</em> menu link in the <em>Footer</em> menu will link to it. You can modify this link from the <a href=":menu-settings">Menus page</a> if you have the Menu UI module installed. You can also create links to other contact forms; the URL for each form you have set up has format <em>contact/machine_name_of_form</em>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6196, 'From the <a href=":contact_admin">Contact forms page</a>, you can configure the fields to be shown on contact forms, including their labels and help text. If you would like other content (such as text or images) to appear on a contact form, use a block. You can create and edit blocks on the <a href=":blocks">Block layout page</a>, if the Block module is installed.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6197, '[@form] @subject', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6198, '@sender-name (@sender-url) sent a message using the contact form at @form-url.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6199, '[@site-name] @subject', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6200, 'Hello @recipient-name,', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6201, '@sender-name (@sender-url) has sent you a message via your contact form at @site-name.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6202, '@name (not verified)', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6203, 'The contact form has not been configured. <a href=":add">Add one or more forms</a> .', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6204, 'In order to translate content, the website must have at least two <a href=":url">languages</a>. When that is the case, you can enable translation for the desired content entities on the <a href=":translation-entity">Content language</a> page. When enabling translation you can choose the default language for content and decide whether to show the language selection field on the content editing forms.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6205, 'Before you can translate content, there must be at least two languages added on the <a href=":url">languages administration</a> page.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6206, 'To configure translation for this field, <a href=":language-settings-url">enable language support</a> for this type.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6207, '<a href=":settings_url">Enable translation</a> for <em>content types</em>, <em>taxonomy vocabularies</em>, <em>accounts</em>, or any other element you wish to translate.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6208, 'The Contextual links module gives users with the <em>Use contextual links</em> permission quick access to tasks associated with certain areas of pages on your site. For example, a menu displayed as a block has links to edit the menu and configure the block. For more information, see the <a href=":contextual">online documentation for the Contextual Links module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6209, 'Hovering over the area of interest will temporarily make the contextual links button visible (which looks like a pencil in most themes, and is normally displayed in the upper right corner of the area). The icon typically looks like this: @picture', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6210, 'The Datetime module provides a Date field that stores dates and times. It also provides the Form API elements <em>datetime</em> and <em>datelist</em> for use in programming modules. See the <a href=":field">Field module help</a> and the <a href=":field_ui">Field UI module help</a> pages for general information on fields and how to create and manage them. For more information, see the <a href=":datetime_do">online documentation for the Datetime module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6211, 'The <em>settings</em> and the <em>display</em> of the Date field can be configured separately. See the <a href=":field_ui">Field UI help</a> for more information on how to manage fields and their display.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6212, 'Dates can be displayed using the <em>Plain</em> or the <em>Default</em> formatter. The <em>Plain</em> formatter displays the date in the <a href="http://en.wikipedia.org/wiki/ISO_8601">ISO 8601</a> format. If you choose the <em>Default</em> formatter, you can choose a format from a predefined list that can be managed on the <a href=":date_format_list">Date and time formats</a> page.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6213, 'Date part order: @order', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6214, 'Time type: @time_type', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6215, 'Time increments: @increment', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6216, 'The Database Logging module logs system events in the Drupal database. For more information, see the <a href=":dblog">online documentation for the Database Logging module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6217, 'The Database Logging module allows you to view an event log on the <a href=":dblog">Recent log messages</a> page. The log is a chronological list of recorded events containing usage data, performance data, errors, warnings and operational information. Administrators should check the log on a regular basis to ensure their site is working properly.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6218, 'In case of errors or problems with the site, the <a href=":dblog">Recent log messages</a> page can be useful for debugging, since it shows the sequence of events. The log messages include usage information, warnings, and errors.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6219, 'The maximum number of messages to keep in the database log. Requires a <a href=":cron">cron maintenance task</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6220, 'Pages which are suitable for caching are cached the first time they are requested, then the cached version is served for all later requests. Dynamic content is handled automatically so that both cache correctness and hit ratio is maintained.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6221, 'Internal Dynamic Page Cache', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6277, 'Updates available for: @languages. See the <a href=":updates">Available translation updates</a> page for more information.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6339, 'The title of the set.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6222, 'The <em>settings</em> and the <em>display</em> of the entity reference field can be configured separately. See the <a href=":field_ui">Field UI help</a> for more information on how to manage fields and their display.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6223, 'No eligible views were found. <a href=":create">Create a view</a> with an <em>Entity Reference</em> display, or add such a display to an <a href=":existing">existing view</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6224, 'The Field module allows custom data fields to be defined for <em>entity</em> types (see below). The Field module takes care of storing, loading, editing, and rendering field data. Most users will not interact with the Field module directly, but will instead use the <a href=":field-ui-help">Field UI module</a> user interface. Module developers can use the Field API to make new entity types "fieldable" and thus allow fields to be attached to them. For more information, see the <a href=":field">online documentation for the Field module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6225, 'You can add, edit, and delete view modes for entities on the <a href=":view_modes">View modes page</a>, and you can add, edit, and delete form modes for entities on the <a href=":form_modes">Form modes page</a>. Once you have defined a view mode or form mode for an entity type, it will be available on the Manage display or Manage form display page for each sub-type of that entity.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6226, 'There are no fields yet added. You can add new fields on the <a href=":link">Manage fields</a> page.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6227, 'The %display_mode mode now uses custom display settings. You might want to <a href=":url">configure them</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6229, 'file from @field_name', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6230, 'The File module allows you to create fields that contain files. See the <a href=":field">Field module help</a> and the <a href=":field_ui">Field UI help</a> pages for general information on fields and how to create and manage them. For more information, see the <a href=":file_documentation">online documentation for the File module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6231, 'The <em>settings</em> and the <em>display</em> of the file field can be configured separately. See the <a href=":field_ui">Field UI help</a> for more information on how to manage fields and their display.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6232, 'Uploaded files can either be stored as <em>public</em> or <em>private</em>, depending on the <a href=":file-system">File system settings</a>. For more information, see the <a href=":system-help">System module help page</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6233, 'The file used in the @name field may not be referenced.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6234, 'The file referenced by the @name field does not exist.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6236, 'If you do encounter problems, try using HTML character entities. A common example looks like &amp;amp; for an ampersand &amp; character. For a full list of entities see HTML''s <a href=":html-entities">entities</a> page. Some of the available characters include:', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6238, '<strong>Configure your website</strong> Once logged in, visit the <a href=":admin">Administration page</a>, where you may <a href=":config">customize and configure</a> all aspects of your website.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6239, '<strong>Customize your website design</strong> To change the "look and feel" of your website, visit the <a href=":themes">Appearance page</a>. You may choose from one of the included themes or download additional themes from the <a href=":download_themes">Drupal.org themes page</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6240, '<strong>Start posting content</strong> Finally, you may <a href=":content">add new content</a> to your website.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6241, 'The Help module displays explanations for using each module listed on the main <a href=":help">Help reference page</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6242, 'Page-specific help text provided by modules is displayed in the Help block. This block can be placed and configured on the <a href=":blocks">Block layout page</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6243, 'The History module keeps track of which content a user has read. It marks content as <em>new</em> or <em>updated</em> depending on the last time the user viewed it. History records that are older than one month are removed during cron, which means that content older than one month is always considered <em>read</em>. The History module does not have a user interface but it provides a filter to <a href=":views-help">Views</a> to show new or updated content. For more information, see the <a href=":url">online documentation for the History module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6244, 'image from @field_name', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6245, 'The Image module allows you to create fields that contain image files and to configure <a href=":image_styles">Image styles</a> that can be used to manipulate the display of images. See the <a href=":field">Field module help</a> and the <a href=":field_ui">Field UI help</a> pages for terminology and general information on entities, fields, and how to create and manage fields. For more information, see the <a href=":image_documentation">online documentation for the Image module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6246, 'The concept of image styles is that you can upload a single image but display it in several ways; each display variation, or <em>image style</em>, is the result of applying one or more <em>effects</em> to the original image. As an example, you might upload a high-resolution image with a 4:3 aspect ratio, and display it scaled down, square cropped, or black-and-white (or any combination of these effects). The Image module provides a way to do this efficiently: you configure an image style with the desired effects on the <a href=":image">Image styles page</a>, and the first time a particular image is requested in that style, the effects are applied. The resulting image is saved, and the next time that same style is requested, the saved image is retrieved without the need to recalculate the effects. Drupal core provides several effects that you can use to define styles; others may be provided by contributed modules.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6247, 'When you create an image field, you will need to choose whether the uploaded images will be stored in the public or private file directory defined in your settings.php file and shown on the <a href=":file-system">File system page</a>. This choice cannot be changed later. You can also configure your field to store files in a subdirectory of the public or private directory; this setting can be changed later and can be different for each entity sub-type using the field. For more information on file storage, see the <a href=":system-help">System module help page</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6248, 'There are currently no styles. <a href=":url">Add a new one</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6249, 'Both a height and width value must be specified in the @name field.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6250, 'The primary identifier for an image style.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6251, 'The style machine name.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6252, 'The style administrative name.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6279, 'No translation status is available. See the <a href=":updates">Available translation updates</a> page for more information.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6228, '@size limit.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6235, 'Use the <a href=":url">@label</a> text format', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6253, 'By default, content is created in the site''s default language and no language selector is displayed on content creation pages. On the <a href=":content_language">Content language</a> page you can customize the language configuration for any supported content entity on your site (for example for content types or menu links). After choosing an entity, you are provided with a drop-down menu to set the default language and a check-box to display language selectors.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6254, 'The <a href=":detection">Detection and selection</a> page provides several methods for deciding which language is used for displaying interface text. When a method detects and selects an interface language, then the following methods in the list are not applied. You can order them by importance, with your preferred method at the top of the list, followed by one or several fall-back methods.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6255, '<em>Browser</em> sets the interface language based on the browser''s language settings. Since browsers use different language codes to refer to the same languages, you can add and edit languages codes to map the browser language codes to the <a href=":language_list">language codes</a> used on your site.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6256, 'Reorder the configured languages to set their order in the language switcher block and, when editing content, in the list of selectable languages. This ordering does not impact <a href=":detection">detection and selection</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6257, 'The site default language can also be set. It is not recommended to change the default language on a working site. <a href=":language-detection">Configure the Selected language</a> setting on the detection and selection page to change the fallback language for language selection.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6258, 'Define how to decide which language is used to display page elements (primarily text provided by modules, such as field labels and help text). This decision is made by evaluating a series of detection methods for languages; the first detection method that gets a result will determine which language is used for that type of text. Be aware that some language detection methods are unreliable under certain conditions, such as browser detection when page-caching is enabled and a user is not currently logged in. Define the order of evaluation of language detection methods on this page. The default language can be changed in the <a href=":admin-change-language">list of languages</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6259, 'Browsers use different language codes to refer to the same languages. Internally, a best effort is made to determine the correct language based on the code that the browser sends. You can add and edit additional mappings from browser language codes to <a href=":configure-languages">site languages</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6260, 'Changing the selected language here (and leaving this option as the last among the detection and selection options) is the easiest way to change the fallback language for the website, if you need to change how your site works by default (e.g., when using an empty path prefix or using the default domain). <a href=":admin-change-language">Changing the site''s default language</a> itself might have other undesired side effects.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6263, 'Use one of the language switcher blocks to allow site visitors to switch between languages. You can enable these blocks on the <a href=":block-admin">block administration page</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6264, 'Use language codes as <a href=":w3ctags">defined by the W3C</a> for interoperability. <em>Examples: "en", "en-gb" and "zh-hant".</em>', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6265, '%field must be a valid language tag as <a href=":url">defined by the W3C</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6266, 'The prefix may only be left blank for the <a href=":url">selected detection fallback language.</a>', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6267, 'The Link module allows you to create fields that contain internal or external URLs and optional link text. See the <a href=":field">Field module help</a> and the <a href=":field_ui">Field UI help</a> pages for general information on fields and how to create and manage them. For more information, see the <a href=":link_documentation">online documentation for the Link module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6268, 'The <em>settings</em> and the <em>display</em> of the link field can be configured separately. See the <a href=":field_ui">Field UI help</a> for more information on how to manage fields and their display.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6269, 'One translation file could not be checked. <a href=":url">See the log</a> for details.@count translation files could not be checked. <a href=":url">See the log</a> for details.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6270, 'One translation file could not be imported. <a href=":url">See the log</a> for details.@count translation files could not be imported. <a href=":url">See the log</a> for details.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6271, 'One translation string was skipped because of disallowed or malformed HTML. <a href=":url">See the log</a> for details.@count translation strings were skipped because of disallowed or malformed HTML. <a href=":url">See the log</a> for details.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6272, 'The Interface Translation module allows you to translate interface text (<em>strings</em>) into different languages, and to switch between them for the display of interface text. It uses the functionality provided by the <a href=":language">Language module</a>. For more information, see the <a href=":doc-url">online documentation for the Interface Translation module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6273, 'You can check how much of the interface on your site is translated into which language on the <a href=":languages">Languages</a> page. On the <a href=":translation-updates">Available translation updates</a> page, you can check whether interface translation updates are available on the <a href=":server">Drupal translation server</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6274, 'You can translate individual strings directly on the <a href=":translate">User interface translation</a> page, or download the currently-used translation file for a specific language on the <a href=":export">Interface translation export</a> page. Once you have edited the translation file, you can then import it again on the <a href=":import">Interface translation import</a> page.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6275, 'This page allows a translator to search for specific translated and untranslated strings, and is used when creating or editing translations. (Note: Because translation tasks involve many strings, it may be more convenient to <a title="User interface translation export" href=":export">export</a> strings for offline editing in a desktop Gettext translation editor.) Searches may be limited to strings in a specific language.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6276, 'This page allows translators to manually import translated strings contained in a Gettext Portable Object (.po) file. Manual import may be used for customized translations or for the translation of custom modules and themes. To customize translations you can download a translation file from the <a href=":url">Drupal translation server</a> or <a title="User interface translation export" href=":export">export</a> translations from the site, customize the translations using a Gettext translation editor, and import the result using this page.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6280, 'Interface translation settings', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6283, 'Select how frequently you want to check for new interface translations for your currently installed modules and themes. <a href=":url">Check updates now</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6284, 'Translation files are stored locally in the  %path directory. You can change this directory on the <a href=":url">File system</a> configuration page.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6285, 'Translation files will not be stored locally. Change the Interface translation directory on the <a href=":url">File system configuration</a> page.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6286, 'You have selected local translation source, but no <a href=":url">Interface translation directory</a> was configured.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6287, 'No translatable languages available. <a href=":add_language">Add a language</a> first.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6288, 'No translation status available. <a href=":check">Check manually</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6289, 'It is required by the Menu UI module, which provides an interface for managing menus and menu links. For more information, see the <a href=":menu-help">Menu UI module help page</a> and the <a href=":drupal-org-help">online documentation for the Custom Menu Links module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6290, 'The Menu UI module provides an interface for managing menus. A menu is a hierarchical collection of links, which can be within or external to the site, generally used for navigation. For more information, see the <a href=":menu">online documentation for the Menu UI module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6291, 'You can enable the newly-created block for this menu on the <a href=":blocks">Block layout page</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6292, 'Each menu has a corresponding block that is managed on the <a href=":blocks">Block layout page</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6294, 'The Migrate module provides a framework for migrating data, usually from an external source into your site. It does not provide a user interface. For more information, see the <a href=":migrate">online documentation for the Migrate module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6295, 'The Migrate Drupal module provides a framework based on the <a href=":migrate">Migrate module</a> to facilitate migration from a Drupal (6, 7, or 8) site to your website. It does not provide a user interface. For more information, see the <a href=":migrate_drupal">online documentation for the Migrate Drupal module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6296, 'The content access permissions need to be rebuilt. <a href=":node_access_rebuild">Rebuild permissions</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6297, 'The Node module manages the creation, editing, deletion, settings, and display of the main site content. Content items managed by the Node module are typically displayed as pages on your site, and include a title, some meta-data (author, creation time, content type, etc.), and optional fields containing text or other data (fields are managed by the <a href=":field">Field module</a>). For more information, see the <a href=":node">online documentation for the Node module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6298, 'When new content is created, the Node module records basic information about the content, including the author, date of creation, and the <a href=":content-type">Content type</a>. It also manages the <em>publishing options</em>, which define whether or not the content is published, promoted to the front page of the site, and/or sticky at the top of content lists. Default settings can be configured for each <a href=":content-type">type of content</a> on your site.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6299, 'The Node module gives users with the <em>Administer content types</em> permission the ability to <a href=":content-new">create new content types</a> in addition to the default ones already configured. Creating custom content types gives you the flexibility to add <a href=":field">fields</a> and configure default settings that suit the differing needs of various site content.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6300, 'The <a href=":content">Content</a> page lists your content, allowing you add new content, filter, edit or delete existing content, or perform bulk operations on existing content.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6301, 'The Node module makes a number of permissions available for each content type, which can be set by role on the <a href=":permissions">permissions page</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6303, 'Maintain the types of content available and the fields that are associated with those types.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6304, 'No content types available. <a href=":link">Add content type</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6306, 'The Options module allows you to create fields where data values are selected from a fixed list of options. Usually these items are entered through a select list, checkboxes, or radio buttons. See the <a href=":field">Field module help</a> and the <a href=":field_ui">Field UI help</a> pages for general information on fields and how to create and manage them. For more information, see the <a href=":options_do">online documentation for the Options module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6307, 'The <em>settings</em> and the <em>display</em> of the list fields can be configured separately. See the <a href=":field_ui">Field UI help</a> for more information on how to manage fields and their display.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6308, 'The Internal Page Cache module caches pages for anonymous users in the database. For more information, see the <a href=":pagecache-documentation">online documentation for the Internal Page Cache module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6309, 'Pages are usually identical for all anonymous users, while they can be personalized for each authenticated user. This is why entire pages can be cached for anonymous users, whereas they will have to be rebuilt for every authenticated user.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6310, 'To speed up your site for authenticated users, see the <a href=":dynamic_page_cache-help">Dynamic Page Cache module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6311, 'The Path module allows you to specify an alias, or custom URL, for any existing internal system path. Aliases should not be confused with URL redirects, which allow you to forward a changed or inactive URL to a new URL. In addition to making URLs more readable, aliases also help search engines index content more effectively. Multiple aliases may be used for a single internal system path. To automate the aliasing of paths, you can install the contributed module <a href=":pathauto">Pathauto</a>. For more information, see the <a href=":path">online documentation for the Path module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6312, 'If you create or edit a taxonomy term you can add an alias (for example <em>music/jazz</em>) in the field "URL alias". When creating or editing content you can add an alias (for example <em>about-us/team</em>) under the section "URL path settings" in the field "URL alias". Aliases for any other path can be added through the page <a href=":aliases">URL aliases</a>. To add aliases a user needs the permission <a href=":permissions">Create and edit URL aliases</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6340, 'The users.uid for this set.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6305, 'Node from URL', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6293, 'There are no menu links yet. <a href=":url">Add link</a>.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6313, 'The Path module provides a way to search and view a <a href=":aliases">list of all aliases</a> that are in use on your website. Aliases can be added, edited and deleted through this list.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6314, 'The internal system path.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6315, 'The path alias.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6316, 'The Responsive Image module provides an image formatter that allows browsers to select which image file to display based on media queries or which image file types the browser supports, using the HTML 5 picture and source elements and/or the sizes, srcset and type attributes. For more information, see the <a href=":responsive_image">online documentation for the Responsive Image module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6317, 'By creating responsive image styles you define which options the browser has in selecting which image file to display. In most cases this means providing different image sizes based on the viewport size. On the <a href=":responsive_image_style">Responsive image styles</a> page, click <em>Add responsive image style</em> to create a new style. First choose a label, a fallback image style and a breakpoint group and click Save.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6318, 'Below the Sizes field you can choose multiple image styles so the browser can choose the best image file size to fill the space defined in the Sizes field. Typically you will want to use image styles that resize your image to have options that range from the smallest px width possible for the space the image will appear in to the largest px width possible, with a variety of widths in between. You may want to provide image styles with widths that are 1.5x to 2x the space available in the layout to account for high resolution screens. Image styles can be defined on the <a href=":image_styles">Image styles page</a> that is provided by the <a href=":image_help">Image module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6319, 'After defining responsive image styles, you can use them in the display settings for your Image fields, so that the site displays responsive images using the HTML5 picture tag. Open the Manage display page for the entity type (content type, taxonomy vocabulary, etc.) that the Image field is attached to. Choose the format <em>Responsive image</em>, click the Edit icon, and select one of the responsive image styles that you have created. For general information on how to manage fields and their display see the <a href=":field_ui">Field UI module help page</a>. For background information about entities and fields see the <a href=":field_help">Field module help page</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6320, 'See the <a href=":responsive_image_help">Responsive Image help page</a> for information on the sizes attribute.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6321, 'Configure Responsive Image Styles', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6322, 'The Search module provides the ability to set up search pages based on plugins provided by other modules. In Drupal core, there are two page-type plugins: the Content page type provides keyword searching for content managed by the Node module, and the Users page type provides keyword searching for registered users. Contributed modules may provide other page-type plugins. For more information, see the <a href=":search-module">online documentation for the Search module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6323, 'To configure search pages, visit the <a href=":search-settings">Search pages page</a>. In the Search pages section, you can add a new search page, edit the configuration of existing search pages, enable and disable search pages, and choose the default search page. Each enabled search page has a URL path starting with <em>search</em>, and each will appear as a tab or local task link on the <a href=":search-url">search page</a>; you can configure the text that is shown in the tab. In addition, some search page plugins have additional settings that you can configure for each search page.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6324, 'Some search page plugins, such as the core Content search page, index searchable text using the Drupal core search index, and will not work unless content is indexed. Indexing is done during <em>cron</em> runs, so it requires a <a href=":cron">cron maintenance task</a> to be set up. There are also several settings affecting indexing that can be configured on the <a href=":search-settings">Search pages page</a>: the number of items to index per cron run, the minimum word length to index, and how to handle Chinese, Japanese, and Korean characters.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6325, 'Users with <a href=":search_permission">Use search</a> permission can use the Search block and <a href=":search">Search page</a>. Users with the <a href=":node_permission">View published content</a> permission can use configured search pages of type <em>Content</em> to search for content containing exact keywords; in addition, users with <a href=":search_permission">Use advanced search</a> permission can use more complex search filtering. Users with the <a href=":user_permission">View user information</a> permission can use configured search pages of type <em>Users</em> to search for active users containing the keyword anywhere in the username, and users with the <a href=":user_permission">Administer users</a> permission can search for active and blocked users, by email address or username keyword.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6326, 'By default, the Search module only supports exact keyword matching in content searches. You can modify this behavior by installing a language-specific stemming module for your language (such as <a href=":porterstemmer_url">Porter Stemmer</a> for American English), which allows words such as walk, walking, and walked to be matched in the Search module. Another approach is to use a third-party search technology with stemming or partial word matching features built in, such as <a href=":solr_url">Apache Solr</a> or <a href=":sphinx_url">Sphinx</a>. There are also contributed modules that provide additional search pages. These and other <a href=":contrib-search">search-related contributed modules</a> can be downloaded by visiting Drupal.org.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6327, '… @excerpt … @excerpt …', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6328, 'This module does not have a user interface. It is used by other modules which need to serialize data, such as <a href=":rest">REST</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6329, 'For more information, see the <a href=":doc_url">online documentation for the Serialization module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6330, 'The Shortcut module allows users to create sets of <em>shortcut</em> links to commonly-visited pages of the site. Shortcuts are contained within <em>sets</em>. Each user with <em>Select any shortcut set</em> permission can select a shortcut set created by anyone at the site. For more information, see the <a href=":shortcut">online documentation for the Shortcut module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6331, 'Users with the <em>Administer shortcuts</em> permission can manage shortcut sets and edit the shortcuts within sets from the <a href=":shortcuts">Shortcuts administration page</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6332, 'Define which shortcut set you are using on the <a href=":shortcut-link">Shortcuts tab</a> of your account page.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6333, 'No shortcuts available. <a href=":link">Add a shortcut</a>', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6334, 'You are now using the new %set_name shortcut set. You can edit it from this page or <a href=":switch-url">switch back to a different one.</a>', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6335, 'The link for this shortcut.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6336, 'The title for this shortcut.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6337, 'The weight for this shortcut', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6338, 'The name under which the set''s links are stored.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6341, 'The shortcut_set.set_name that will be displayed for this user.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6345, 'This theme requires PHP version @php_required and is incompatible with PHP version @php_version.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6346, 'The System module is integral to the site: it provides user interfaces for many core systems and settings, as well as the basic administrative menu structure. For more information, see the <a href=":system">online documentation for the System module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6347, 'Users with appropriate permission can install and uninstall modules from the <a href=":modules">Extend page</a>. Depending on which distribution or installation profile you choose when you install your site, several modules are installed and others are provided but not installed. Each module provides a discrete set of features; modules may be installed or uninstalled depending on the needs of the site. Many additional modules contributed by members of the Drupal community are available for download from the <a href=":drupal-modules">Drupal.org module page</a>. Note that uninstalling a module is a destructive action: when you uninstall a module, you will permanently lose all data connected to the module.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6348, 'Users with appropriate permission can install and uninstall themes on the <a href=":themes">Appearance page</a>. Themes determine the design and presentation of your site. Depending on which distribution or installation profile you choose when you install your site, a default theme is installed, and possibly a different theme for administration pages. Other themes are provided but not installed, and additional contributed themes are available at the <a href=":drupal-themes">Drupal.org theme page</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6349, 'When you are performing site maintenance, you can prevent non-administrative users (including anonymous visitors) from viewing your site by putting it in <a href=":maintenance-mode">Maintenance mode</a>. This will prevent unauthorized users from making changes to the site while you are performing maintenance, or from seeing a broken site while updates are in progress.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6350, 'On the <a href=":performance-page">Performance page</a>, the site can be configured to aggregate CSS and JavaScript files, making the total request size smaller. Note that, for small- to medium-sized websites, the <a href=":page-cache">Internal Page Cache module</a> should be installed so that pages are efficiently cached and reused for anonymous users. Finally, for websites of all sizes, the <a href=":dynamic-page-cache">Dynamic Page Cache module</a> should also be installed so that the non-personalized parts of pages are efficiently cached (for all users).', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6351, 'Your site has several file directories, which are used to store and process uploaded and generated files. The <em>public</em> file directory, which is configured in your settings.php file, is the default place for storing uploaded files. Links to files in this directory contain the direct file URL, so when the files are requested, the web server will send them directly without invoking your site code. This means that the files can be downloaded by anyone with the file URL, so requests are not access-controlled but they are efficient. The <em>private</em> file directory, also configured in your settings.php file and ideally located outside the site web root, is access controlled. Links to files in this directory are not direct, so requests to these files are mediated by your site code. This means that your site can check file access permission for each file before deciding to fulfill the request, so the requests are more secure, but less efficient. You should only use the private storage for files that need access control, not for files like your site logo and background images used on every page. The <em>temporary</em> file directory is used internally by your site code for various operations, and is configured on the <a href=":file-system">File system settings</a> page. You can also see the configured public and private file directories on this page, and choose whether public or private should be the default for uploaded files.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6352, 'On the <a href=":toolkit">Image toolkit page</a>, you can select and configure the PHP toolkit used to manipulate images. Depending on which distribution or installation profile you choose when you install your site, the GD2 toolkit and possibly others are included; other toolkits may be provided by contributed modules.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6353, 'Set and configure the default theme for your website.  Alternative <a href=":themes">themes</a> are available.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6354, 'You can place blocks for each theme on the <a href=":blocks">block layout</a> page.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6355, 'Here you can find a short overview of your site''s parameters as well as any problems detected with your installation. It may be useful to copy and paste this information into support requests filed on Drupal.org''s support forums and project issue queues. Before filing a support request, ensure that your web server meets the <a href=":system-requirements">system requirements.</a>', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6356, 'Configure your <a href=":user-edit">account time zone setting</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6357, 'The minimum version of Apache needed to run Drupal without mod_rewrite enabled is 2.2.16. See the <a href=":link">enabling clean URLs</a> page for more information on mod_rewrite.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6358, 'Your server is capable of using clean URLs, but it is not enabled. Using clean URLs gives an improved user experience and is recommended. <a href=":link">Enable clean URLs</a>', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6360, 'Drupal requires you to enable the PHP extensions in the following list (see the <a href=":system_requirements">system requirements page</a> for more information):', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6362, 'Your web server does not appear to support PDO (PHP Data Objects). Ask your hosting provider if they support the native PDO extension. See the <a href=":link">system requirements</a> page for more information.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6363, 'Your web server does not appear to support any common PDO database extensions. Check with your hosting provider to see if they support PDO (PHP Data Objects) and offer any databases that <a href=":drupal-databases">Drupal supports</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6364, 'Your web server seems to have the wrong version of PDO installed. Drupal requires the PDO extension from PHP core. This system has the older PECL version. See the <a href=":link">system requirements</a> page for more information.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6365, 'For more information, see the online handbook entry for <a href=":memory-limit">increasing the PHP memory limit</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6366, 'See <a href=":url">@url</a> for information about the recommended .htaccess file which should be added to the %directory directory to help protect against arbitrary code execution.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6368, 'For more information, see the online handbook entry for <a href=":cron-handbook">configuring cron jobs</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6361, 'PHP OPcode caching', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6343, 'Requires: @module-list', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6367, 'Last run @time ago', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6359, '@phpversion (<a href=":url">more information</a>)', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6344, 'Required by: @module-list', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6369, 'You may need to set the correct directory at the <a href=":admin-file-system">file system settings page</a> or change the current directory''s permissions so that it is writable.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6370, 'An automated attempt to create this directory failed, possibly due to a permissions problem. To proceed with the installation, either create the directory and modify its permissions manually or ensure that the installer has the permissions to create it automatically. For more information, see INSTALL.txt or the <a href=":handbook_url">online handbook</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6371, 'Some modules have database schema updates to install. You should run the <a href=":update">database update script</a> immediately.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6376, 'One or more problems were detected with your Drupal installation. Check the <a href=":status">status report</a> for more information.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6383, 'More information about setting up scheduled tasks can be found by <a href=":url">reading the cron tutorial on drupal.org</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6384, 'This version is not compatible with Drupal @core_version and should be replaced.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6385, 'This module requires PHP version @php_required and is incompatible with PHP version @php_version.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6386, 'Defined on the <a href=":information">Site Information</a> page.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6388, 'The Taxonomy module allows users who have permission to create and edit content to categorize (tag) content of that type. Users who have the <em>Administer vocabularies and terms</em> <a href=":permissions" title="Taxonomy module permissions">permission</a> can add <em>vocabularies</em> that contain a set of related <em>terms</em>. The terms in a vocabulary can either be pre-set by an administrator or built gradually as content is added and edited. Terms may be organized hierarchically if desired.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6389, 'For more information, see the <a href=":taxonomy">online documentation for the Taxonomy module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6390, 'Users who have the <em>Administer vocabularies and terms</em> permission can add and edit vocabularies from the <a href=":taxonomy_admin">Taxonomy administration page</a>. Vocabularies can be deleted from their <em>Edit vocabulary</em> page. Users with the <em>Taxonomy term: Administer fields</em> permission may add additional fields for terms in that vocabulary using the <a href=":field_ui">Field UI module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6391, 'Users who have the <em>Administer vocabularies and terms</em> permission or the <em>Edit terms</em> permission for a particular vocabulary can add, edit, and organize the terms in a vocabulary from a vocabulary''s term listing page, which can be accessed by going to the <a href=":taxonomy_admin">Taxonomy administration page</a> and clicking <em>List terms</em> in the <em>Operations</em> column. Users must have the <em>Administer vocabularies and terms</em> permission or the <em>Delete terms</em> permission for a particular vocabulary to delete terms.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6392, 'A user with the <em>Administer fields</em> permission for a certain entity type may add <em>Taxonomy term</em> reference fields to the entity type, which will allow entities to be classified using taxonomy terms. See the <a href=":entity_reference">Entity Reference help</a> for more information about reference fields. See the <a href=":field">Field module help</a> and the <a href=":field_ui">Field UI help</a> pages for general information on fields and how to create and manage them.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6393, 'See the <a href=":entity_reference">Entity Reference help</a> page for the field widgets and formatters that can be configured for any reference field on the <em>Manage display</em> and <em>Manage form display</em> pages. Taxonomy additionally provides an <em>RSS category</em> formatter that displays nothing when the entity item is displayed as HTML, but displays an RSS category instead of a list when the entity item is displayed in an RSS feed.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6394, 'No vocabularies available. <a href=":link">Add vocabulary</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6396, 'Format of the term description.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6397, 'Module responsible for the vocabulary.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6398, 'The Telephone module allows you to create fields that contain telephone numbers. See the <a href=":field">Field module help</a> and the <a href=":field_ui">Field UI help</a> pages for general information on fields and how to create and manage them. For more information, see the <a href=":telephone_documentation">online documentation for the Telephone module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6399, 'The <em>settings</em> and the <em>display</em> of the telephone field can be configured separately. See the <a href=":field_ui">Field UI help</a> for more information on how to manage fields and their display.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6400, 'The Text module allows you to create short and long text fields with optional summaries. See the <a href=":field">Field module help</a> and the <a href=":field_ui">Field UI help</a> pages for general information on fields and how to create and manage them. For more information, see the <a href=":text_documentation">online documentation for the Text module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6401, 'The <em>settings</em> and <em>display</em> of the text field can be configured separately. See the <a href=":field_ui">Field UI help</a> for more information on how to manage fields and their display.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6402, 'If you choose <em>Text (plain)</em> or <em>Text (plain, long)</em> you restrict the input to <em>Plain text</em> only. If you choose <em>Text (formatted)</em>, <em>Text (formatted, long)</em>, or <em>Text (formatted, long with summary)</em> you allow users to write formatted text. Which options are available to individual users depends on the settings on the <a href=":formats">Text formats and editors page</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6404, 'The Toolbar module provides a toolbar for site administrators, which displays tabs and trays provided by the Toolbar module itself and other modules. For more information, see the <a href=":toolbar_docs">online documentation for the Toolbar module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6405, 'Uninstalled modules', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6373, 'Put your site into <a href=":url">maintenance mode</a>.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6406, 'Uninstalled themes', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6375, 'Updates were attempted. If you see no failures below, you may proceed happily back to your <a href=":url">site</a>. Otherwise, you may need to update your database manually.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6374, 'All errors have been <a href=":url">logged</a>.', '', '11.3.5');
