INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6395, 'No terms available. <a href=":link">Add term</a>.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6408, 'New release(s) available for @site_name', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6409, 'Your site is currently configured to send these emails when any updates are available. To get notified only for security updates, @url.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6410, 'Your site is currently configured to send these emails only when security updates are available. To get notified for any available updates, @url.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6412, 'There was a problem checking <a href=":update-report">available updates</a> for your modules or themes.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6413, '%archive_file contains a version of %names that is not compatible with Drupal @version.%archive_file contains versions of modules or themes that are not compatible with Drupal @version: %names', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6419, 'The User module allows users to register, log in, and log out. It also allows users with proper permissions to manage user roles and permissions. For more information, see the <a href=":user_docs">online documentation for the User module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6420, 'After creating roles, you can set permissions for each role on the <a href=":permissions_user">Permissions page</a>. Granting a permission allows users who have been assigned a particular role to perform an action on the site, such as viewing content, editing or creating  a particular type of content, administering settings for a particular module, or using a particular function of the site (such as search).', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6421, 'Because User accounts are an entity type, you can extend them by adding fields through the Manage fields tab on the <a href=":accounts">Account settings page</a>. By adding fields for e.g., a picture, a biography, or address, you can a create a custom profile for the users of the website. For background information on entities and fields, see the <a href=":field_help">Field module help page</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6422, 'A role defines a group of users that have certain privileges. These privileges are defined on the <a href=":permissions">Permissions page</a>. Here, you can define the names and the display sort order of the roles on your site. It is recommended to order roles from least permissive (for example, Anonymous user) to most permissive (for example, Administrator user). Users who are not logged in have the Anonymous user role. Users who are logged in have the Authenticated user role, plus any other roles granted to their user account.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6424, 'Configure site-wide settings and behavior for user accounts and registration. This includes account cancellation methods, the content of user emails and fields attached to users.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6425, 'Manage all user accounts. This includes editing all user information, changes of email addresses and passwords, issuing emails to users and blocking and deleting user accounts.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6428, 'Created a new user account for <a href=":url">%name</a>. No email has been sent.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6429, 'The new user <a href=":url">%name</a> was created without an email address, so no welcome message was sent.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6430, 'A welcome message with further instructions has been emailed to the new user <a href=":url">%name</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6431, 'Password reset instructions will be sent to your registered email address.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6432, 'Send password reset instructions via email.', '', 'none');
