INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6438, 'Contributed projects that support the Views module can be found in the <a href=":node">online documentation for Views-related contributed modules</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6440, 'This link is provided by the Views module. The path can be changed by editing the view <a href=":url">@label</a>', '', 'none');
