INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6444, 'Override the view and other argument titles. You may use Twig syntax in this field as well as the "arguments" and "raw_arguments" arrays.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6445, 'Override the view and other argument titles. You may use Twig syntax in this field.', '', 'none');
