INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6447, 'The category this block will appear under on the <a href=":href">blocks placement page</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6449, 'You may also adjust the @settings for the currently selected access restriction.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6450, 'You may also adjust the @settings for the currently selected cache mechanism.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6452, 'You may also adjust the @settings for the currently selected row style.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6453, 'The following tokens are available for this link. You may use Twig syntax in this field.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6455, 'An offset from the current time such as "@example1" or "@example2"', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6456, 'The Views UI module provides an interface for managing views for the <a href=":views">Views module</a>. For more information, see the <a href=":handbook">online documentation for the Views UI module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6457, 'Views can be enabled or disabled from the <a href=":list">Views list page</a>. To enable a view, find the view within the "Disabled" list and select the "Enable" operation. To disable a view find the view within the "Enabled" list and select the "Disable" operation.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6458, 'Views can be exported and imported as configuration files by using the <a href=":config">Configuration Manager module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6459, 'Advanced Views settings', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6441, '@type language selected for page', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6417, 'Deprecated: Use account-name or display-name instead.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6416, 'Deprecated: User Name', '', '11.3.5');
