INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6427, 'Available variables are: [site:name], [site:url], [user:display-name], [user:account-name], [user:mail], [site:login-url], [site:url-brief], [user:edit-url], [user:one-time-login-url], [user:cancel-url].', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6426, 'Users with the %select-cancel-method or %administer-users <a href=":permissions-url">permissions</a> can override this default method.', '', '11.3.5');
