INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6454, 'You may also adjust the @settings for the currently selected pager.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6463, 'By breaking this lock, any unsaved changes made by @user will be lost.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6474, 'Hide logo', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6475, '@display ''@id'': Component ''@name'' was disabled because its settings depend on removed dependencies.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6476, 'No widget available for: %type.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6478, 'The URL to which the user should be redirected. This can be an internal URL like /node/1234 or an external URL like @url.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6479, 'The Automated Cron module runs cron operations for your site using normal browser/page requests instead of having to set up a separate cron job. The Automated Cron module checks at the end of each server response when cron operation was last ran and, if it has been too long since last run, it executes the cron tasks after sending a server response. For more information, see the <a href=":automated_cron-documentation">online documentation for the Automated Cron module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6480, 'Configuring Automated Cron', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6481, 'On the <a href=":cron-settings">Cron page</a>, you can set the frequency (time interval) for running cron jobs.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6482, 'Disabling Automated Cron', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6483, 'To disable automated cron, the recommended method is to uninstall the module, to reduce site overhead. If you only want to disable it temporarily, you can set the frequency to Never on the Cron page, and then change the frequency back when you want to start it up again.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6484, 'Automated Cron', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6486, 'Automated cron settings', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6487, 'Ban visits from specific IP addresses.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6488, 'You can place a new block in a region by selecting <em>Place block</em> on the <a href=":blocks">Block layout page</a>. Once a block is placed, it can be moved to a different region by drag-and-drop or by using the <em>Region</em> drop-down list, and then clicking <em>Save blocks</em>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6489, 'Block placement is specific to each theme on your site. Changes will not be saved until you click <em>Save blocks</em> at the bottom of the page.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6490, 'Adding comment types', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6491, 'Additional <em>comment types</em> can be created per entity sub-type and added on the <a href=":field">Comment types page</a>. If there are multiple comment types available you can select the appropriate one after adding a <em>Comments field</em>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6492, 'Compare the configuration uploaded to your sync directory with the active configuration before completing the import.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6493, 'Upload a full site configuration archive to the sync directory. It can then be compared and imported on the Synchronize page.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6494, 'The Database Logging module logs system events in the Drupal database. Monitor your site or debug site problems on this page.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6495, 'The Internal Dynamic Page Cache module caches pages for all users in the database, handling dynamic content correctly. For more information, see the <a href=":dynamic_page_cache-documentation">online documentation for the Internal Dynamic Page Cache module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6496, 'The module requires no configuration. Every part of the page contains metadata that allows Internal Dynamic Page Cache to figure this out on its own.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6497, '<strong>Entity Reference</strong> fields allow you to create fields that contain links to other entities (such as content items, taxonomy terms, etc.) within the site. This allows you, for example, to include a link to a user within a content item. For more information, see <a href=":er_do">the online documentation for the Entity Reference module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6498, 'Enable custom storage', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6499, 'An instance-specific widget type', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6500, 'Widget types @types are used in Drupal 6 field instances: widget type @selected_type applied to the Drupal 8 base field', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6501, 'You can define which users will be able to use each text format by selecting roles. To ensure security, anonymous and untrusted users should only have access to text formats that restrict them to either plain text or a safe set of HTML tags. This is because HTML tags can allow embedding malicious links or scripts in text. More trusted registered users may be granted permission to use less restrictive text formats in order to create rich text. <strong>Improper text format configuration is a security risk.</strong>', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6502, 'Each text format uses filters that add, remove, or transform elements within user-entered text. For example, one filter removes unapproved HTML tags, while another transforms URLs into clickable links. Filters are applied in a specific order. They do not change the <em>stored</em> content: they define how it is processed and displayed.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6503, 'Text formats define how text is filtered for output and how HTML tags and other text is displayed, replaced, or removed. <strong>Improper text format configuration is a security risk.</strong> Learn more on the <a href=":filter_help">Filter module help page</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6504, 'A text format contains filters that change the display of user input; for example, stripping out malicious HTML or making URLs clickable. Filters are executed from top to bottom and the order is important, since one filter may prevent another filter from doing its job. For example, when URLs are converted into links before disallowed HTML tags are removed, all links may be removed. When this happens, the order of filters may need to be rearranged.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6462, 'Add @display', '', '11.3.5');
