INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6485, 'Provides an automated way to run cron jobs, by executing them at the end of a server response.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6505, 'Configure how content is filtered when displayed, including which HTML tags are rendered, and enable module-provided filters.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6506, 'A list of HTML tags that can be used. By default only the <em>lang</em> and <em>dir</em> attributes are allowed for all HTML tags. Each HTML tag may have attributes which are treated as allowed attribute names for that HTML tag. Each attribute may allow all values, or only allow specific values. Attribute names or values may be written as a prefix and wildcard like <em>jump-*</em>. JavaScript event attributes, JavaScript URLs, and CSS are always stripped.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6508, 'Overriding default English strings', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6509, 'If translation is enabled for English, you can <em>override</em> the default English interface text strings in your site with other English text strings on the <a href=":translate">User interface translation</a> page. Translation is off by default for English, but you can turn it on by visiting the <em>Edit language</em> page for <em>English</em> from the <a href=":languages">Languages</a> page.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6512, '<q>Log in</q> for anonymous users', '', 'none');
