INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6515, 'Revert content shared among translations', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6517, '- None (original image) -', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6518, 'Only items in the index will appear in search results. To build and maintain the index, a correctly configured <a href=":cron">cron maintenance task</a> is required.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6519, 'The minimum character length for a word to be added to the index. Searches must include a keyword of at least this length.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6520, 'Checking site status', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6521, 'The <a href=":status">Status report</a> provides an overview of the configuration, status, and health of your site. Review this report to make sure there are not any problems to address, and to find information about the software your site and web server are using.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6522, 'In order for the site and its modules to continue to operate well, a set of routine administrative operations must run on a regular basis; these operations are known as <em>cron</em> tasks. On the <a href=":cron">Cron page</a>, you can configure cron to run periodically as part of server responses by installing the <em>Automated Cron</em> module, or you can turn this off and trigger cron from an outside process on your web server. You can verify the status of cron tasks by visiting the <a href=":status">Status report page</a>. For more information, see the <a href=":handbook">online documentation for configuring cron jobs</a>.', '', 'none');
