INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7055, 'The Inline Form Errors module makes it easier for users to identify which errors need to be resolved by providing a summary of all errors and by placing the individual error messages next to the form elements themselves. For more information, see the <a href=":inline_form_error">online documentation for the Inline Form Errors module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7056, 'Displaying error messages', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7057, 'When a form is not filled in correctly (for example, if a required field is left blank), a warning message is displayed at the top of the form. This message links to the affected form elements, and individual error messages are displayed next to each form element.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7058, 'Displaying error messages in browsers with HTML5 form validation', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7059, 'In browsers that support HTML5 form validation, users will first see the error messages generated by their browser. In this case, the inline form error messages are only displayed after the HTML5 validation errors have been resolved.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7061, 'Language format settings', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7062, 'Include locked languages', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7063, 'Creating media items', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7064, 'When a new media item is created, the Media module records basic information about it, including the author, date of creation, and the <a href=":media-type">media type</a>. It also manages the <em>publishing options</em>, which define whether or not the item is published. Default settings can be configured for each type of media on your site.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7065, 'Creating custom media types', '', 'none');
