INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7066, 'The Media module gives users with the <em>Administer media types</em> permission the ability to <a href=":media-new">create new media types</a> in addition to the default ones already configured. Each media type has an associated media source (such as the image source) which support thumbnail generation and metadata extraction. Fields managed by the <a href=":field">Field module</a> may be added for storing that metadata, such as width and height, as well as any other associated values.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7067, 'The Media module also enables you to create multiple versions of any media item, and revert to older versions using the <em>Revision information</em> settings.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7068, 'The Media module makes a number of permissions available, which can be set by role on the <a href=":permissions">permissions page</a>.', '', 'none');
