INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7188, 'Display the file using an HTML5 video tag.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7189, 'Root-relative file URL', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7190, 'An entity field containing a file URI, and a computed root-relative file URL.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7191, '@title field is required if there is @uri input.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7192, 'The Media module manages the creation, editing, deletion, settings, and display of media. Items are typically images, documents, slideshows, YouTube videos, tweets, Instagram photos, etc. You can reference media items from any other content on your site. For more information, see the <a href=":media">online documentation for the Media module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7193, 'Listing media items', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7194, 'Media items are listed at the <a href=":media-collection">media administration page</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7195, 'Adding media to other content', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7196, 'Users with permission to administer content types can add media support by adding a media reference field to the content type on the content type administration page. (The same is true of block types, taxonomy terms, user profiles, and other content that supports fields.) A media reference field can refer to any configured media type. It is possible to allow multiple media types in the same field.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7197, 'Differences between Media, File, and Image reference fields', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7198, '<em>Media</em> reference fields offer several advantages over basic <em>File</em> and <em>Image</em> references:', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7199, 'Media reference fields can reference multiple media types in the same field.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7200, 'Fields can also be added to media types themselves, which means that custom metadata like descriptions and taxonomy tags can be added for the referenced media. (Basic file and image fields do not support this.)', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7201, 'Media types for audio and video files are provided by default, so there is no need for additional configuration to upload these media.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7202, 'Contributed or custom projects can provide additional media sources (such as third-party websites, Twitter, etc.).', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7203, 'Existing media items can be reused on any other content items with a media reference field.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7204, 'For more information, see the <a href="@help_url">Media help page</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7205, 'Media Name', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7206, '%type_name: Create new media', '', 'none');
