INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7223, 'On the <a href=":cache-settings">Performance page</a>, you can configure how long browsers and proxies may cache pages based on the Cache-Control header; this setting is ignored by the Internal Page Cache module, which caches pages permanently until invalidation, unless they carry an Expires header. There is no other configuration.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7224, 'The Settings Tray module allows users with the <a href=":administer_block_permission">Administer blocks</a> and <a href=":contextual_permission">Use contextual links</a> permissions to edit blocks without visiting a separate page. For more information, see the <a href=":handbook_url">online documentation for the Settings Tray module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7225, 'Editing blocks in place', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7226, 'To edit blocks in place, either click the <strong>Edit</strong> button in the toolbar and then click on the block, or choose "Quick edit" from the block''s contextual link. (See the <a href=":contextual">Contextual Links module help</a> for more information about how to use contextual links.)', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7227, 'The Settings Tray for the block will open in a sidebar, with a compact form for configuring what the block shows.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7228, 'Save the form and the changes will be immediately visible on the page.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7229, 'Specify the format of the syslog entry. Available variables are: <dl><dt><code>!base_url</code></dt><dd>Base URL of the site.</dd><dt><code>!timestamp</code></dt><dd>Unix timestamp of the log entry.</dd><dt><code>!type</code></dt><dd>The category to which this message belongs.</dd><dt><code>!ip</code></dt><dd>IP address of the user triggering the message.</dd><dt><code>!request_uri</code></dt><dd>The requested URI.</dd><dt><code>!referer</code></dt><dd>HTTP Referer if available.</dd><dt><code>!severity</code></dt><dd>The severity level of the event; ranges from 0 (Emergency) to 7 (Debug).</dd><dt><code>!uid</code></dt><dd>User ID.</dd><dt><code>!link</code></dt><dd>A link to associate with the message.</dd><dt><code>!message</code></dt><dd>The message to store in the log.</dd></dl>', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7230, 'Either the path ''%path'' is invalid or you do not have access to it.', '', 'none');
