INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7244, 'Enforce a <code>destination</code> parameter in the link to return the user to the original view upon completing the link action. Most operations include a destination by default and this setting is no longer needed.', '', 'none');
