INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7248, 'There are no workflow types available. In order to create workflows you need to install a module that provides a workflow type. For example, the <a href=":content-moderation">Content Moderation</a> module provides a workflow type that enables workflows for content entities.', '', 'none');
