INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7260, 'The Content Moderation module allows you to expand on Drupal''s "unpublished" and "published" states for content. It allows you to have a published version that is live, but have a separate working copy that is undergoing review before it is published. This is achieved by using <a href=":workflows">Workflows</a> to apply different states and transitions to entities as needed. For more information, see the <a href=":content_moderation">online documentation for the Content Moderation module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7261, 'Applying workflows', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7262, 'Moderating content', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7263, 'You can view a list of content awaiting moderation on the <a href=":moderated">moderated content page</a>. This will show any content in an unpublished state, such as Draft or Archived, to help surface content that requires more work from content editors.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7264, 'Each transition is exposed as a permission. If a user has the permission for a transition, they can use the transition to change the state of the content item, from Draft to Published.', '', 'none');
