INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7433, 'Displaying media assets from third-party services, such as YouTube or Twitter, can be risky. This is because many of these services return arbitrary HTML to represent those assets, and that HTML may contain executable JavaScript code. If handled improperly, this can increase the risk of your site being compromised.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7434, 'In order to mitigate the risks, third-party assets are displayed in an iFrame, which effectively sandboxes any executable code running inside it. For even more security, the iFrame can be served from an alternate domain (that also points to your Drupal site), which you can configure on this page. This helps safeguard cookies and other sensitive information.', '', 'none');
