INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7805, 'Filters out unpublished media if the current user cannot view it.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7806, 'The view mode that an embedded media item should be displayed in by default. This can be overridden using the <code>data-view-mode</code> attribute.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7807, 'If none are selected, all will be allowed.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7808, 'View modes selectable in the ''Edit media'' dialog', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7809, 'If two or more view modes are selected, users will be able to update the view mode that an embedded media item should be displayed in after it has been embedded.  If less than two view modes are selected, media will be embedded using the default view mode and no view mode options will appear after a media item has been embedded.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7810, 'The referenced media source is missing and needs to be re-embedded.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7811, '
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7812, 'You can embed media items (using the <code>&lt;drupal-media&gt;</code> tag).', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7813, 'During rendering of embedded media: recursive rendering detected for %entity_id. Aborting rendering.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7814, 'During rendering of embedded media: the media item with UUID "@uuid" does not exist.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7815, 'Embeds media items using a custom tag, <code>&lt;drupal-media&gt;</code>. If used in conjunction with the ''Align/Caption'' filters, make sure this filter is configured to run after them.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7816, 'The Media Library module provides a rich, visual interface for managing media, and allows media to be reused in entity reference fields or embedded into text content. It overrides the <a href=":media-collection">media administration page</a>, allowing users to toggle between the existing table-style interface and a new grid-style interface for browsing and performing administrative operations on media.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7817, 'To learn more about media management, begin by reviewing the <a href=":media-help">documentation for the Media module</a>. For more information about the media library and related functionality, see the <a href=":media-library-handbook">online documentation for the Media Library module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7818, 'Selection dialog', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7819, 'When selecting media for an entity reference field or a text editor, Media Library opens a modal dialog to help users easily find and select media. The modal dialog can toggle between a grid-style and table-style interface, and new media items can be uploaded directly into it.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7820, 'Within the dialog, media items are divided up by type. If more than one media type can be selected by the user, the available types will be displayed as a set of vertical tabs. To users who have appropriate permissions, each media type may also present a short form allowing you to upload or create new media items of that type.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7821, 'Grid-style vs. table-style interface', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7822, 'The Media Library module provides a new grid-style interface for the media administration page that displays media as thumbnails, with minimal textual information, allowing users to visually browse media in their site. The existing table-style interface is better suited to displaying additional information about media items, in addition to being more accessible to users with assistive technology.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7823, 'Reusing media in entity reference fields', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7824, 'Any entity reference field that references media can use the media library. To enable, configure the form display for the field to use the "Media library" widget.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7825, 'Embedding media in text content', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7826, 'To use the media library within CKEditor, you must add the "Insert from Media Library" button to the CKEditor toolbar, and enable the "Embed media" filter in the text format associated with the text editor.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8058, 'Unable to install @theme due to missing module dependencies.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8059, 'Empty version', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7827, 'Both the table-style and grid-style interfaces are regular views and can be customized via the Views UI, including sorting and filtering. This is the case for both the administration page and the modal dialog.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7828, 'Media Library settings', '', 'none');
