INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7869, 'The top-level help topics are listed on the main <a href=":help_page">Help page</a>. Links to other topics, including non-top-level help topics, can be found under the "Related" heading when viewing a topic page.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7870, 'Providing help topics', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7871, 'Translating help topics', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7872, 'The title and body text of help topics provided by contributed modules and themes are translatable using the <a href=":locale_help">Interface Translation module</a>. Topics provided by custom modules and themes are also translatable if they have been viewed at least once in a non-English language, which triggers putting their translatable text into the translation database.', '', 'none');
