INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7878, 'Optionally, click <em>Demonstrate block regions</em> to see the regions of the theme.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7880, 'If you want to change additional settings, find the region where the block you want to update is currently located, and click <em>Configure</em> in the line of the block description.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7881, 'Edit the block''s settings. The available settings vary depending on the module that provides the block, but for all blocks you can change:', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7882, '<em>Block title</em>: The heading for the block on your site -- for some blocks, you will need to check the <em>Override title</em> checkbox in order to enter a title', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7883, '<em>Display title</em>: Check the box if you want the title displayed', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7884, '<em>Visibility</em>: Add conditions for when the block should be displayed', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7885, '<em>Region</em>: Change the theme region the block is displayed in', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7886, 'Click <em>Save block</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7893, 'Place a block into a theme''s region.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7894, 'Click the name of the theme that you want to place the block in.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7895, 'Find the region where you want the block, and click <em>Place block</em> in that region. A modal dialog will pop up.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7896, 'Find the block you want to place and click <em>Place block</em>. A <em>Configure block</em> modal dialog will pop up.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7836, 'Configuration sync directory', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7887, 'What are blocks?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7888, 'Blocks are boxes of content rendered into an area, or region, of a web page of your site. Blocks are placed and configured specifically for each theme.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7889, 'What is the block description?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7890, 'The block description is an identification name for a block, which is shown in the administrative interface. It is not displayed on the site.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7891, 'What is the block title?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7892, 'The block title is the heading that is optionally shown to site visitors when the block is placed in a region.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7873, 'Configuring help search', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7847, 'Require summary', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7860, 'Provides an interface to create workflows with transitions between different states (for example publication or user status) provided by other modules.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7849, 'The summary will also be visible when marked as required.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7854, 'Limit the available operators', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7856, 'Limit the available operators to be shown on the exposed filter.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7857, 'Restrict operators to', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7858, 'Selecting none will make all of them available.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7903, 'What are contextual links?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7905, 'Make sure that the core Contextual Links module is installed, and that you have a role with the <em>Use contextual links</em> permission. Optionally, make sure that a toolbar module is installed (either the core Toolbar module or a contributed module replacement).', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7906, 'Visit a non-administrative page on your site, such as the home page.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7907, 'Locate a block or another area on the page that you want to edit or configure.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7908, 'Make the contextual links button visible by hovering your mouse over that area in the page. In most themes, this button looks like a pencil and is placed in the upper right corner of the page area (upper left for right-to-left languages), and hovering will also temporarily outline the affected area. Alternatively, click the contextual links toggle button on the right end of the toolbar (left end for right-to-left languages), which will make all contextual link buttons on the page visible until it is clicked again.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7909, 'While the contextual links button for the area of interest is visible, click the button to display the list of links for that area. Click a link in the list to visit the corresponding administrative page.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7910, 'Complete your administrative task and save your settings, or cancel the action. You should be returned to the page you started from.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7922, 'See the related topics listed below for specific tasks.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7897, 'Enter a description of your block (to be shown to administrators) and the body text for your block.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7918, 'A menu system, which you can navigate to find pages for administrative tasks. The core Toolbar module displays this menu on the top or left side of the page (right side in right-to-left languages). There are also contributed module replacements for the core Toolbar module, with additional features, such as the <a href="https://www.drupal.org/project/admin_toolbar">Admin Toolbar module</a>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7919, 'The core Shortcuts module enhances the toolbar with a configurable list of links to commonly-used tasks.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7920, 'If you install the core Contextual Links module, non-administrative pages will contain links leading to related administrative tasks.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7921, 'The core Help module displays help topics, and provides a Help block that can be placed on administrative pages to provide an overview of their functionality.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7917, 'Administrative interface overview', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8297, 'What is the search index?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7934, 'Configure the basic settings of your site, including the site name, slogan, main email address, default time zone, default country, and the date formats to use.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7935, 'Enter the site name, slogan, and main email address for your site.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7915, 'Overview of accessibility', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7916, 'The default drag-and-drop user interface for ordering tables in the administrative interface presents a challenge for some users, including keyboard-only users and users of screen readers and other assistive technology. The drag-and-drop interface can be disabled in a table by clicking a link labeled <em>Show row weights</em> above the table. The replacement interface allows users to order the table by choosing numerical weights (with increasing numbers) instead of dragging table rows.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7926, 'Create, view, and use a set of shortcuts to access administrative pages.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7927, 'What are shortcuts?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7929, 'Navigate to an administrative page that you want in your shortcut list.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7930, 'Repeat until all the desired links have been added to your shortcut set.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7931, 'Click <em>Shortcuts</em> in the toolbar to display your shortcuts, and verify that the list is complete.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7932, 'Optionally, click <em>Edit shortcuts</em> at the right end of the shortcut list (left end in right-to-left languages), to remove links or change their order.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7933, 'Click any link in the shortcut bar to go directly to the administrative page.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7898, 'Enter a label for this block type (shown in the administrative interface). Optionally, edit the automatically-generated machine name or the description.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7899, 'Click <em>Save</em>. You will be returned to the <em>Block types</em> page.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7900, 'Click <em>Manage fields</em> in the row of your new block type, and add the desired fields to your block type.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7901, 'Optionally, click <em>Manage form display</em> or <em>Manage display</em> to change the editing form or field display for your block type.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7923, 'Set up your site so that users can search for help.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7924, 'In the <em>Manage</em> administrative menu, navigate to <em>Configuration</em> &gt; <em>Search and metadata</em> &gt; <em>Search pages</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7925, 'Verify that a Help search page is listed in the <em>Search pages</em> section. If not, add a new page of type <em>Help</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7911, 'What are security updates?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7912, 'Any software occasionally has bugs, and sometimes these bugs have security implications. When security bugs are fixed in the core software, modules, or themes that your site uses, they are released in a <em>security update</em>. You will need to apply security updates in order to keep your site secure.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7913, 'Security tasks', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7914, 'Keeping track of updates, updating the core software, and updating contributed modules and/or themes are all part of keeping your site secure. See the related topics listed below for specific tasks.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7964, 'Topics can be provided by modules or themes. Top-level help topics on your site:', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7965, 'Both the table-style and grid-style interfaces are regular views and can be customized via the <a href=":views-ui">Views UI</a>, including sorting and filtering. This is the case for both the administration page and the modal dialog.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7966, 'In the grid-style interface, the fields that are displayed (including which image style is used for images) can be customized by configuring the "Media library" view mode for each of your <a href=":media-types">media types</a>. The thumbnail images in the grid-style interface can be customized by configuring the "Media Library thumbnail (220×220)" image style.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7967, 'When adding new media items within the modal dialog, the fields that are displayed can be customized by configuring the "Media library" form mode for each of your <a href=":media-types">media types</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7968, 'Provides the API allowing to rename URLs.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7969, 'The parent workspace.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7970, 'Merge workspace', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7971, 'Only top-level workspaces can be published.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7972, 'Merge into @target_label', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7973, 'The %label workspace can not be deleted because it has child workspaces.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7974, 'There are no changes that can be merged from %source_label to %target_label.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7975, 'Would you like to merge the contents of the %source_label workspace into %target_label?', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7976, 'Merge workspace contents.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7977, 'The contents of the %source_label workspace have been merged into %target_label.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7978, 'There is @count item that can be merged from %source_label to %target_labelThere are @count items that can be merged from %source_label to %target_label', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7979, 'Workspace selection', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7980, 'Medium 8:7', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7981, 'Responsive 3x2', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7982, 'The field that is going to be used as the RSS item link for each row. This must either be an internal unprocessed path like "node/123" or a processed, root-relative URL as produced by fields like "Link to content".', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7983, 'Recursive rendering detected when rendering entity %entity_type: %entity_id, using the %field_name field on the %parent_entity_type:%parent_bundle %parent_entity_id entity. Aborting rendering.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7985, 'Directory "@temp" has insufficient space. There must be at least @space megabytes free.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7986, 'Width: %width pixels', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7987, 'Height: %height pixels', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7988, 'Heading type', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7943, 'What are 403 and 404 responses?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7945, 'What other errors can occur?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7946, 'Under some situations, your site can generate error messages. These can be due to user errors (such as entering invalid values in a form, or incorrect configuration), PHP runtime errors, or software bugs. Some errors may result in a <em>white screen of death</em> (a totally blank web page response); less drastic errors will generate error messages. You can configure what happens when an error message is generated.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7947, 'If desired, create pages to use for 403 and 404 responses. Note the URLs for these pages.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7936, 'Click <em>Save configuration</em>. You should see a message indicating that the settings were saved.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7948, 'For a production site, select <em>None</em> under <em>Error messages to display</em>. For a site that is in development, select one of the other options, so that you are more aware of the errors the site is generating.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7949, 'Configure settings related to how user accounts are created and deleted.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7950, 'What are the settings related to user account creation and deletion?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7951, 'You can make it possible for new users to register themselves for accounts, with or without email verification or administrative approval. Or, you can make it so only administrators with <em>Administer users</em> permission can register new users.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7952, 'You can configure what happens to content that a user created, if their account is <em>canceled</em> (deleted).', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7953, 'You can edit the email messages that are sent to users when their accounts are pending, approved, created, blocked, or canceled, or when they request a password reset.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7954, 'What are variables in email message text?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7955, '<em>Variables</em> are short text strings, enclosed in square brackets [], that you can insert into configured email message text. When an individual message is generated, data from your site is substituted for the variables. Some commonly-used variables are:', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7956, '[site:login-url]: The URL where users can log in to your site.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7957, '[user:display-name]: The user''s displayed name.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7958, '[user:mail]: The user''s email alias.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7959, '[user:one-time-login-url]: An expiring URL that a user can use to log in once, if they need to reset their password.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7960, 'Select the method you want to use for creating user accounts, and check or uncheck the box that requires email verification, to match the settings you want for your site.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7961, 'Select the desired option for what happens to content that a user created if their account is canceled.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7962, 'Optionally, edit the text of email messages related to user accounts.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7963, 'Verify that the other settings are correct.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7937, 'Select the default country and default time zone for your site.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7938, 'Look at the <em>Patterns</em> for the Default long, medium, and short date formats. If any of them does not match the date format you want to use on your site, click <em>Edit</em> in that row to edit the format.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7939, 'Adjust the <em>Format string</em> until the <em>Displayed</em> format matches what you want. (Date format strings are composed of PHP date format codes.)', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7940, 'Click <em>Save format</em>. You should see a message indicating that the format was saved.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7941, 'Repeat the previous three steps for any other date formats that need to be changed.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7989, '@interval hence', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7984, 'Response status', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7990, 'The @drupal installer requires that the %default-file file must not be deleted or modified from the original download.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7991, 'Field discovery failed for Drupal core version @core. Did this site have the Field module installed? Error: @message', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7992, 'Drupal 9 no longer uses the $settings[''install_profile''] value in settings.php and it should be removed.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7993, '@low_version_number to @high_version_number', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7996, 'Manage workspace', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7997, 'Other workspaces:', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7998, 'View all workspaces', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7999, 'Not compatible', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8002, 'Coverage has ended', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8003, '<a href=":update_status_report">Update to @next_minor or higher</a> soon to continue receiving security updates.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8004, 'Covered until @date', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8005, '<a href=":update_status_report">Update to a supported minor</a> as soon as possible to continue receiving security updates.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8021, 'Enabled (@size)', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8022, 'Depending on your configuration, Drupal can run with a @apcu_size APCu limit. However, a @apcu_default_size APCu limit (the default) or above is recommended, especially if your site uses additional custom or contributed modules.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8023, 'Memory available: @available.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8025, 'The version of Drupal you are trying to update from is too old', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8026, 'Unsupported schema version: @module', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8027, 'The installed version of the %module module is too old to update. Update to an intermediate version first (last removed version: @last_removed_version, installed version: @installed_version).', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8029, '<p class="text-align-center">Explore recipes across every type of occasion, ingredient, and skill level.</p>', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8030, '<p class="text-align-center">Explore recipes across every type of occasion, ingredient, and skill level</p>', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8032, 'Leave blank for all. Otherwise, the first selected item will be the default instead of "Any".', '', 'none');
