INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8008, 'Allows users to translate configuration text.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8009, 'Provides site-wide contact forms and forms to contact individual users.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8010, 'Allows users to translate content.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8054, '@module_name (<span class="admin-missing">missing</span>)', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8016, 'Allows users to create menu links.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8012, 'Logs system events in the database.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8014, 'Provides a user interface for the Field module.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8013, 'Caches pages, including those with dynamic content, for all users.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8018, 'Caches pages for anonymous users and can be used when external page cache is not available.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8015, 'Allows users to configure available languages.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8019, 'Allows users to create search pages based on plugins provided by other modules.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8028, 'Provides a user interface for creating and managing views.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8017, 'Users with sufficient access rights will be able to override these options.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7994, 'Drupal core security coverage', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8007, 'Allows users to comment on content.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (10410, 'America/Detroit', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8020, 'PHP APCu caching', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8000, 'Requires Drupal core:', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8011, 'Provides contextual links to directly access tasks related to page elements.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8001, 'Covered until @end_version', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7995, 'Visit the <a href=":url">release cycle overview</a> for more information on supported releases.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8060, 'Invalid version: @existing_version', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8061, 'Stable 9', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8062, 'A base theme using Drupal 9.0.0''s core markup and CSS.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8063, 'Ban visitors from one or more IP addresses from accessing and viewing your site.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8064, 'Enter an <em>IP address</em> and click <em>Add</em>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8065, 'You should see the IP address you entered listed under <em>Banned IP addresses</em>. Repeat the above steps to ban additional IP addresses.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8098, 'What is an Experimental module?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8099, 'An <em>Experimental</em> module is a module that is still in development and is not yet stable. Using Experimental modules on production sites is not recommended.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8100, 'What are installing and uninstalling?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8101, 'Installing a core or downloaded contributed module means turning it on, so that you can use its features and functionality. Uninstalling means turning it off and removing all of its configuration. A module cannot be uninstalled if another installed module depends on it, or if you have created content on your site using the module -- you would need to delete the content and uninstall dependent modules first.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8102, 'Extending overview', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8103, 'See the related topics listed below for help performing tasks related to extending the functionality of your site.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8086, 'Configure your system so that cron will run automatically.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8087, 'What are cron tasks?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8089, 'What options are available for running cron?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8090, 'If the core Automated Cron module is installed, your site will run cron periodically, on a schedule you can configure.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8091, 'You can set up a task on your web server to visit the <em> cron URL</em>, which is unique to your site, on a schedule.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8092, 'You can also run cron manually, but this is not the recommended way to make sure it is run periodically.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8093, 'If you want to run cron right now, click <em>Run cron</em> and wait for cron to finish.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8094, 'If you have a way to configure tasks on your web server, copy the link where it says <em>To run cron from outside the site, go to</em>. Set up a task to visit that URL on your desired cron schedule, such as once an hour or once a week. (On Linux-like servers, you can use the <em>wget</em> command to visit a URL.) If you configure an outside task, you should uninstall the Automated Cron module.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8095, 'If you are not configuring an outside task, and you have the core Automated Cron module installed, select a schedule for automated cron runs in <em>Cron settings</em> &gt; <em>Run cron every</em>. Click <em>Save configuration</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8147, 'Enter a word from the module name or description into the filter box, to make the list of modules smaller. Locate the module you want to uninstall.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8066, 'What types of data does a site have?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8067, 'What is a content entity?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8068, 'What is a field?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8069, 'Within entity items, the data is stored in individual <em>fields</em>, each of which holds one type of data, such as formatted or plain text, images or other files, or dates. Fields can be added by an administrator on entity sub-types, so that all entity items of a given entity sub-type have the same collection of fields available, and they can be single-valued or multiple-valued. When you create or edit entity items, you are specifying the values for the fields on the entity item.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8070, 'What is a reference field?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8071, 'A <em>reference field</em> is a field that stores a relationship between an entity and one or more other entities, which may belong to the same or different entity type. For example, a <em>Content reference</em> field on a content type stores a relationship between one content item and one or more other content items.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8072, 'What field types are available?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8073, 'The following field types are provided by the core system and core modules (many more are provided by contributed modules):', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8074, 'Boolean, Number (provided by the core system): Stores true/false values and numbers', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8075, 'Comment (provided by the core Comment module): Allows users to add comments to an entity', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8076, 'Date, Timestamp (Datetime module): Stores dates and times', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8077, 'Email (core system): Stores email addresses', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8078, 'Link (Link module): Stores URLs and link text', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8079, 'Telephone (Telephone module): Stores telephone numbers', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8080, 'What is a formatter?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8081, 'A <em>formatter</em> is a way to display a field; most field types offer several types of formatters, and most formatters have settings that further define how the field is displayed. It is also possible to completely hide a field from display, and you have the option of showing or hiding the field''s label when it is displayed.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8082, 'What is a widget?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8083, 'A <em>widget</em> is a way to edit a field. Some field types, such as plain text single-line fields, have only one widget available (in this case, a single-line text input field). Other field types offer choices for the widget; for example, single-valued <em>List</em> fields can use a <em>Select</em> or <em>Radio button</em> widget for editing. Many widget types have settings that further define how the field can be edited.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8084, 'Managing content structure overview', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8085, 'Besides the field modules listed in the previous section, there are additional core modules that you can use to manage your content structure:', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8104, 'Maintaining and troubleshooting overview', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8105, 'Here are some tasks and hints related to maintaining your site, and troubleshooting problems that may come up on your site. See the related topics below for more information.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8106, 'Configure your site so that cron runs periodically.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8107, 'If your site is not behaving as expected, clear the cache before trying to diagnose the problem.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8137, 'What is maintenance mode?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8139, 'Check <em>Put site into maintenance mode</em>, optionally change the <em>Message to display when in maintenance mode</em>, and click <em>Save configuration</em>. Your site will be in maintenance mode.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8140, 'Perform your maintenance operations.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8141, 'Uncheck <em>Put site into maintenance mode</em> and click <em>Save configuration</em>. Your site will be back in normal operation mode.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8132, 'Clear the data in the site cache.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8133, 'What is the cache?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8135, 'Click <em>Clear all caches</em>. Your site''s cached data will be cleared.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8142, 'Install a core module, or a contributed module that has already been downloaded.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8143, 'Enter a word from the module name or description into the filter box, to make the list of modules smaller. Locate the module you want to install.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8144, 'Check the box next to the name of the module you want to install; you can also check more than one box to install multiple modules at the same time. If the checkbox is disabled for the module you are trying to install, expand the information to see why -- you may need to download an additional module that your module requires.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8145, 'Click <em>Install</em> at the bottom of the page. If you chose to install a module with dependencies that were not already installed, or if you chose an Experimental module, confirm your choice on the next page.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8146, 'Wait for the module (or modules) to be installed. You should be returned to the <em>Extend</em> page with a message saying the module or modules were installed.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8109, 'Find the particular sub-type that you want to add the field to, and click <em>Manage fields</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8110, 'Click <em>Add field</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8111, 'The <em>Label</em> field should now be visible; enter a label for the field, which is used as the field label for both content editing and content display.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8112, 'Click <em>Save and continue</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8113, 'On the next screen, enter a value for <em>Allowed number of values</em>. You can limit the field to one value per entity item, a set number of values, or set it to have unlimited values. Click <em>Save field settings</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8114, 'On the next screen, optionally edit the settings for the field, which vary depending on what field type you are creating. For all fields, you can edit the <em>Label</em>, <em>Help text</em> (text to be displayed below the field on the content editing page), and <em>Required field</em> (to make it so a value must be entered in order to save the content when editing). You can also configure a default value for the field.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8108, 'There are several site reports that can help you diagnose problems with your site. There are also two core modules that can be used for error logging: Database Logging and Syslog.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8128, 'In <em>Add a new field</em>, select the type of reference field you want to add. The <em>Reference</em> section of the select list shows the most common types of reference field; choose <em>Other...</em> if the entity type you want to reference is not listed.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8129, 'On the next screen, verify that the type of entity you want to reference is shown in <em>Type of item to reference</em>, or select it if not. Enter a value for <em>Allowed number of values</em>. You can limit the field to one value per entity item, a set number of values, or set it to have unlimited values. Click <em>Save field settings</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8130, 'On the next screen, optionally edit the settings for <em>Label</em>, <em>Help text</em> (text to be displayed below the field on the content editing page), and <em>Required field</em> (to make it so a value must be entered in order to save the content when editing).', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8131, 'In the <em>Reference type</em> section, you will usually want to limit the entity sub-types that can be referenced; for example, if you are creating a <em>Content</em> reference, you can check one or two <em>Content type</em> choices. The choices will be easier for content editors to scan if you also choose a sort value (normally the entity title or label field).', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8115, 'Find the particular sub-type that you want to configure the display of, and click <em>Manage display</em> in the <em>Operations</em> list.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8116, 'Use the drag arrows to order the fields in your preferred order.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8117, 'Drag any fields that you do not wish to see in the display to the <em>Disabled</em> section.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8118, 'In the <em>Label</em> column, select the position for each field label in the display, or <em>- Hidden -</em> to hide a label. You can also choose <em>- Visually Hidden-</em> if you want the label''s text to appear in the HTML page, so that screen readers and search engines can read it, but it will not be visible.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8119, 'In the <em>Format</em> column, select the formatter for displaying each field.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8120, 'After selecting the desired formatters, click the settings gear in each row to change the settings for the formatter.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8121, 'When you are done making changes, click <em>Save</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8122, 'Test the display for your entity sub-type by viewing an entity. If needed, return to these steps to further refine the display.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8123, 'Find the particular sub-type that you want to configure the editing form for, and click <em>Manage form display</em> in the <em>Operations</em> list.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8124, 'Drag any fields that you do not wish to see on the editing form to the <em>Disabled</em> section.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8125, 'In the <em>Widget</em> column, select the widget for editing each field.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8126, 'After selecting the desired widgets, click the settings gear in each row to change the settings for the widget.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8127, 'Test the editing form for your entity sub-type by editing or creating an entity. If needed, return to these steps to further refine the form.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (10411, 'America/Dominica', '', '11.3.5');
