INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8191, 'Olivero', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8192, 'olivero settings', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8193, 'Schema information for module %module was missing from the database. You should manually review the module updates and your database to check if any updates have been skipped up to, and including, %last_update_hook.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8194, 'Add, remove, or rearrange the fields on personal and site-wide contact forms.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8195, 'What are the fields on contact forms?', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8196, 'Click <em>Manage fields</em> for the form you want to change the fields of, and add or remove one or more fields on the form.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8197, 'Click <em>Manage form display</em> to change the order or configuration of the fields on the form.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8198, 'Configure personal contact forms for registered users on the website.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8199, 'In the <em>Contact settings</em> section, check/uncheck the box to enable/disable the contact form for new user accounts.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8200, 'Click <em>Save configuration</em>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8201, 'Verify that permissions are correct for your site''s roles, including the generic <em>Anonymous user</em> and <em>Authenticated user</em>. In order to use personal contact forms, users need both <em>View user information</em> (in the <em>User</em> section, which enables them to view user profiles) and <em>Use users'' personal contact forms</em> (in the <em>Contact</em> section, which enables them to use contact forms if they can view user profiles).', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8202, 'Create a new site-wide contact form.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8203, 'Click <em>Add contact form</em>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8204, 'Fill in the <em>Label</em> (title) for the form, <em>Recipients</em>, and optionally the other settings.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8205, 'Click <em>Save</em>. You should see your new contact form in the table, along with a link to view it.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8206, 'What are contact forms?', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8154, 'Click <em>Add user</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8156, 'Verify that the <em>Roles</em> checked for the new user are correct.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8157, 'If you want the new user to receive an email message notifying them of the new account, check <em>Notify user of new account</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8158, 'Optionally, change other settings on the form.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8159, 'Click <em>Create new account</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8160, 'You will be left on the <em>Add user</em> page; repeat these steps if you have more user accounts to create.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8175, 'Update or delete an existing user account.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8177, 'Click <em>Edit</em> in the <em>Operations</em> area of the account of interest.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8178, 'To delete the user account, scroll to the bottom and click <em>Cancel account</em>. Select what you want to happen to the user''s content on the next screen, and click <em>Cancel account</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8179, 'To update the user account, enter new values in the form and click <em>Save</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8148, 'In the <em>Description</em> column, see if there are reasons that this module cannot be uninstalled. For example, you may have created content using this module (which you would need to delete first), or there may be another module installed that requires this module to be installed (you would need to uninstall the other module first).', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8149, 'If there are no reasons listed, the module can be uninstalled. Check the box in the <em>Uninstall</em> column, next to the module''s name.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8150, 'Click <em>Uninstall</em> at the bottom of the page. Verify the list of modules to be uninstalled and configuration to be deleted on the confirmation page, and click <em>Uninstall</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8151, 'Wait for the module to be uninstalled. You should be returned to the <em>Uninstall</em> page with a message saying the module was uninstalled.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8161, 'Create a new role.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8162, 'Click <em>Add role</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8163, 'Enter the desired <em>Role name</em>. If desired, click <em>Edit</em> to change the <em>Machine name</em> for the role.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8164, 'Click <em>Save</em>. You should be returned to the <em>Roles</em> page and your new role should be in the role list.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8165, 'What is a user?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8166, 'A user is anyone accessing or viewing your site. <em>Anonymous</em> users are users who are not logged in, and <em>Authenticated</em> users are users who are logged in.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8167, 'What is a role?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8168, '<em>Roles</em> are used to group and classify users; each user can be assigned one or more roles. There are also special roles for all anonymous and all authenticated users.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8169, 'What is a permission?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8170, 'Granting a <em>permission</em> to a role allows users who have been assigned that role to perform an action on the site, such as viewing content, editing or creating  a particular type of content, administering settings for a particular module, or using a particular function of the site (such as search).', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8171, 'Overview of managing user accounts and visitors', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8172, 'Modify the permissions for an existing role.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8174, 'Click <em>Save permissions</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8152, 'Run reports to learn about the status and health of your site.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8153, 'If you have the core Database Logging module installed, in the <em>Manage</em> administrative menu, navigate to <em>Reports</em> &gt; <em>Recent log messages</em> to see a report of the error and informational messages your site has generated. You can filter the report by <em>Severity</em> to see only the most critical messages, if desired.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8207, 'There are two different types of contact forms provided by the core Contact module: personal contact forms, which allow users to contact other users on the site, and site-wide contact forms, which allow users to contact site managers or administrators. A site can have more than one site-wide contact form; each has its own fields to fill out, recipients, and URL; you can also change the fields that are shown on personal contact forms.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8208, 'Site visitors can email registered users on your site by using the personal contact form, without knowing or learning the email address of the recipient. When a user with the correct permissions is viewing another user''s profile, the viewer will see a <em>Contact</em> tab or link, which leads to the personal contact form if the user whose profile is being viewed has their personal contact form enabled (this is a user account setting).', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8209, 'Contact form management tasks', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8210, 'See the related topics below for specific tasks.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8211, 'Click <em>Edit</em> for the site-wide form you want to be the default.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8212, 'Check <em>Make this the default form</em> and click <em>Save</em>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8214, 'Whether to force the output to be an absolute link (beginning with http: or https:)', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8218, 'It looks like you have content on your new site which <strong>may be overwritten</strong> if you continue to run this upgrade. The upgrade should be performed on a clean Drupal @version installation. For more information see the <a target="_blank" href=":id-conflicts-handbook">upgrade handbook</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8219, 'An upgrade has already been performed on this site. To perform a new migration, create a clean and empty new install of Drupal @version. Rollbacks are not yet supported through the user interface. For more information, see the <a href=":url">upgrading handbook</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8220, 'Upgrade a site by importing its files and the data from its database into a clean and empty new install of Drupal @version. See the <a href=":url">Drupal site upgrades handbook</a> for more information.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8221, 'This empty Drupal @version installation you will import the old site to.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8222, 'The menu name (= set name) for this shortcut link.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8223, 'There are errors with some installed themes. Visit the <a href=":link">status report page</a> for more information.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8224, 'There are errors with some installed modules. Visit the <a href=":link">status report page</a> for more information.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8225, 'Display machine name must contain only lowercase letters, numbers, or underscores.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8226, 'Module %name has an entry in the system.schema key/value storage, but is missing from your site. <a href=":url">More information about this error</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8227, 'Module %name has an entry in the system.schema key/value storage, but is not installed. <a href=":url">More information about this error</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8228, 'Missing required data for configuration: %config', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8231, 'What are breakpoints?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8233, 'What are media queries?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8234, 'Media  queries are a formal way to encode breakpoints. For instance, a width breakpoint at 40em would be written as the media query "(min-width: 40em)". Breakpoints are really just media queries with some additional meta-data, such as a name and multiplier information.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8235, 'What are resolution multipliers?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8236, 'What is a breakpoint group?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8237, 'Managing breakpoints and breakpoint groups overview', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8238, 'The <em>Breakpoint</em> module allows you to define breakpoints and breakpoint groups in YAML files. Modules and themes can use the API provided by the <em>Breakpoint</em> module to define breakpoints and breakpoint groups, and to assign resolution multipliers to breakpoints.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8239, 'W3C standards for media queries', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8247, 'What is site performance?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8248, 'Site performance, in this context, refers to speed factors such as the page load time and the response time after a user action on a page.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8249, 'What is caching?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8250, 'Caching is saving already-rendered HTML output and other calculated data for later use the first time it is needed. This saves time, because the next time the same data is needed it can be quickly retrieved instead of recalculated. Automatic caching systems also include mechanisms to delete cached calculations or mark them as no longer valid when the underlying data changes. To facilitate that, cached data has a <em>lifetime</em>, which is the maximum time before the data will be deleted from the cache (forcing recalculation).', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8251, 'What is file aggregation?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8245, 'The core Field UI module provides a user interface for managing fields and their display on entities.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8246, 'The core Layout Builder module provides a more flexible user interface for configuring the display of entities.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8213, 'Click <em>Save settings</em>. You should be returned to the <em>Manage fields</em> page, with your new field in the list.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8240, 'What is a theme?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8241, 'A <em>theme</em> is a set of files that define the visual look and feel of your site. The core software and modules that run on your site determine which content (including HTML text and other data stored in the database, uploaded images, and any other asset files) is displayed on the pages of your site. The theme determines the HTML markup and CSS styling that wraps the content. Several basic themes are supplied with the core software; additional <em>contributed themes</em> can be downloaded separately from the <a href="https://www.drupal.org/project/project_theme">Download &amp; Extend page on drupal.org</a>, or you can create your own theme.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8242, 'What is a base theme?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8243, 'What is a layout?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8244, 'Changing site appearance overview', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8215, 'Checked %langcode translation for %project.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8229, 'Search form (narrow)', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8230, 'Search form (wide)', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (10678, 'Europe/Zagreb', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8216, 'Downloaded %langcode translation for %project.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8265, 'What are the parts of a layout?', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8266, 'Find the particular sub-type that you want to create a layout for, and click <em>Manage display</em> in the <em>Operations</em> list.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8267, 'Under <em>Layout options</em>, check <em>Use Layout Builder</em>. You can also check the box below to allow each entity item to have its layout individually customized (if it is left unchecked, the site will use the same layout for all items of this entity sub-type).', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8268, 'Click <em>Save</em>. You will be returned to the <em>Manage display</em> page, but you will no longer see the table of fields of the classic display manager.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8269, 'Click <em>Manage layout</em> to enter layout management view. A default layout will be set up for you, with a single one-column section containing the fields on your entity sub-type.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8270, 'To remove the default section and start from an empty layout, find and click the <em>Remove</em> button for the default section, which looks like an X. Confirm by clicking <em>Remove</em> in the pop-up dialog.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8271, 'Add new sections, each with one to four columns, to your layout. For instance, you might want a one-column section at the top, a two-column section in the middle, and then a one-column section at the bottom. To add a section, click <em>Add section</em> and click the desired number of columns. For multi-column sections, set the column width percentages and click <em>Add section</em> in the pop-up dialog.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8272, 'In each section, click <em>Add block</em> to add a block. You will see a list of the blocks available on your site, plus a section called <em>Content fields</em> with a block for each field on your content item. Each block can be configured, if desired, with a <em>Title</em>, and for content field blocks, you can also configure the field formatter. Continue to add blocks to your sections until all the desired blocks and fields are displayed.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8273, 'Verify your layout. You can check <em>Show content preview</em> to show a preview of what your layout will look like, or uncheck it to see the names of the fields and blocks in each section.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8274, 'If needed, reorder the blocks by dragging them to new locations. If you hover over a block, a contextual menu will appear that will let you change the configuration of the block, remove the block, or <em>Move</em> blocks within the section using a more compact interface.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8275, 'When you are satisfied with your layout, click <em>Save layout</em>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8276, 'Creating layout defaults', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8277, 'Building Layouts Using the Layout Builder UI', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8286, 'The form has become outdated. Press the back button, copy any unsaved work in the form, and then reload the page.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8287, 'Deployment identifier', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8279, 'Locate the themes that you want to use as the site default theme and for administrative pages.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8281, 'Locate the theme that you want to be your default theme, which should now be in the <em>Installed themes</em> section. If it is not already labeled as the <em>default theme</em>, click the <em>Set as default</em> link.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8282, 'At the bottom of the page, select the <em>Administration theme</em> that you want to use on administrative pages. Click <em>Save configuration</em> if you selected a new theme.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8283, 'If you changed the default theme for your site, visit the site home page or another page on the non-administration part of your site and verify that the site is using the new theme. If you changed the administration theme, verify that the new theme is used on administrative pages.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8284, 'Uninstall a theme that was previously installed, but is no longer being used on the site.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8285, 'Locate the theme that you want to uninstall, in the <em>Installed themes</em> section.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8288, 'Configure one or more search pages.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8289, 'Scroll down to the <em>Search pages</em> section. You will see a list of the already-configured search pages on your site.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8290, 'To configure an existing search page, click <em>Edit</em>. Or, to add a new search page, select the <em>Search page type</em> and click <em>Add search page</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8291, 'Enter the desired <em>Label</em> name and URL <em>Path</em> for the search page.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8292, 'For <em>Content</em> search pages, select the desired level of influence in ranking search results of the available <em>Content ranking</em> factors.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8293, 'Click <em>Save</em>. You will be returned to the <em>Search pages</em> page.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8294, 'Verify that the correct search page is listed as <em>Default</em> in the <em>Status</em> column. If not, click <em>Set as default</em> in the <em>Operations</em> list for the correct search page.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8296, 'Manage the search index, and make sure that the site is fully indexed for searching.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8252, 'Aggregation is when CSS and JavaScript files are merged together and compressed into a format that is much smaller than the original. This allows for faster transmission and faster rendering on the other end.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8253, 'What can I do to improve my site''s performance?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8254, 'Internal Page Cache module', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8255, 'Caches pages requested by users who are not logged in (anonymous users). Do not use if your site needs to send different output to different anonymous users.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8256, 'Internal Dynamic Page Cache module', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8257, 'Caches data for both authenticated and anonymous users, with non-cacheable data in the page converted to placeholders and calculated when the page is requested.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8258, 'Big Pipe module', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8259, 'Changes the way pages are sent to users, so that cacheable parts are sent out first with placeholders, and the uncacheable or personalized parts of the page are streamed afterwards. This allows the browser to render the bulk of the page quickly and fill in the details later.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8260, 'Performance page settings', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8261, 'In the <em>Manage</em> administrative menu, if you navigate to <em>Configuration</em> &gt; <em>Development</em> &gt; <em>Performance</em>, you will find a setting for the maximum cache lifetime, as well as the ability to turn on CSS and JavaScript file aggregation.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8262, 'Online documentation for the Internal Page Cache module', '', '11.3.2');
