INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8299, 'Under <em>Default indexing settings</em>, enter the desired <em>Minimum word length to index</em>. Words smaller than this length will be dropped from both keywords when searching and content when indexing.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8300, 'If your site uses Chinese, Japanese, or Korean languages, optionally check <em>Simple CJK handling</em> under <em>Default indexing settings</em> to provide some support for these languages.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8301, 'Click <em>Save configuration</em>, and you should be returned to the <em>Search pages</em> page.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8302, 'Click <em>Re-index site</em> if you have changed the indexing configuration, or later on, if you believe that the search index has been corrupted.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8303, 'After waiting for cron to run several times, verify that the content has been fully indexed for searching. The overall status is listed under <em>Indexing progress</em>, and the status for each search page is shown in the <em>Indexing progress</em> column of the <em>Search pages</em> section.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8328, 'Managing height, width, and resolution breakpoints', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8352, 'Changing basic site settings', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8340, 'Optimizing site performance', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8344, 'Adding a field to an entity sub-type', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8339, 'Maintaining and troubleshooting your site', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8363, 'Modifying the permissions for a role', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8326, 'Managing blocks', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8335, 'Changing the appearance of your site', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8357, 'Running reports on your site', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8349, 'Configuring site search', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8304, 'What are search pages?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8306, 'What modules provide site search?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8307, 'The core Search module provides the ability to configure search pages; search page types are provided by both core and contributed modules. The core modules that provide search page types are:', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8308, 'The Node module, for searching content pages', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8309, 'The User module, for searching user profiles', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8310, 'The Help module, for searching help topics', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8311, 'As an alternative to the core Search module''s system of search pages, you can use contributed modules to provide site search. For example, the <a href="https://www.drupal.org/project/apachesolr">Apache Solr</a> and <a href="https://www.drupal.org/project/sphinx">Sphinx</a> contributed modules use third-party technology to provide site search.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8312, 'What are the limitations of the core Search module?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8314, 'What are the search permissions?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8315, 'Users with <em>Use search</em> permission can use the <em>Search form</em> block and <em>Search</em> page; this permission is required for any search configured in the core Search module.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8316, 'In addition to <em>Use search</em>, <em>View user information</em> permission is needed for searching users.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8317, 'In addition to <em>Use search</em>, <em>View published content</em> permission is needed for searching content.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8318, 'Users with <em>Use advanced search</em> permission can use more complex search filtering when performing content searches.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8319, 'Configuring site search overview', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8320, '<a href="https://www.drupal.org/documentation/modules/search">Online documentation for the Search module</a>', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8350, 'Creating and using shortcut administrative links', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8347, 'Adding a reference field to an entity sub-type', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8341, 'Making your site secure', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8345, 'Configuring field display for an entity sub-type', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8346, 'Configuring the edit form for an entity sub-type', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8368, 'Site branding background color', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8379, 'Migration failed with source plugin exception: @e in @file line @line', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8380, 'Display %display has set node/% as path. This will not produce what you want. If you want to have multiple versions of the node view, use Layout Builder.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8381, 'See <a href="https://www.php.net/manual/datetime.format.php#refsect1-datetime.format-parameters" target="_blank">the documentation for PHP date formats</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8382, 'A user-defined date format. See the <a href="https://www.php.net/manual/datetime.format.php#refsect1-datetime.format-parameters">PHP manual</a> for available options.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8383, 'Manage translations for any entity that the user can edit', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8384, 'The Filter module allows administrators to configure text formats. Text formats change how HTML tags and other text will be <em>processed and displayed</em> in the site. They are used to transform text, and also help to defend your website against potentially damaging input from malicious users. Visual text editors can be associated with text formats by using the <a href=":editor_help">Text Editor module</a>. For more information, see the <a href=":filter_do">online documentation for the Filter module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8393, 'What is a menu?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8395, 'Managing menus overview', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8385, 'There are four main types of data. <em>Content</em> is the information (text, images, etc.) meant to be displayed to website visitors. <em>Configuration</em> is data that defines how the content is displayed; some configuration (such as field labels) may also be visible to site visitors. <em>State</em> is temporary data about the state of your site, such as the last time the system <em>cron</em> jobs ran. <em>Session</em> is a subset of State information, related to users'' interactions with the site, such as site cookies and whether or not they are logged in.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8386, 'List (Options module): Stores values chosen from pre-defined lists, where the values can be numbers or text; see section below for more on list fields.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8387, 'Reference (core system): Stores entity references; see section above', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8388, 'Text (Text module): Stores formatted and unformatted text; see section below for more on text fields.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8389, 'What settings are available for List field types?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8390, 'List fields associate pre-defined <em>keys</em> (or value codes) with <em>labels</em> that the user sees. For example, you might define a list field that shows the user the names of several locations, while behind the scenes a location code is stored in the database. Each list field type corresponds to one type of stored key. For example, a <em>List (integer)</em> field stores integers, while the <em>List (text)</em> field stores text strings. Once you have chosen the field type, the main setting for a list field is the <em>Allowed values</em> list, which associates the keys with the labels.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8391, 'What types of Text fields are available?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8397, 'Enabling web services', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8398, 'What is a web service?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8399, 'A web service allows your site to provide its content and data to other web sites and applications. Typically, the data is transported via <a href="https://en.wikipedia.org/wiki/Hypertext_Transfer_Protocol">HTTP</a> in a serialized machine-readable format.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8400, 'What is serialization?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8401, 'Serialization is the process of converting complex data structures into text strings, so that they can be exchanged and stored. The reverse process is called <em>deserialization</em>. JSON and XML are the two most-commonly-used data serialization formats for web services.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8402, 'What is HTTP Basic authentication?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8403, '<a href="http://en.wikipedia.org/wiki/Basic_access_authentication">HTTP Basic authentication</a> is a method for authenticating requests by sending a user name and password along with the request.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8369, '<em>You haven’t created any frontpage content yet.</em>', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8370, 'Drupal is an open source platform for building amazing digital experiences. It’s made, used, taught, documented, and marketed by the <a href="@drupal_community">Drupal community</a>. Our community is made up of people from around the world with a shared set of <a href="@drupal_values">values</a>, collaborating together in a respectful manner. As we like to say:', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8371, 'Come for the code, stay for the community.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8372, 'There are a few ways to get started with Drupal:', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8373, '<a href="@drupal_user_guide">User Guide:</a> Includes installing, administering, site building, and maintaining the content of a Drupal website.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8374, '<a href="@create_content">Create Content:</a> Want to get right to work? Start adding content. <strong>Note:</strong> the information on this page will go away once you add content to your site. Read on and bookmark resources of interest.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8375, '<a href="@drupal_extend">Extend Drupal:</a> Drupal’s core software can be extended and customized in remarkable ways. Install additional functionality and change the look of your site using addons contributed by our community.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8376, 'Bookmark these links to our active Drupal community groups and support resources.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8377, '<a href="@drupal_events">Upcoming Events:</a> Learn and connect with others at conferences and events held around the world.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8378, '<a href="@drupal_community">Community Page:</a> List of key Drupal community groups with their own content.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8443, 'Locate the desired menu and click <em>Add link</em> in the <em>Operations</em> list.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8444, 'Enter the <em>Menu link title</em> to be displayed.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8445, 'Enter the <em>Link</em>, one of the following:', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8446, 'An internal path, such as <em>/node/add</em>', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8447, 'A full external URL', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8448, 'Start typing the title of a content item and select it when the full title comes up', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8449, '<em>&lt;nolink&gt;</em> to display the <em>Menu link title</em> as plain text without a link', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8450, '<em>&lt;front&gt;</em> to link to the front page of your site', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8451, 'Make sure that <em>Enabled</em> is checked; if not, the menu link will not be displayed.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8452, 'Optionally, enter a <em>Description</em>, which will be displayed when a user hovers over the link.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8453, 'Optionally, check <em>Show as expanded</em> to automatically show the children of this link (if any) when this link is shown.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8454, 'Optionally, select the <em>Parent link</em>, if this menu link should be a child of another menu link.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8455, 'Click <em>Save</em>. You will be returned to the <em>Add link</em> page to add another link.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8456, 'Locate the menu you just added a link to and click <em>Edit</em> in the <em>Operations</em> list.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8457, 'Verify that the order of links is correct. If it is not, drag menu links until the order is correct, and click <em>Save</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8436, 'Configure menu settings for a content type', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8438, 'Locate the content type you want to configure, and click <em>Edit</em> in the <em>Operations</em> list.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8439, 'Under <em>Menu settings</em>, check the menus that you want to be available when editing a content item of this type.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8440, 'Optionally, select the <em>Default parent item</em>, to put links to content items under a default location in the menu structure.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8415, 'Managing text filters and text formats', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8416, 'Configure text formats on the site.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8417, 'What are text filters and text formats?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8419, 'Text fields that have "formatted" in the field type name, such as <em>Text (formatted)</em>, use text formats. Users choose the text format when editing the field text; when the field text is shown on the site, it is processed by the chosen text format. Administrators can configure text formats and assign permissions for who can use each format. If the core Text Editor module is enabled, administrators can also associate visual editors with text formats.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8420, 'What text filters are available?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8421, 'Some of the more commonly used text filters are:', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8422, 'Limits which HTML tags can be used; useful both for site security and enforcing site design.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8423, 'Line breaks in HTML source are displayed as horizontal spaces. This filter converts line breaks into HTML paragraph and line break tags.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8424, 'Takes plain URLs in text and turns them into HTML links.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8425, 'For text formats that allow HTML image tags, restricts images to URLs within this site.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8426, 'Click <em>Configure</em> to configure an existing text format, or <em>+ Add text format</em> to create a new text format.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8427, 'Enter the desired <em>Name</em> for the text format.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8428, 'Check the <em>Roles</em> that can use this text format. Some HTML tags allow users to embed malicious links or scripts in text. To ensure security, anonymous and untrusted users should only have access to text formats that restrict them to either plain text or a safe set of HTML tags. <strong>Improper text format configuration is a security risk.</strong>', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8429, 'If the core Text Editor module is installed, see the related topic to connect a text editor to this text format.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8430, 'Under <em>Enabled filters</em>, check the text filters that you want to use.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8431, 'Under <em>Filter processing order</em>, drag the filters to the correct order. Choose the order carefully; for example, if you have a filter that results in a particular HTML tag being added to the text, that should run after a filter that restricts HTML tags, to avoid deleting the new tags the first filter added.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8432, 'Under <em>Filter settings</em>, verify and adjust the settings for each active filter that has configuration options.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8433, 'Click <em>Save configuration</em>, which will return you to the <em>Text formats and editors</em> page.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8434, 'Repeat these steps if you have additional text formats to configure.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8458, 'Creating a menu', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8459, 'Create a new menu.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8460, 'Click <em>Add menu</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8461, 'Enter the title for the menu, which is used as the default block title if the menu is displayed as a block. If desired, also edit the machine name of the menu, which is by default derived from the title.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8462, 'Enter an administrative summary, which is displayed on the <em>Menus</em> page.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8414, 'What is a text editor?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8404, 'What modules provide web services?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8405, 'JSON:API module', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8406, 'RESTful Web Services module', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8407, 'Serialization module', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8408, 'Provides a framework for adding specific serialization formats for other modules to use.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8409, 'HTTP Basic Authentication module', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8410, 'There are also contributed modules that provide web services.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8411, 'Online documentation for the RESTful Web Services module', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8412, 'Online documentation for the JSON:API module', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8413, 'Comparison of the RESTFul Web Services and JSON:API modules', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8435, 'In the <em>Manage</em> administrative menu, navigate to <em>Structure</em> &gt; <em>Block layout</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8467, 'Click <em>Edit menu</em> for the menu that you want to edit.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8468, 'Drag menu links into a new order, or check/uncheck <em>Enabled</em> to enable or disable menu links.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8469, 'Click <em>Save</em> to save your changes.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8503, 'Editing an existing view display', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8473, 'Managing content listings (views)', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8504, 'Edit an existing view display, to modify what data is displayed or how it is displayed.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8505, 'Under <em>Displays</em>, click the display you want to edit.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8508, 'When you have finished changing all the settings, verify that the display is correct by clicking <em>Update preview</em>. Return to editing settings if necessary.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8509, 'When you have verified the display, click <em>Save</em>. Alternatively, if you have made mistakes and want to discard your changes, click <em>Cancel</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8496, 'Creating a new view', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8497, 'Create a new view to list content or other items on your site.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8498, 'Click <em>Add view</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8499, 'In the <em>View name</em> field, enter a name for the view, which is how it will be listed in the administrative interface.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8500, 'In <em>View settings</em> &gt; <em>Show</em>, select the base data type to display in your view. This cannot be changed later.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8501, 'Optionally, select or enter filtering, sorting, and page/block display settings; these can be added or changed later.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8502, 'Click <em>Save and edit</em>. Your view will be created; edit it following the steps in the related topics below.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8564, 'Click <em>Export</em> and save the archive file.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8463, 'If your site has more than one language, choose the language for the menu.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8464, 'Click <em>Save</em>. You will be on the menu editing page, ready to add links to the menu if the core Custom Menu Links module is installed; see related topics for further tasks.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8565, 'Select the <em>Configuration type</em> that you want to export, and then select the specific <em>Configuration name</em> to export.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8566, 'Use your browser to copy the text in the box marked <em>Here is your configuration</em> to the clipboard.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8471, '[site:name]: The name of your website.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8472, '[site:url]: The URL of your website.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8470, '<a href="https://www.php.net/manual/datetime.format.php#refsect1-datetime.format-parameters">PHP date format codes reference</a>', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8474, 'What is a view?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8475, 'A <em>view</em> is a listing of items on your site; for example, a block showing the most recent comments, a page listing news items, or a list of registered users. The listings can be formatted in a table, grid, list, calendar, RSS feed, and other formats (some output formats may require you to install additional contributed modules).', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8476, 'What are the components of a view?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8477, 'When you first create a view, you will specify what type of <em>base data</em> is being displayed in the view, which cannot be changed. After choosing a base data type, you can edit the following components, which allow you to specify which data to output, in what order, and in what format:', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8478, '<em>Displays</em>: whether the output goes to a page, block, feed, etc.; a single view can have multiple displays, each with different settings.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8479, '<em>Format</em>: the output style for each display, such as content item, grid, table, or HTML list.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8480, '<em>Fields</em>: if the Format allows, the particular fields to display.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8481, '<em>Filter criteria</em>: criteria to limit the data to output, such as whether the content is published, the type of content, etc. Filters can be <em>exposed</em> to let users choose how to filter the data.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8482, '<em>Sort criteria</em>: how to order the data. Sorting can also be exposed to users.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8483, '<em>Header</em> and <em>Footer</em>: content to display at the top or bottom of the view display.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8484, '<em>No results behavior</em>: what to do if the filter criteria result in having no data to display.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8485, '<em>Pager</em>: how many items to display, and how to paginate if there are additional items to display.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8486, '<em>Advanced</em> &gt; <em>Contextual filters</em>: like regular filters, except the criteria come from the <em>context</em>, such as the current date, page the view is displayed on, etc.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8487, '<em>Advanced</em> &gt; <em>Relationships</em>: additional data to pull in and display, related in some way to the base data of the view (such as data about the user who created the content item).', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8488, '<em>Advanced</em> &gt; <em>Exposed form</em>: if you have exposed filters or sorts, how to display the form to the user.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8489, 'Managing views overview', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8490, 'The core Views module handles the display of views, and the core Views UI module allows you to create, edit, and delete views in the administrative interface. See the related topics listed below for specific tasks (if the Views UI module is installed).', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8491, 'Adding a new display to an existing view', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8492, 'Add a new display to an existing view. This will allow you to display similar data to an existing view, using similar settings, in a new block, page, feed, etc.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8493, 'Under <em>Displays</em>, click <em>Add</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8494, 'In the pop-up list, click the link for the type of display you want to add; the most common types are <em>Page</em> and <em>Block</em>. The new display will be added to your view, and you will be editing that display.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8495, 'Optionally, click the link next to <em>Display name</em> and enter a new name to be shown for this display in the administrative interface.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8510, 'For accessibility and search engine optimization, all images that convey meaning on websites should have alternate text. Drupal also allows entry of title text for images, but it can lead to confusion for screen reader users and its use is not recommended. Image fields can be configured so that alternate and title text fields are enabled or disabled; if enabled, the fields can be set to be required. The recommended setting is to enable and require alternate text and disable title text.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8511, 'This must be an internal path such as %add-node. You can also start typing the title of a piece of content to select it. Enter %front to link to the front page. Enter %nolink to display link text only. Enter %button to display keyboard-accessible link text only.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8513, 'It is potentially insecure to display oEmbed content in a frame that is served from the same domain as your main Drupal site, as this may allow execution of third-party code. Refer to <a href="https://oembed.com/#section3">oEmbed Security Considerations</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8514, 'It is potentially insecure to display oEmbed content in a frame that is served from the same domain as your main Drupal site, as this may allow execution of third-party code. <a href=":url">You can specify a different domain for serving oEmbed content in the Media settings</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8515, 'If checked, users creating new media items in the media library will see a summary of their selected media items, and they will be able to insert their selection directly into the media field or text editor.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8516, 'A flag for whether the link should be rendered in menus. (1 = a disabled menu link that may be shown on admin screens, -1 = a menu callback, 0 = a normal, visible link)', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8517, 'Menu link language code.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8518, 'Translation set id.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8519, 'Menu link ID of the source language menu link.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8520, 'Users with the <em>Administer menus and menu links</em> permission can add, edit, and delete custom menus on the <a href=":menu">Menus page</a>. Custom menus can be special site menus, menus of external links, or any combination of internal and external links. You may create an unlimited number of additional menus, each of which will automatically have an associated block (if you have the <a href=":block_help">Block module</a> installed). By selecting <em>Edit menu</em>, you can add, edit, or delete links for a given menu. The links listing page provides a drag-and-drop interface for controlling the order of links, and creating a hierarchy within the menu.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8523, 'The selected menu link is not under one of the selected menus.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8524, '<strong>Warning:</strong> There is currently 1 menu link in %title. It will be deleted (system-defined links will be reset).<strong>Warning:</strong> There are currently @count menu links in %title. They will be deleted (system-defined links will be reset).', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8525, 'Drupal @version module name', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8526, 'Drupal @version machine name', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8527, 'The human-readable name of the mapping', '', 'none');
