INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8529, 'The group this mapping belongs to', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8530, 'The mappings linked to the breakpoints group', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8532, 'You can display your shortcuts by enabling the <em>Shortcuts</em> block on the <a href=":blocks">Blocks administration page</a>. Certain administrative modules also display your shortcuts; for example, the core <a href=":toolbar-help">Toolbar module</a> provides a corresponding menu link.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8533, 'The new set is created by copying links from your default shortcut set.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8534, 'The new set is created by copying links from the %default set.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8535, 'The menu.mlid primary key for this menu link (= shortcut link).', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8537, 'The menu is only visible if the menu link for the current page is at this level or below it. Use level 1 to always display this menu.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8538, 'Menu language.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8539, 'Menu i18n mode.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8541, 'Flood control blocked login attempt for uid %uid from %ip', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8542, 'Flood control blocked login attempt for uid %uid', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8543, 'Flood control blocked login attempt from %ip', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8544, 'Menu link entry', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8545, 'When providing a menu link as a tab, Drupal needs to know what the parent menu link of that tab will be. Sometimes the parent will already exist, but other times you will need to have one created. The path of a parent link will always be the same path with the last part left off. i.e, if the path to this view is <em>foo/bar/baz</em>, the parent path would be <em>foo/bar</em>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8546, 'Normal menu link', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8547, 'If creating a parent menu link, enter the title of the link.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8548, 'If creating a parent menu link, enter the description of the link.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8549, 'If the parent menu link is a tab, enter the weight of the tab. Heavier tabs will sink and the lighter tabs will be positioned nearer to the first menu link.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8550, 'Views cannot create normal menu links for paths with a % in them.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8551, 'If "Custom", see <a href="https://www.php.net/manual/datetime.format.php#refsect1-datetime.format-parameters" target="_blank">the PHP docs</a> for date formats. Otherwise, enter the number of different time units to display, which defaults to 2.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8552, 'Primary Branding Color', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8557, 'Failed to fetch available update data:', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8558, 'See <a href="@url">PHP OpenSSL requirements</a> in the Drupal.org handbook for possible reasons this could happen and what you can do to resolve them.', '', 'none');
