INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8553, 'A clean, accessible, and flexible Drupal front-end theme.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8521, 'Default parent link', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8536, 'Administer menus and menu links', '', '11.3.5');
