INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8601, 'Managing media', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8568, 'Importing your complete site configuration', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8569, 'Browse to find the <em>Configuration archive</em> that you want to import.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8570, 'Click <em>Upload</em>. Your configuration archive will be unpacked and placed in the configuration synchronization directory, and you will be redirected to the <em>Synchronize</em> page.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8571, 'Review the differences between your uploaded configuration and the active configuration, if any, and click <em>Import all</em> to import the changes.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8577, 'What is the configuration system?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8579, 'Providing storage for configuration', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8580, 'Providing a process in which configuration changes can be imported and exported between instances of the same site; for example, from "dev" to "staging" to "live"', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8581, 'What is configuration data?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8582, 'Configuration data describes settings that define how your site behaves or is displayed. For example, when a site administrator updates settings using an administrative form, these settings are stored as configuration data. Configuration data describes settings as simple as a site name and as complex as a view or image style.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8583, 'What kinds of configuration are there?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8584, 'Active configuration', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8585, 'Active configuration is the current working configuration of a site. Storage of active configuration is defined by the site, and resides in the database by default.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8586, 'A simple configuration item is a group of settings, such as the settings for a module or theme. Each simple configuration item has its own unique structure.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8587, 'Configuration entities are user-defined configuration items grouped by type, such as views, image styles, and content types. Each configuration entity within a type has a similar structure.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8589, 'What is configuration synchronization?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8590, 'Configuration synchronization is the process of exporting and importing configuration to keep configuration synchronized between different versions of a site; for example, between a development site and the live site.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8591, 'Each site has unique identifier, also called a <em>UUID</em>, which identifies the site to the system in any instance of the site, as long as the site instances have been reproduced as clones (cloning is when the codebase and database are copied to create a new site instance). When site instances are cloned, a "dev" instance of the site has the same UUID as the "live" instance. When site instances share the same UUID, configuration can be exported from one instance to another.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8592, 'The following list contains terms and concepts related to configuration synchronization:', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8593, 'Exported configuration', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8594, 'When configuration is exported, the active configuration is exported as a set of files in YAML format. When using the <em>Configuration synchronization</em> administrative UI, configuration can be exported as a full-export or single-item archive. This archive can then be imported into the destination site instance.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8595, 'Imported configuration', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8596, 'Imported configuration is configuration that has been exported from another instance of the site (the "source") and is now being imported into another site instance (the "destination"), thereby updating its active configuration to match the imported configuration data set.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8597, 'The configuration sync directory location is set in the site''s <em>settings.php</em> file. When configuration is exported, the active configuration is exported and described in YAML files which are stored in the configuration sync directory. After the first export, the system compares the site''s active configuration with the configuration data in the sync directory and will only export active configuration items that are different than their counterparts in the sync directory.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8598, 'Managing configuration overview', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8599, 'Configuration management tasks, such as exporting or importing configuration and synchronizing configuration, can be done either through the administrative UI provided by the core Configuration Manager module or a command-line interface (CLI) tool. Defining a configuration sync directory path other than the default value requires read/write access to the site''s <em>settings.php</em> file.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8600, 'Most modules and themes also provide settings forms for updating the configuration they provide. See the related topics listed below for specific tasks.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8602, 'What are media items?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8603, 'What is the media library?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8604, 'The media library is a visual user interface for managing and reusing media items. Add media items to content using Media reference fields and the Media library field widget.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8605, 'What is an image style?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8606, 'An image style is a set of processing steps, known as <em>effects</em>, that can be applied to images. Examples of effects include scaling and cropping images to different sizes. Responsive image styles can associate image styles with your theme''s size breakpoints. This allows serving images sized for the browser width.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8607, 'Overview of managing media', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8608, 'The following modules provide media-related functionality:', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8609, 'Media items and media types are managed by the core Media module.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8572, 'Select the <em>Configuration type</em> that you want to import.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8573, 'On your computer or other device, copy the YAML-format configuration that you want to import to the clipboard.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8574, 'Paste the clipboard text into the box labeled <em>Paste your configuration here</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8575, 'Click <em>Import</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8621, 'Adding a new media type', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8622, 'If there is not already a media type for the type of media you want to use on your site, click <em>Add media type</em>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8623, 'Enter a <em>Name</em> and <em>Description</em> for your media type, and select the <em>Media source</em>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8624, 'For most media sources, there is additional information that will need to be stored with your media item, in a field on your media type. Under <em>Media source configuration</em>, select an existing field to re-use to store this information, or select <em> - Create -</em> to create a new field.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8625, 'Note the types of metadata in the <em>Field mapping</em> section that can be mapped to fields on your media type.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8626, 'Optionally, add additional fields for the metadata noted above or for other information that you want to store to your media type by clicking on <em>Manage fields</em> (see related topic below).', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8627, 'If you have added metadata fields, click <em>Edit</em>. Under <em>Field mapping</em>, select the fields you added for each piece of metadata information.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8628, 'You can now use this media type by adding a Media reference field to any content entity sub-type. See related topic below.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8629, 'Migrating, updating, and upgrading', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8630, 'What are updating, upgrading, and migrating?', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8631, '<em>Updating</em> is the process of changing from one minor version of the software to a newer version, such as from version 8.3.4 to 8.3.5, or 8.3.5 to 8.4.0. Starting with version 8.x, you can also update to major versions 9, 10, and beyond if your add-on modules, themes, and install profiles are compatible. <em>Upgrading</em> is the process of changing from an older major version of the software to a newer version, such as from version 7 to 8. <em>Migrating</em> is the process of importing data into a site.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8632, 'To upgrade a site from Drupal 6 or 7 to Drupal 8 or later, keeping the content and configuration the same, you will install the new version of the software and add-on modules and themes in a new site, and then migrate the content and other data from your old site into the new site.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8633, 'Overview of Migrating', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8634, 'Provides the underlying API for migrating data.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8635, '<a href="https://www.drupal.org/docs/upgrading-drupal">Upgrading Drupal</a>', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8636, 'Migrating data for an upgrade using the user interface', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8637, 'Read the introduction and follow the <em>Preparation steps</em> on the page. Then click <em>Continue</em>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8638, 'Select the Drupal version of the source site. Also enter the database credentials and public and private files directories (private file directory is not available when migrating from Drupal 6). Click <em>Review upgrade</em>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8639, 'If the next page you see contains a message about conflicting content, that means that the site where you are running the upgrade is not empty. If you continue, you will lose the data in the site. If that is acceptable, click the button to continue; if not, start these steps over in a new, clean Drupal site.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8640, 'On the <em>What will be upgraded?</em> page, review the list of modules whose data will not be upgraded. If that list is not empty and you want to migrate the data from those modules, you will need to download contributed modules and/or install core or contributed modules, and start these steps over.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8641, 'When the list of modules that will and will not be upgraded meets your expectations, click <em>Perform upgrade</em> and wait for the upgrade to complete. You will see a message about the number of upgrade tasks that were successful or failed, and you can review the upgrade message log by clicking the link on the results page.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8642, '<a href="https://www.drupal.org/docs/upgrading-drupal/upgrading-from-drupal-6-or-7-to-drupal-8-and-newer">Upgrading from Drupal 6 or 7 to Drupal 8 (and newer)</a>', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8643, 'Configuring a responsive image style', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8644, 'Click <em>Add responsive image style</em>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8645, 'Enter a descriptive <em>Label</em> for your style.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8646, 'Select a <em>Breakpoint group</em> from the groups defined by your installed themes and modules.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8647, 'On the next page, locate the fieldsets for the breakpoints provided by the selected <em>Breakpoint group</em>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8648, 'For each breakpoint that you want to use, expand the corresponding fieldset. Select the <em>Select a single image style.</em> radio button under <em>Type</em> for the breakpoint, and select the <em>Image style</em> to use for images when that breakpoint is in effect. Repeat this step for the rest of the breakpoints you want to use.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8649, 'Click <em>Save</em>', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8650, 'You can now use this responsive image style to format a field containing an image, in your layouts or traditional field displays. See related topics below for more information.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8651, 'Entity create', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8652, 'Human name of the parent node type.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8653, 'Machine name of the parent node type.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8616, 'Under <em>Effect</em>, choose an effect to apply and click <em>Add</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8618, 'Repeat the previous two steps until all of the effects have been added.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8619, 'Drag to change the order of the effects. Then click <em>Save</em> to save the new order.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8620, 'The image style can now be used to format a field containing an image in your layouts or traditional field displays. It can also be used as part of a responsive image style. See related topics below for more information.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8610, 'The core Media module provides a Media reference field to add media to content entities. The core File and Image modules also provide reference fields. It is recommended to use the Media reference field because it is more versatile.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8611, 'The core Media Library module provides the media library and the Media library field widget. With this module installed, the Media library field widget becomes the default widget for editing Media reference fields.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8612, 'The core Image module provides a user interface for defining image styles. The core Responsive Image module provides responsive image styles. Using the core Breakpoint module, and a breakpoint-enabled theme, these responsive styles can serve images sized for the browser.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8613, '<a href="https://www.drupal.org/docs/8/core/modules/media">Media module</a>', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8656, 'Who can change workflow states?', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8657, 'Click <em>Edit</em> to edit the entity.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8658, 'At the bottom of the page, select the new workflow state under <em>Change to:</em> and click <em>Save</em>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8659, 'Who can configure a workflow?', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8660, 'Make a plan for the new workflow:', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8661, 'Decide which workflow states you need; for example, <em>Concept</em>, <em>Review</em>, and <em>Final</em>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8662, 'Decide on the settings for each state:', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8663, '<em>Label</em>: the state name', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8664, '<em>Published</em>: if checked, when content reaches this state it will be made visible on the site (to users with permission).', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8665, '<em>Default revision</em>: if checked, when content reaches this state it will become the default revision of the content; published content is automatically the default revision.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8666, 'Decide which state content should be created in.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8667, 'Decide on the list of allowed transitions between states. For example, you might want a transition between <em>Concept</em> and <em>Review</em>. Each transition has a label; for example, the Concept to Review transition might be labeled "Review concept".', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8668, 'Click <em>Add workflow</em>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8669, 'Enter a name in the <em>Label</em> field, select <em>Content moderation</em> from the <em>Workflow type</em> field, and click <em>Save</em>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8670, 'Verify that the <em>States</em> list matches your planned states. You can add missing states by clicking <em>Add a new state</em>. You can edit or delete states by clicking <em>Edit</em> or <em>Delete</em> under <em>Operations</em> (if the <em>Delete</em> option is not available, you will first need to delete any <em>Transitions</em> to or from this state).', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8671, 'Verify that the <em>Transitions</em> list matches your plan. You can add missing transitions by clicking <em>Add a new transition</em>. You can edit or delete transitions by clicking <em>Edit</em> or <em>Delete</em> under <em>Operations</em>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8672, 'Check the entity subtypes that you want to apply the workflow to. For example, you might choose to apply your workflow to the <em>Page</em> content type, but not to <em>Article</em>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8673, 'Under <em>Workflow settings</em>, select the <em>Default moderation state</em> for new content.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8674, 'Click <em>Save</em> to save your workflow.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8675, 'Optionally (recommended), create a view for your custom workflow, to provide a page for content editors to see what content needs to be moderated. You can do this if the Views UI module is installed, by following the steps in the related <em>Creating a new view</em> topic listed below under <em>Related topics</em>. When creating the view, under <em>View settings</em> &gt; <em>Show</em>, select the revision data type you configured the workflow for, and be sure to display the <em>Workflow State</em> field in your view.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8676, 'Managing content moderation workflows', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8677, 'What is a content moderation workflow?', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8678, 'On some sites, new content and content revisions need to be <em>moderated</em>. That is, they need to pass through several <em>states</em> before becoming visible to site visitors. The collection of states and the definition of the transitions between states is known as a <em>workflow</em>. For example, new content might start out in a <em>Draft</em> state, and then might need to pass through several <em>Review</em> states before it becomes <em>Published</em> on the live site.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8679, 'Overview of content moderation workflows', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8680, 'The core Content Moderation module allows you to expand on core software''s "unpublished" and "published" states for content. It allows you to have a published version that is live, but have a separate working copy that is undergoing review before it is published. This is achieved by using workflows to apply different states and transitions to entities as needed.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8681, 'The core Workflows module allows you to manage workflows with states and transitions.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8682, 'See the related topics listed below for specific tasks and background information.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8683, 'On-line documentation about Content Moderation', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8684, 'If %identifier is a valid account, an email will be sent with instructions to reset your password.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8685, '@language translation was not added. To add a translation, you must modify the configuration.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8686, 'No page is specified', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8691, 'There are no @entity_type_plural matching "%value".', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8692, 'Many @entity_type_plural are called %value. Specify the one you want by appending the id in parentheses, like "@value (@id)".', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8693, 'Multiple @entity_type_plural match this reference; "%multiple". Specify the one you want by appending the id in parentheses, like "@value (@id)".', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8695, 'Failed to connect to the server. The server reports the following message: <p class="error">@message</p> For more help adding or updating code on your server, see the <a href=":handbook_url">handbook</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8696, 'HTML tables can be created with table headers and caption/summary elements.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8697, 'Alt text is required by default on images added through CKEditor (note that this can be overridden).', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8698, 'Semantic HTML5 figure/figcaption are available to add captions to images.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8699, 'This log is not persistent', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8700, 'The Database Logging module logs may be cleared by administrators and automated cron tasks, so they should not be used for <a href=":audit_trail_wiki">forensic logging</a>. For forensic purposes, use the Syslog module.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8701, 'Your upload has been renamed to %filename.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8703, 'The list of allowed extensions is not valid. Allowed characters are a-z, 0-9, ''.'', and ''_''. The first and last characters cannot be ''.'' or ''_'', and these two characters cannot appear next to each other. Separate extensions with a comma or space.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8702, 'Separate extensions with a comma or space. Each extension can contain alphanumeric characters, ''.'', and ''_'', and should start and end with an alphanumeric character.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8687, 'Provide markup for the area using any available text format.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8694, 'The module ''@module_name'' is providing the database driver ''@driver_name''.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8688, 'Provide markup for the area with minimal filtering.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8690, 'You may include the following allowed HTML tags with these "Replacement patterns": <code>@tags</code>', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8704, 'Add %txt_extension to the list of allowed extensions to securely upload files with a %extension extension. The %txt_extension extension will then be added automatically.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8707, 'Translating configuration', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8708, 'For configuration entities, find the specific entity that you want to translate on the next page, and click <em>Translate</em> under <em>Operations</em>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8709, 'Enter translations for the translatable text fields for the configuration item, and save.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8710, 'Configuring content language settings and translation', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8711, 'Under <em>Custom language settings</em>, find the content entity types that should have customized language settings on your site. Check the box next to each one. A section will appear below the list with settings for that entity type.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8712, 'For each entity type you checked, in the settings section below check the boxes for each entity sub-type that should be <em>Translatable</em> on your site. If the entity type does not have sub-types, there is just one check box for the entity type as a whole.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8713, 'For each entity type or subtype, select the <em>Default language</em>. Also, if you want to have languages other than the default available when you create content, check <em>Show language selector on create and edit pages</em>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8714, 'For each <em>Translatable</em> type or sub-type, look through the list of fields for the type or sub-type, and verify that only the fields that should be translatable are checked. For example, you would probably want to translate a <em>Title</em> field, but you might not want to translate a <em>Start date</em> field.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8715, 'Click <em>Save configuration</em> when all of your changes are complete.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8750, 'Checking interface translation status', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8751, 'Check the current status of interface translations, and see if there are any updates available.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8752, 'Look at the <em>Interface translation</em> column in the language table, to find the percentage of user interface text that has been translated for each language.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8753, 'Optionally, click <em>Check manually</em> to update the report.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8754, 'View the report to find out if any languages have translation updates that you can download.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8721, 'Adding a language', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8722, 'Add a language to your site.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8723, 'Click <em>Add language</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8724, 'If your language is in the <em>Language name</em> list, select it and click <em>Add language</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8705, 'In the <em>Manage</em> administrative menu, navigate to <em>Structure</em> &gt; @layout_link.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8706, 'Configure the block and click <em>Save block</em>; see @configure_topic for configuration details.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8745, 'Translating user interface text', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8746, 'Translate user interface text strings from English into a non-English language that is configured on your site.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8747, 'Using the filters, search for a string or set of strings that you want to translate; make sure to select the correct <em>Translation language</em> if you have more than one non-English language on your site.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8748, 'Enter new translations and click <em>Save translations</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8749, 'Repeat these steps until all of the desired user interface text is translated for all languages on your site.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8716, 'Working with languages and translations', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8717, 'What text can be translated in your site?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8718, 'There are three types of text that can be translated:', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8719, 'User interface text that is provided by the core software, your install profile, themes, and modules is provided in English, but can be translated into other languages. You can also download translations that community-members have provided.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8720, 'Working with languages overview', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8726, 'Configuring language detection and selection', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8727, 'Configure the methods used to decide which language will be used to display text on your site.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8728, 'What is a language detection method?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8730, 'What language detection methods are available?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8731, 'The available detection methods depend on what modules you have installed. Some of the most commonly-used language detection methods are:', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8732, 'Use the language from the URL, which can either be in a path prefix like <em>example.com/fr/page_path</em> for French (fr) language, or in a domain like <em>fr.example.com/page_path</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8733, 'For logged in users, use the language they have set in their profiles.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8734, 'Use the language preferences from the user''s browser.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8735, 'Use the language most recently selected from a <em>Language switcher</em> block.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8736, 'Use the language from a session parameter or a request parameter; for example, adding <em>?language=fr</em> to the end of the URL.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8737, 'Check the boxes to enable the desired language detection methods, and uncheck boxes for the methods you do not want to use.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8738, 'Drag the methods to change their order, if desired.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8739, 'Click <em>Save settings</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8740, 'Click <em>Configure</em> on each enabled detection method and verify that its configuration is correct (or update the configuration if not).', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8741, 'Importing a translation file', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8742, 'Import a file (.po extension) containing translations for user interface text.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8743, 'Browse to find the <em>Translation file</em> you want to import. Select the language and check the desired import options.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8744, 'Click <em>Import</em> and wait for your file to be imported.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (10412, 'America/Edmonton', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8755, 'You can use the <em>Migration</em> group of modules to perform the migration step of upgrading from Drupal 6 or 7 to Drupal 8 or later, as well as other migrations. These modules also provide APIs that can be used by programmers to write custom software for migrations. Here are the functions of the core migration modules:', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8757, 'Help search is not fully indexed. Some results may be missing or incorrect.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8758, 'If an upgrade has been performed on this site, you will be informed.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8759, 'You need to enter the database credentials of the Drupal site that you want to upgrade. You can also include its files directory in the upgrade. For example local files, /var/www/docroot, or remote files http://www.example.com.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8760, 'If there is existing content on the site that may be overwritten by this upgrade, you will be informed.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8761, 'Finally, a message is displayed about the number of upgrade tasks that were successful or failed.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8762, 'To import private files from your current Drupal site, enter a local file directory containing your site (e.g. /var/www/docroot). Leave blank to use the same value as Public files directory.', '', 'none');
