INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8783, 'See <a href=":url">Troubleshooting the advisory feed</a> for possible causes and resolutions.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8784, 'Check <a href=":url">your local system logs</a> for additional error messages.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8785, 'Critical security advisories', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8786, 'The System module displays highly critical and time-sensitive security announcements to site administrators. Some security announcements will be displayed until a critical security update is installed. Announcements that are not associated with a specific release will appear for a fixed period of time. <a href=":handbook">More information on critical security advisories</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8787, 'Only the most highly critical security announcements will be shown. <a href=":advisories-list">View all security announcements</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8788, '(<a href=":system-help">What are critical security announcements?</a>)', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8789, 'Critical security announcements', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8790, 'Security advisory settings', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8791, 'Display critical security advisories', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8792, 'How often to check for security advisories, in hours', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8793, 'The security advisory JSON feed from Drupal.org could not be decoded.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8795, 'The label of the link.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8796, 'Pre-header', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8797, 'Banner Top', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8798, 'Hero (full width)', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8799, 'Move content from %from state to %to state.Move content from %from states to %to state.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8800, 'Your server does not support updating modules and themes from this interface. Instead, update modules and themes by uploading the new versions directly to the server, as documented in <a href=":doc_url">Extending Drupal</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8801, 'Your server does not support adding modules and themes from this interface. Instead, add modules and themes by uploading them directly to the server, as documented in <a href=":doc_url">Extending Drupal</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8802, 'Updating modules and themes requires <strong>@backends access</strong> to your server. See <a href=":doc_url">Extending Drupal</a> for other update methods.Updating modules and themes requires access to your server via one of the following methods: <strong>@backends</strong>. See <a href=":doc_url">Extending Drupal</a> for other update methods.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8803, 'Adding modules and themes requires <strong>@backends access</strong> to your server. See <a href=":doc_url">Extending Drupal</a> for other methods.Adding modules and themes requires access to your server via one of the following methods: <strong>@backends</strong>. See <a href=":doc_url">Extending Drupal</a> for other methods.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8806, 'Who can configure comments?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8808, 'Follow the steps in the related <em>Adding a field to an entity sub-type</em> topic to add a field of type <em>Comments</em> to the desired entity type or sub-type.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8756, '[user:account-name]: The user''s account name.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8763, 'Add <a href=":modules">contributed modules</a> to extend your site''s functionality.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8794, '[user:display-name]
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8767, 'View user email addresses', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9024, '@bundle_type is not @bundles or @last', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8812, '<em>Comments per page</em>: the maximum number of comments displayed on one page (a pager will be added if you exceed this limit).', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8813, '<em>Anonymous commenting</em>: whether or not anonymous commenters are allowed or required to leave contact information with their comments (only applies if anonymous users have permission to post comments).', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8814, '<em>Preview comments</em>: whether previewing comments before submission is <em>Required</em>, <em>Optional</em>, or <em>Disabled</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8815, '<em>Default value</em>: each individual entity has its own comment settings, but here you can set defaults for the comment settings for this entity type or subtype. The comment settings values are:', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8816, '<em>Open</em>: comments are allowed.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8817, '<em>Closed</em>: past comments remain visible, but no new comments are allowed.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8818, '<em>Hidden</em>: past comments are hidden, and no new comments are allowed.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8819, 'Online documentation for content comment settings', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8846, 'Managing comments', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8847, 'What is a comment?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8848, 'What is a comment type?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8850, 'What is moderation?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8851, '<em>Moderation</em> is a workflow where comments posted by some users on your site are verified before being published, to prevent spam and other bad behavior. The core software provides basic moderation functionality: you can configure permissions so that new comments posted by some user roles start as unpublished until a user with a different role reviews and publishes them. Contributed modules provide additional moderation and spam-reduction functionality, such as requiring untrusted users pass a CAPTCHA test before submitting comments and letting community members flag comments as possible spam. See @users_overview_topic for more about users, permissions, and roles.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8852, 'Overview of managing comments', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8853, 'The core Comment module provides the following functionality:', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8854, 'Posting comments', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8855, 'Creating comment types; the core Field UI module allows you to attach fields to comment types and attach comment reference fields to other entities so that people can comment on them.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8856, 'Configuring commenting', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8857, 'Moderating comments as discussed above', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8821, 'Create a new comment type. See @comment_overview_topic for information about comments and comment types.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8822, 'Who can create a comment type?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8823, 'Users with the <em>@comment_permissions_link</em> permission (typically administrators) can create comment types.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8824, 'In the <em>Manage</em> administrative menu, navigate to <em>Structure</em> &gt; <em>@comment_types_link</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8825, 'Click <em>Add comment type</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8826, 'In the <em>Label</em> field, enter a name for the comment type, which is how it will be listed in the administrative interface.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8827, 'In the <em>Target entity type</em> field, select the entity type to be commented on. See @content_structure_topic for more about content entities and fields.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8828, 'Click <em>Save</em>. The comment type will be created.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8829, 'Optionally, if you have the core Field UI module installed you can follow the steps in the related topics to add fields to the new comment type, set up the editing form, and configure the display.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8837, 'Moderating comments', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8838, 'Decide which comments are shown on the website.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8839, 'Who can moderate comments?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8840, 'Users with the <em>@comment_permissions_link</em> permission (typically administrators) can moderate comments. You will also need the <em>Access the Content Overview page</em> permission from the Node module (if it is installed) to navigate to the comment management page.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8841, 'In the <em>Manage</em> administrative menu, navigate to <em>Content</em> &gt; <em>@comment_published_link</em>. A list of all comments is shown.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8842, 'To unpublish comments, select one or more comments by checking the boxes on the left side (right side in right-to-left languages). Then select <em>Unpublish comment</em> from the <em>Action</em> select list and click <em>Apply to selected items</em>. If you select the <em>Delete comment</em> action, you can instead delete the unwanted  comments.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8843, 'To change the content of a comment click <em>Edit</em> from the dropdown button for a particular comment.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8844, 'To publish comments that are not yet visible on the website, navigate to the <em>@comment_unpublished_link</em> tab. Select one or more comments by checking the boxes on the left side (right side in right-to-left languages). Then select <em>Publish comment</em> from the <em>Action</em> select list and click <em>Apply to selected items</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8845, 'Online documentation for moderating comments', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8858, 'What is quick editing?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8830, 'Disabling comments', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8831, 'Turn off commenting for a particular entity (see @content_structure_topic for more about content entities and fields). Note that if you want to turn off commenting for all entities of an entity type or subtype, you will need to edit the field settings for the comment field; see @comment_config_topic for more about configuring the comment field.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8832, 'Who can disable comments?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8833, 'You will need the <em>@comment_permissions_link</em> permission in order to disable commenting. You will also need permission to edit the entity that the comments are on.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8834, 'Find the entity you want to disable comments for, and edit it. For example, to turn off comments on a content item, you could find it by navigating in the <em>Manage</em> administrative menu to <em>Content</em>, filtering to find the content item, and clicking <em>Edit</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8835, 'Under <em>Comment settings</em>, select the desired comment setting:', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8836, 'Save the entity.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8880, 'Who can create content?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8882, 'In the <em>Manage</em> administrative menu, navigate to <em>@content_link</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8883, 'Click <em>Add content</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8884, 'If there is more than one content type defined on your site that you have permission to create, click the name of the type of content you want to create.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8885, 'On the content edit form, enter the <em>Title</em> of your content, which will show as the page title when the content item is displayed on a page, and also as the label for the content item in administration screens.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8886, 'Fill in the other fields shown on the edit form for this specific content type.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8887, 'Leave the <em>Published</em> field checked to publish the content immediately, or uncheck it to make it unpublished. Unpublished content is generally not shown to non-administrative site users.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8888, 'Optionally, click <em>Preview</em> to preview the content.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8889, 'Click <em>Save</em>. You will see the content displayed on a page.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8890, 'Creating a content type', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8891, 'Create a new content type. See @content_overview_topic for more about content types.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8892, 'Who can create a content type?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8893, 'Users with the <em>@content_permissions_link</em> permission (typically administrators) can create new content types.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8894, 'In the <em>Manage</em> administrative menu, navigate to <em>Structure</em> &gt; <em>@content_types_link</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8895, 'Click <em>Add content type.</em>', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8896, 'In the <em>Name</em> field, enter a name for the content type, which is how it will be listed in the administrative interface.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8897, 'Optionally, enter a <em>Description</em> for the content type. You may also want to adjust some of the settings in the vertical tabs section of the edit page.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8898, 'Click <em>Save and manage fields</em>. Your content type will be created, and assuming you have the core Field UI module installed, you will be taken to the <em>Manage fields</em> page for the content type. (If you do not have the core Field UI module installed, the button will say <em>Save</em> instead.)', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8899, 'If you have the core Field UI module installed, follow the steps in the related topics to add fields to the new content type, set up the editing form, and configure the display.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8865, 'What administrative interface components are available?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8866, 'Accessibility features, to enable all users to perform administrative tasks. See @accessibility_topic for more information.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8867, 'What are the sections of the administrative menu?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8868, 'The administrative menu, which you can navigate by visiting <em>@admin_link</em> on your site or by using an administrative toolbar, has the following sections (some may not be available, depending on which modules are currently installed on your site, and your permissions):', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8869, '<strong>Content:</strong> Find, manage, and create new pages; manage comments and files.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8870, '<strong>Structure:</strong> Place and edit blocks, set up content types and fields, configure menus, administer taxonomy, and configure some contributed modules.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8871, '<strong>Appearance:</strong> Switch between themes, install themes, and update existing themes.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8872, '<strong>Extend:</strong> Update, install, and uninstall modules.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8873, '<strong>Configuration:</strong> Configure the settings for various site functionality, including some contributed modules.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8874, '<strong>People:</strong> Manage user accounts and permissions.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8875, '<strong>Reports:</strong> Display information about site security, necessary updates, and site activity.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8876, '<strong>Help:</strong> Get help on using the administrative interface.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8877, 'Install the core modules mentioned above to use the corresponding aspect of the administrative interface. See the related topics listed below for more details on some aspects of the administrative interface.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8900, 'Editing a content item', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8901, 'Find a content item and edit it, or update a group of content items in bulk. See @node_overview_topic for more about content types and content items.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8902, 'Who can find and edit content?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8949, 'Users with the <em>@taxonomy_permissions_link</em> permission can configure a vocabulary. To add a field in the administrative interface, the core Field UI module must be installed, and you will also need the <em>Administer fields</em> permission for the entity you are adding the field to.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8950, 'In the <em>Manage</em> administrative menu, navigate to <em>Structure</em> &gt; <em>@taxonomy_admin_link</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8951, 'Click <em>Add vocabulary</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8859, 'Click the contextual links <em>Edit</em> button on the toolbar (in most themes, it looks like a pencil). Contextual <em>Edit</em> links with the same icon will appear all over your page.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8860, 'Find the contextual link for the part of the page you want to edit. For example, if you want to edit the settings for a block, the link should be in the top-right corner of the block, or top-left for right-to-left languages.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8861, 'Make your edits and submit the form.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8862, 'The core administrative interface has built-in compliance with many accessibility standards so that most pages are accessible to most users in their default state. However, certain pages become more accessible to some users through the use of a non-default or improved interface. These interfaces include:', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8863, 'Enabling inline form errors', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8864, 'Errors that occur when you submit a form, such as not filling in a required field, are sometimes difficult for users to understand and locate. In order to make these errors easier to find, the best practice is to put a summary of the errors at the top of the form page. To make them easier to understand, the best practice is to display error messages with the form fields they are related to. Both of these practices are implemented by the core Inline Form Errors module.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9025, '@bundle_type is not @bundle', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8935, 'What is a URL?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8937, 'What is a path?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8938, 'A path is the unique, last part of the URL for a specific function or piece of content. For example, for a page whose full URL is <em>https://example.com/node/7</em>, the path is <em>node/7</em>. Here are some examples of paths you might find in your site:', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8939, 'node/7: Path to a particular content item.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8940, 'taxonomy/term/6: Path to a taxonomy term page.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8941, 'user/3: Path to a user profile page.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8942, 'What is an alias?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8943, 'The core software allows you to provide more understandable URLs for pages on your site, which are called <em>aliases</em>. For example, if you have an "About Us" page with the path <em>node/7</em>, you can set up an alias of <em>about</em> so that your visitors will see it as <em>https://www.example.com/about</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8944, 'Overview of configuring paths, aliases, and URLs', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8945, 'The core Path module provides the URL aliasing functionality. The contributed <a href="https://www.drupal.org/project/pathauto">Pathauto</a> module allows you to configure automatically-generated URL aliases for content items and other pages. See the related topics listed below for specific tasks.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8913, 'What is a content item?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8914, 'A <em>content item</em> is a type of content entity for page-level content, which can have fields that store text, HTML markup, images, attached files, and other data. See @content_structure_topic for more about content entities and fields.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8915, 'What is a content type?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8916, 'Content items are divided into <em>content types</em>, which are the entity sub-types for the content item entity type; each content type has its own fields and display settings. For example, you might set up content types for pages, articles, recipes, events, and blog entries on your web site.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8917, 'Overview of managing content', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8926, 'Editing a URL alias', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8927, 'Change an existing URL alias, to correct the path or the alias value. See @path_overview_topic for more about aliases.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8928, 'Who can manage URL aliases?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8929, 'Users with the <em>@path_permissions_link</em> permission can edit aliases.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8930, 'In the <em>Manage</em> administration menu, navigate to <em>Configuration</em> &gt; <em>Search and metadata</em> &gt; <em>@path_aliases_link</em>. A list of all the site''s aliases will appear.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8931, 'Click <em>Edit</em> in the dropdown button for the alias that you would like to change.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8932, 'Make the required changes and click <em>Save</em>. You will be returned to the URL alias list page.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8933, 'Note that you can also add new aliases from this page, for any path on your site.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8919, 'Creating a URL alias for a content item', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8920, 'Give a content item page a human- or SEO-friendly URL alias; you can follow similar steps to create an alias for a taxonomy term page. See @overview_topic for more about aliases.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8921, 'Who can create URL aliases?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8922, 'Users with the <em>@path_permissions_link</em> permission can create aliases. To follow the steps in this topic, you will also need permission to edit the content item.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8923, 'Locate and open the content edit form for the content item, or create a new content item (see related topics on creating and editing content).', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8924, 'Under <em>URL alias</em> on the edit form, enter the desired alias (for example, "/about-us"). Make sure the alias starts with a "/" character.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8925, 'Verify that the page can be visited with the new alias, for example <em>https://example.com/about-us</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8903, 'Users with the <em>@content_permissions_link</em> permission can use the <em>Content</em> page to find content. Each content type has its own edit permissions. For example, to edit content of type Article, a user would need the <em>Article: Edit own content</em> permission to edit an article they created, or the <em>Article: Edit any content</em> permission to edit an article someone else created. In addition, users with the <em>Bypass content access control</em> or <em>Administer content</em> permission can edit content items of all types. Some contributed modules change the permission structure for editing content.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8904, 'Optionally, use filters to reduce the list of content items shown:', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8905, '<em>Title</em>: key word(s) from the title', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8906, '<em>Content type</em>', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8907, '<em>Published status</em>', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8908, '<em>Language</em>', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8909, 'If you enter or select filter values, click <em>Filter</em> to apply the filters.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8910, 'Optionally, sort the list by clicking a column header. Click again to reverse the order.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8911, 'To edit the title or other field values for one content item, click <em>Edit</em> in the row of the content item. Update the values and click <em>Save</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8912, 'A few types of edits can be done in bulk to multiple content items. For example, to publish several unpublished content items, check the boxes in the left column (right column in right-to-left languages) to select the desired content items. For <em>Action</em>, select the <em>Publish content</em> action. Click <em>Apply to selected items</em> to make the change. The other actions under <em>Action</em> work in a similar manner.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8946, 'Configuring taxonomy', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8947, 'Create a taxonomy vocabulary and add a reference field for that vocabulary to a content entity. See @taxonomy_overview_topic for information about taxonomy and @content_structure_topic for more on content entities.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8948, 'Who can configure a taxonomy vocabulary?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8952, 'In the <em>Name</em> field, enter a name for the vocabulary (for example "Ingredients"), which is how it will be shown in the administrative interface. Optionally, add a description.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8981, 'Translate your site configuration to another language. See @language_add_topic if you need to add a new language.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8982, 'Find either the configuration entity type or the simple configuration item that you want to translate in the <em>Label</em> column of the list. Click <em>List</em> under <em>Operations</em> for a configuration entity, or <em>Translate</em> for simple configuration. (See @config_overview_topic to learn more about types of configuration and configuration entities.)', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8983, 'The contact form will always have <em>Subject</em> and <em>Message</em> fields. If you want to add more fields, follow the steps in @adding_fields_topic.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8984, 'Change the workflow state of a particular entity. See @workflows_overview_topic for an overview of workflows, and @content_structure_topic for an overview of content entities.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8985, 'Create or edit a workflow with various workflow states (for example <em>Concept</em>, <em>Archived</em>, etc.) for moderating content. See @workflows_overview_topic for more information on workflows.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8986, 'Decide which roles should have permissions to make each transition; see @user_overview_topic for an overview of roles and permissions.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8987, 'Decide which <em>entity types</em> and subtypes the workflow should apply to. Only entity types that support revisions are possible to define workflows for. See @content_structure_topic for more information on content entities and fields.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9021, 'Remote oEmbed providers database returned invalid or empty list. Using previously stored data. This may contain out of date information.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9022, 'Block type settings', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8978, 'Export a single configuration item to a file. See @config_overview_topic for more information about configuration.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8969, 'Adding a bulk operations form to a view', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8970, 'Who can edit views?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8971, 'The core Views UI module will need to be installed and you will need <em>@views_permissions</em> permission in order to edit a view.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8972, 'In the <em>Manage</em> administrative menu, navigate to <em>Structure</em> &gt; <em>@views</em>. A list of all views is shown.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8974, 'Check the action(s) you want to make available in the <em>Selected actions</em> list and click <em>Apply (all displays)</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8975, 'Verify that the <em>Access</em> settings for the view are at least as restrictive as the permissions necessary to perform the bulk operations. People with permission to see the view, but who don''t have permission to do the bulk operations, will experience problems.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8976, 'Click <em>Save</em>. The action(s) will be available as bulk operations in the view.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8979, 'Import the complete configuration of your site from an archive file, such as one that was previously exported (see @export_full_topic). See @config_overview_topic for more information about configuration.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8967, '<em>Page settings</em>, <em>Block settings</em>, etc.: settings specific to the display type, such as the URL for a page display. Most display types support an <em>Access</em> setting, where you can choose a Permission or Role that a user must have in order to see the view.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8968, 'What are bulk operations?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8957, 'Managing taxonomy', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8953, 'Click <em>Save</em>. Your vocabulary will be created and you will see the page that lists all the terms in this vocabulary.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8954, 'Optionally, click <em>Add term</em> to add a term to the new vocabulary. In the <em>Name</em> field, enter the term name (for example "Butter"). Click <em>Save</em>. You will receive a confirmation about the term you created. You may optionally continue to add more terms.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8955, 'If you have the Field UI module installed, follow the instructions on the related <em>Adding a reference field to an entity sub-type</em> topic to add a taxonomy reference field to the entity type of your choice. The settings page will allow you to choose the <em>Vocabulary</em> that you created as the vocabulary to reference.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8956, 'You may also want to configure the display and form display of the new field (see related topics).', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8958, 'What is taxonomy?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8960, 'An individual vocabulary can organize its terms in a hierarchy, or it could be flat. For example, blog tags normally have a flat structure, while a recipe ingredients vocabulary could be hierarchical (for example, tomatoes could be a sub-term of vegetables, and under tomatoes, you could have green and red tomatoes).', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8961, 'Taxonomy terms are normally attached as reference fields to other content entities, which is how you can use them to classify content. When you set up a taxonomy reference field, you can let users enter terms in two ways:', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8962, 'New terms can be created right on the content editing form.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8963, 'Fixed list of terms', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8964, 'The list of terms is curated and managed outside the content editing form, and users can only select from the existing list when editing content.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8965, 'Overview of managing taxonomy', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8966, 'The core Taxonomy module allows you to create and edit taxonomy vocabularies and taxonomy terms. The core Field UI module provides a user interface for adding fields to entities, including the taxonomy reference field, and configuring field editing and display. See the related topics listed below for specific tasks.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8980, 'Import a single configuration item in YAML format, such as one that was previously exported (see @export_single_topic). See @config_overview_topic for more information about configuration.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8988, 'Configure language and translation settings for one or more content entity types (see @content_structure_topic for an overview of content entities). To do this, you must have at least two languages configured. Afterwards, you will have a <em>Translate</em> operation available for your content entities, either as a tab or link when you are viewing or editing content, or on content administration pages.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9005, 'Configure an entity sub-type to have its fields displayed using a layout (see @content_structure_topic for more on entities and fields).', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9006, 'A layout consists of one or more <em>sections</em>. Each section can have from one to four <em>columns</em>. You can place blocks, including special blocks for the fields on the entity sub-type, in each column of each section (see @block_overview_topic for more on blocks).', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9007, 'Add a new media type that can be referenced in Media reference fields; media types are a content entity type. See @media_topic for an overview of media items and media types, and @content_structure_topic for more information on content entities and fields.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9008, 'Migrate data into a new, empty site, as part of an upgrade from an older version of Drupal. See @migrate_overview_topic for an overview of migrating and upgrading.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9009, 'Configure a responsive image style, which can be used to display images at different sizes on different devices. See @media_topic for an overview of responsive image styles, and @breakpoint_overview_topic for an overview of breakpoints.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9010, 'Select a <em>Fallback image style</em> to use when none of the other styles apply. See @image_style_topic if you need to add a new style.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9018, 'The core software allows you to configure workflows in which each transition has an associated permission that can be granted to a particular role. See @configuring_workflows_topic for more information.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9019, 'Users with sufficient permissions can change the workflow state of a particular entity. See @changing_states_topic for more information.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9020, 'Remote oEmbed providers could not be retrieved due to error: @error. Using previously stored data. This may contain out of date information.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9023, 'Navigation logo', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9011, 'Follow the steps in @search_index_topic to make sure that the search index is updated.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9004, 'Add a new image style, which can be used to process and display images. See @media_topic for an overview of image styles.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9015, 'Uninstall a module. Your site should be in <em>maintenance mode</em> when you uninstall modules. See @maintenance_topic for details.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9013, 'Follow the steps in @cron_topic to make sure a cron task has been configured.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8994, 'Configure a text format so that when a user is editing text and selects this text format, a text editor installed on your site is shown. Configure the text editor, such as choosing which buttons and functions are available. See @filter_overview_topic for more about text formats.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8995, 'Follow the steps on @filter_overview_topic to add a new text format or configure an existing text format; when you reach the step about text editors, return to this topic.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8996, 'Return to @filter_overview_topic to complete the text format configuration, and be sure to save the text format.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8991, 'Content (blocks, content items, etc.) can be written in English or another language, and can be translated into additional languages. See @content_structure_topic to learn more about content.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8992, 'Many configuration items also include text that can be translated. Default configuration provided by your site''s software is provided in English; you can also download community-provided translations. See @config_overview_topic to learn more about configuration.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8997, 'Add a field to an entity sub-type; see @content_structure_topic for an overview of entity types and sub-types, as well as an overview of field types.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8998, 'In <em>Add a new field</em>, select the type of field you want to add; see @content_structure_topic for an overview of field types.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9016, 'Follow the steps in @view_edit_topic to edit the other settings for the display.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8993, 'Exposes <em>entities</em> to other applications using a fully compliant implementation of the <a href="https://jsonapi.org">JSON:API Specification</a>. See @content_structure_topic for more information on content entities and fields.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8989, 'A <em>layout</em> is a template that defines where blocks and other pieces of content should be displayed. The core Layout Discovery module allows modules and themes to register layouts, and the core Layout Builder module provides a visual interface for placing fields and blocks in layouts for entity sub-types and individual entity items (see @content_structure_topic for more on entities and fields).', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9002, 'Check the indexing status of the Help search page. If it is not fully indexed, see @cron_topic about how to run Cron until indexing is complete.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9003, 'In the future, you can click <em>Rebuild search index</em> on this page, or @cache_topic, in order to force help topic text to be reindexed for searching. This should be done whenever a module, theme, language, or string translation is updated.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9001, 'Add an entity reference field to an entity sub-type; see @content_structure_topic for more information on entities and reference fields.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8990, 'Core media items include audio, images, documents, and videos. You can add other media types, such as social media posts, through the use of contributed modules. Media items may be files located in your site''s file system, or remote items referenced by a URL. Media items are content entities, and they are divided into media types (which are entity sub-types); media types can have fields. See @content_structure_topic for more information on content entities and fields.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8999, 'Configure the <em>formatters</em> used to display the fields of an entity sub-type, their order in the display, and the formatter settings. See @content_structure_topic for background information.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9000, 'Configure the <em>widgets</em> used to edit the fields of an entity sub-type, their order on the form, and the widget settings. See @content_structure_topic for background information.', '', '11.3.2');
