INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9046, 'Automatic updating of Drupal core is not supported. See the <a href=":update-guide">Updating Drupal guide</a> for information on how to update Drupal core manually.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9047, 'Other permissions pages', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9048, 'The main Permissions page can be overwhelming, so each module that defines permissions has its own page for setting them. There are links to these pages on the <a href=":modules">Extend page</a>. When editing a content type, vocabulary, etc., there is also a Manage permissions tab for permissions related to that configuration.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9052, 'To log in to this site, your browser must accept cookies from the domain %domain.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9055, 'Sort field identifier', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9056, 'This will appear in the URL after the ?, as value of ''sort_by'' parameter, to identify this sort field. Cannot be blank. Only letters, digits and the dot (''.''), hyphen (''-''), underscore (''_''), and tilde (''~'') characters are allowed.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9057, 'This identifier is already used by %label sort handler.', '', 'none');
