INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9065, 'Code Block', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9066, 'The CKEditor 5 module provides a highly-accessible, highly-usable visual text editor and adds a toolbar to text fields. Users can use buttons to format content and to create semantically correct and valid HTML. The CKEditor module uses the framework provided by the <a href=":text_editor">Text Editor module</a>. It requires JavaScript to be enabled in the browser. For more information, see the <a href=":doc_url">online documentation for the CKEditor 5 module</a> and the <a href=":cke5_url">CKEditor 5 website</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9067, 'Enabling CKEditor 5 for individual text formats', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9068, 'When CKEditor 5 is chosen from the <em>Text editor</em> drop-down menu, its toolbar configuration is displayed. You can add and remove buttons from the <em>Active toolbar</em> by dragging and dropping them. Separators and rows can be added to organize the buttons.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9069, 'Filtering HTML content', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9070, 'Unlike other text editors, plugin configuration determines the tags and attributes allowed in text formats using CKEditor 5. If using the <em>Limit allowed HTML tags and correct faulty HTML</em> filter, this filter''s values will be automatically set based on enabled plugins and toolbar items.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9071, 'Developing CKEditor 5 plugins in Drupal', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9072, 'See the <a href=":dev_docs_url">online documentation</a> for detailed information on developing CKEditor 5 plugins for use in Drupal.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9073, 'The built in WYSIWYG editor (CKEditor 5) comes with a number of accessibility features. CKEditor 5 comes with built in <a href=":shortcuts">keyboard shortcuts</a>, which can be beneficial for both power users and keyboard only users.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9074, 'To support multilingual page content, CKEditor 5 can be configured to include a language button in the toolbar.', '', 'none');
