INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9085, 'These are the headings that will appear in the headings dropdown. If a heading is not chosen here, it does not necessarily mean the corresponding tag is disallowed in the text format.', '', 'none');
