INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9097, 'CKEditor 5 only works with HTML-based text formats. The "%filter_label" (%filter_plugin_id) filter implies this text format is not HTML anymore.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9098, 'CKEditor 5 needs at least the &lt;p&gt; and &lt;br&gt; tags to be allowed to be able to function. They are not allowed by the "%filter_label" (%filter_plugin_id) filter.', '', 'none');
