INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9159, 'Package Manager is a framework for updating Drupal core and installing contributed modules and themes via Composer. It has no user interface, but it provides an API for creating a temporary copy of the current site, making changes to the copy, and then syncing those changes back into the live site.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9160, 'Package Manager dispatches events before and after various operations, and external code can integrate with it by subscribing to those events. For more information, see <code>package_manager.api.php</code>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9161, 'Modules cannot be uninstalled while Package Manager is applying staged changes to the active code base.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9162, 'Post updating @extension', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9163, 'Press the down arrow key to activate', '', 'none');
