INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9169, 'The following @element_type(s) are already supported by available plugins and should not be added to the Source Editing "Manually editable HTML tags" field. Instead, enable the following plugins to support these @element_types: %overlapping_tags.', '', 'none');
