INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9189, 'Select the loading attribute for images. <a href=":link">Learn more about the loading attribute for images.</a>', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9190, 'Delays loading the image until that section of the page is visible in the browser. When in doubt, lazy loading is recommended.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9191, 'Force browsers to download an image as soon as possible. This is the browser default for legacy reasons. Only use this option when the image is always expected to render.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9193, 'Your PHP installation is too old. Drupal requires at least PHP %version. It is recommended to upgrade to PHP version %recommended or higher for the best ongoing support. See <a href="http://php.net/supported-versions.php">PHP''s version support documentation</a> and the <a href=":php_requirements">Drupal PHP requirements</a> page for more information.', '', 'none');
