INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9210, 'CKEditor 5 Media plugin in sync with filter settings', 'Validation', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9211, 'The CKEditor 5 "%cke5_media_plugin_label" plugin''s "%cke5_allow_view_mode_override_label" setting should be in sync with the "%filter_media_plugin_label" filter''s "%filter_media_allowed_view_modes_label" setting: when checked, two or more view modes must be allowed by the filter.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9256, 'Note that anonymous users with this permission are able to delete any content created by any anonymous user.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9257, 'The fallback image style is typically the smallest size image you expect to appear in this space. The fallback image should only appear on a site if an error occurs.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9174, 'Edit settings in place.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9175, 'The core Settings Tray module provides the ability to quickly edit settings inline. It requires the core Contextual Links module in order to expose the links that let you edit in place.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9176, 'Who can edit settings in place?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9178, 'Find and visit a page on your site that has the settings that you would like to edit.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9179, 'Click the link to open the contextual links menu, and click <em>Quick edit</em>. An editing form for the settings should appear on the page.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9181, 'Exposes entities and other resources to other applications using a <a href="https://en.wikipedia.org/wiki/Representational_state_transfer">REST</a> implementation. Data is exchanged using a serialization format such as JSON, and transferred using an authentication method such as HTTP Basic Authentication.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9172, 'The main way to change the overall appearance of your site is to switch the default theme. The core Layout Builder and Layout Discovery modules allow you to define layouts for your site''s content, and the core Breakpoint module helps themes change appearance for different-sized devices. See the related topics listed below for specific tasks.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9194, 'It is recommended to upgrade to PHP version %recommended or higher for the best ongoing support.  See <a href="http://php.net/supported-versions.php">PHP''s version support documentation</a> and the <a href=":php_requirements">Drupal PHP requirements</a> page for more information.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9164, 'Decorative image', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9192, 'Image loading: @attribute', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9166, 'Change image alternative text', '', '11.3.5');
