INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9214, 'Olivero Color Scheme Settings', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9215, 'These settings adjust the look and feel of the Olivero theme. Changing the color below will change the base hue, saturation, and lightness values the Olivero theme uses to determine its internal colors.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9216, 'Olivero Color Scheme', '', 'none');
