INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9220, 'Unable to uninstall the %module module because: @reason.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9221, 'Unable to install the %theme theme since it requires the %required_module module.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9222, 'If the <em>Source</em> button is available in the toolbar, users can click this button to disable the visual editor and edit the HTML source directly. After toggling back, the visual editor uses the HTML tags allowed via plugin configuration (and not explicity disallowed by filters) to format the text. Tags not enabled via plugin configuration will be stripped out of the HTML source when the user toggles back to the text editor.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9223, '@theme theme', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9224, 'The <code>update_fetch_with_http_fallback</code> setting must be disabled.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9225, 'Resolve all issues below to continue the installation. For help configuring your database server, see the <a href="https://www.drupal.org/docs/installing-drupal">installation handbook</a>, or contact your hosting provider.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9226, 'Updating to Drupal @current_major is only supported from Drupal version @required_min_version or higher. If you are trying to update from an older version, first update to the latest version of Drupal @previous_major. (<a href=":url">Drupal upgrade guide</a>)', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9227, 'Migrating an Existing Text Format to CKEditor 5', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9228, 'When switching an existing text format to use CKEditor 5, an automatic process is initiated that helps text formats switching to CKEditor 5 from CKEditor 4 (or no text editor) to do so with minimal effort and zero data loss.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9229, 'This process is designed for there to be no data loss risk in switching to CKEditor 5. However some of your editor''s functionality may not be 100% equivalent to what was available previously. In most cases, these changes are minimal. After the process completes, status and/or warning messages will summarize any changes that occurred, and more detailed information will be available in the site''s logs.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9230, 'CKEditor 5 will attempt to enable plugins that provide equivalent toolbar items to those used prior to switching to CKEditor 5. All core CKEditor 4 plugins and many popular contrib plugins already have CKEditor 5 equivalents. In some cases, functionality that required contrib modules is now built into CKEditor 5. In instances where a plugin does not have an equivalent, no data loss will occur but elements previously provided via the plugin may need to be added manually as HTML via source editing.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9231, 'Additional migration considerations for text formats with restricted HTML', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9232, 'The “Allowed HTML tags" field in the “Limit allowed HTML tags and correct Faulty HTML" filter is now read-only', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9233, 'This field accurately represents the tags/attributes allowed by a text format, but the allowed tags are based on which plugins are enabled and how they are configured. For example, enabling the Underline plugin adds the &lt;u&gt; tag to “Allowed HTML tags".', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9234, 'The &lt;p&gt; and &lt;br &gt; tags will be automatically added to your text format.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9235, 'CKEditor 5 requires the &lt;p&gt; and &lt;br &gt; tags to achieve basic functionality. They will be automatically added to “Allowed HTML tags" on formats that previously did not allow them.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9236, 'Tags/attributes that are not explicitly supported by any plugin are supported by Source Editing', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9237, 'When a necessary tag/attribute is not directly supported by an available plugin, the "Source Editing" plugin is enabled. This plugin is typically used for by passing the CKEditor 5 UI and editing contents as HTML source. In the settings for Source Editing, tags/attributes that aren''t available via other plugins are added to Source Editing''s "Manually editable HTML tags" setting so they are supported by the text format.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9238, 'To maintain the capabilities of this text format, <a target="_blank" href=":ck_migration_url">the CKEditor 5 migration</a> did the following:', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9239, 'To maintain the capabilities of this text format, the CKEditor 5 migration did the following:', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9240, 'Enabled these plugins: (%plugins).', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9241, 'Added these tags/attributes to the Source Editing Plugin''s <a target="_blank" href=":source_edit_url">Manually editable HTML tags</a> setting: @tag_list', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9242, 'Added these tags/attributes to the Source Editing Plugin''s Manually editable HTML tags setting: @tag_list', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9243, 'Additional details are available <a target="_blank" href=":dblog_url">in your logs</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9244, 'Additional details are available in your logs.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9245, 'Updating to CKEditor 5 added support for some previously unsupported tags/attributes.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9246, 'A plugin introduced support for the following:', '', 'none');
