INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9248, 'The @tag tag was added because it is <a target="_blank" href=":fundamental_tag_link">required by CKEditor 5</a>.The @tag tags were added because they are <a target="_blank" href=":fundamental_tag_link">required by CKEditor 5</a>.', '', 'none');
