INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9263, 'Block content entity changed', 'Validation', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9264, 'Style label', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9265, 'Style tag + classes', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9266, 'A list of classes that will be provided in the "Style" dropdown. Enter one or more classes on each line in the format: element.classA.classB|Label. Example: h1.title|Title. Advanced example: h1.fancy.title|Fancy title.<br />These styles should be available in your theme''s CSS file.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9267, 'Line @line-number does not contain a valid value. Enter a valid CSS selector containing one or more classes, followed by a pipe symbol and a label.Lines @line-numbers do not contain a valid value. Enter a valid CSS selector containing one or more classes, followed by a pipe symbol and a label.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9268, 'The following tag is missing the required attribute <code>@required_attribute_name</code>: <code>@provided_element</code>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9269, 'The following tag does not have the minimum of @min_attribute_value_count allowed values for the required attribute <code>@required_attribute_name</code>: <code>@provided_element</code>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9270, 'Styles can only be specified for already supported tags.', 'Validation', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9271, 'A style can only be specified for an HTML 5 tag. <code>@tag</code> is not an HTML5 tag.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9272, 'A style must only specify classes not supported by other plugins. The <code>@classes</code> classes on <code>@tag</code> are already supported by the enabled %plugin plugin.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9273, 'A style must only specify classes not supported by other plugins. The <code>@classes</code> classes on <code>@tag</code> are supported by the %plugin plugin. Remove this style and enable that plugin instead.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9274, 'Unique label in list', 'Validation', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9275, 'The label %label is not unique.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9276, 'The Text Editor module provides a framework that other modules (such as <a href=":ckeditor5">CKEditor5 module</a>) can use to provide toolbars and other functionality that allow users to format text more easily than typing HTML tags directly. For more information, see the <a href=":documentation">online documentation for the Text Editor module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9277, 'To search help, you will need to install the core Search module, configure a search page, and add a search block to the Help page or another administrative page. (A search page is provided automatically, and if you use the core Claro administrative theme, a help search block is shown on the main Help page.) Then users with search permissions, and permission to view help, will be able to search help. See the <a href=":search_help">Search module help page</a> for more information.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9287, 'The Shortcut module creates an add/remove link for each page on your site; the link lets you add or remove the current page from the currently-enabled set of shortcuts (if your theme displays it and you have permission to edit your shortcut set). The core Claro administration theme displays this link next to the page title, as a gray or yellow star. If you click on the gray star, you will add that page to your preferred set of shortcuts. If the page is already part of your shortcut set, the link will be a yellow star, and will allow you to remove the current page from your shortcut set.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9288, 'Grid - Responsive', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9289, 'Maximum number of columns', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9290, 'Minimum cell width', '', 'none');
