INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9281, 'Select <em>CKEditor 5</em> as the <em>Text editor</em>, or another text editor that you have installed. The rest of these steps assume you selected <em>CKEditor 5</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9282, 'Under <em>Toolbar configuration</em>, drag buttons between <em>Available buttons</em> and <em>Active toolbar</em>; only buttons in <em>Active toolbar</em> will be shown to the user. Focusing or hovering over a button will display a tooltip explaining what the button does.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9283, 'Drag buttons within <em>Active toolbar</em> to the desired order, and group buttons by dragging them between group identifiers; drag <em>a new group identifier</em> to the toolbar to add additional groups.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9284, 'If you add buttons that require configuration, the <em>CKEditor 5 plugin settings</em> section will be visible, and provide their respective configuration forms.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9279, 'The core Filter, Responsive Image, and Path modules provide settings and display options for entities and fields.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9278, 'A base theme is a theme that is not meant to be used directly on a site, but instead acts as a scaffolding for building other themes. The core Stable 9 theme is one example; other base themes can be downloaded from the <a href="https://www.drupal.org/project/project_theme">Download &amp; Extend page on drupal.org</a>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9286, 'Click the shortcut link to add the page to your shortcut list -- in the core Claro administrative theme, the link looks like a star, and is displayed next to the page title. However, if the page is already in your shortcut set, clicking the shortcut link will remove it from your shortcut set.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9285, 'Click the link for your administrative theme (such as the core Claro theme), near the top of the page, and verify that there is already a search block for help located in the Help region. If not, follow the steps in the related topic to place the <em>Search form</em> block in the Help region. When configuring the block, choose <em>Help</em> as the search page, and in the <em>Pages</em> tab under <em>Visibility</em>, enter <em>/admin/help</em> to make the search form only visible on the main <em>Help</em> page.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9260, 'Heading Level', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9296, 'The Drupal application''s codebase must be writable in order to use Automatic Updates. This includes Drupal core, modules, themes and the Composer dependencies in the <code>vendor</code> directory. This makes Automatic Updates incompatible with some hosting platforms.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9297, 'Because Package Manager modifies the current site''s code base, it is intentionally limited in certain ways to prevent unexpected changes to the live site:', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9298, 'It does not support Drupal multi-site installations.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9299, 'It does not automatically perform version control operations, e.g., with Git. Site administrators are responsible for committing updates.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9300, 'It can only maintain one copy of the site at any given time. If a copy of the site already exists, another one cannot be created until the existing copy is destroyed.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9301, 'It associates the temporary copy of the site with the user or session that originally created it, and only that user or session can make changes to it.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9302, 'It does not allow modules to be uninstalled while syncing changes into live site.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9303, 'The new package @package will be installed in the directory @path, which already exists but is not managed by Composer.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9304, '@message See <a href=":package-manager-help">the help page</a> for information on how to resolve the problem.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9305, 'Staged changes failed to apply, and the site is in an indeterminate state. It is strongly recommended to restore the code and database from a backup.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9306, 'Post-apply tasks are running in the same request during which staged changes were applied to the active code base. This can result in unpredictable behavior.', '', 'none');
