INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9397, 'The CKEditor 5 migration enabled the following plugins to support tags that are allowed by the %text_format text format: %enabling_message_content. The text format must be saved to make these changes active.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9398, 'The following tags were permitted by the %text_format text format''s filter configuration, but no plugin was available that supports them. To ensure the tags remain supported by this text format, the following were added to the Source Editing plugin''s <em>Manually editable HTML tags</em>: @unsupported_string. The text format must be saved to make these changes active.', '', 'none');
