INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9495, '%label is used by 1 content block on your site. You can not remove this block type until you have removed all of the %label blocks.%label is used by @count content blocks on your site. You may not remove %label until you have removed all of the %label content blocks.', '', 'none');
