INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9502, 'Images can only be added by URL.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9503, 'A list of programming languages that will be provided in the "Code Block" dropdown. Enter one value per line, in the format key|label. Example: php|PHP.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9504, 'Line @line-number does not contain a valid value. Enter a valid language key followed by a pipe symbol and a label.Lines @line-numbers do not contain a valid value. Enter a valid language key followed by a pipe symbol and a label.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9506, 'Content Moderation allows you to apply <a href=":workflows">Workflows</a> to content, content blocks, and other <a href=":field_help" title="Field module help, with background on content entities">content entities</a>, to provide more fine-grained publishing options. For example, a Basic page might have states such as Draft and Published, with allowed transitions such as Draft to Published (making the current revision "live"), and Published to Draft (making a new draft revision of published content).', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9508, 'The Content Translation module allows you to translate content, comments, content blocks, taxonomy terms, users and other <a href=":field_help" title="Field module help, with background on content entities">content entities</a>. Together with the modules <a href=":language">Language</a>, <a href=":config-trans">Configuration Translation</a>, and <a href=":locale">Interface Translation</a>, it allows you to build multilingual websites. For more information, see the <a href=":translation-entity">online documentation for the Content Translation module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9510, 'When enabled, images can only be uploaded. When disabled, images can only be added by URL.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9511, 'The Text Editor module provides a framework for managing editors. To use it, you also need to install a text editor. This can either be the core <a href=":ckeditor5">CKEditor5 module</a>, which can be installed on the <a href=":extend">Extend page</a>, or a contributed module for any other text editor. When installing a contributed text editor module, be sure to check the installation instructions, because you will most likely need to download an external library as well as the Drupal module.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9513, 'Text editors', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9514, 'Ensures that the latest versions of images uploaded via a Text Editor are displayed, along with their dimensions.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9515, 'The website''s content and configuration is managed using <em>entities</em>, which are grouped into <em>entity types</em>. <em>Content entity types</em> are the entity types for site content (such as the main site content, comments, content blocks, taxonomy terms, and user accounts). <em>Configuration entity types</em> are used to store configuration information for your site, such as individual views in the Views module, and settings for your main site content types.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9517, 'Once you have created a field, you can use it again in other sub-types of the same entity type. For instance, if you create a field for the article content type, you can also use it for the page content type, but you cannot use it for content blocks or taxonomy terms. If there are fields available for re-use, after clicking <em>Add field</em> from the <em>Manage fields</em> page, you will see a list of available fields for re-use. After selecting a field for re-use, you can configure the sub-type-level settings.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9525, 'There was a problem reusing field %label: @message', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9530, 'Lazy load images', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9730, 'TLS must be enabled for HTTPS Composer downloads.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9505, 'Allows importing and exporting configuration changes.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9509, 'Defines field types for storing dates and times.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9516, 'Provides the capabilities to add fields to entities.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9528, 'Provides a field type for files and defines a "managed_file" Form API element.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9529, 'Filters text content in preparation for display.', '', '11.3.5');
