INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9531, 'Instruct browsers to lazy load images if dimensions are specified. Use in conjunction with and place after the ''Track images uploaded via a Text Editor'' filter that adds image dimensions required for lazy loading. Results can be overridden by <code>&lt;img loading=&quot;eager&quot;&gt;</code>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9547, 'In the <em>Manage</em> administrative menu, navigate to <em>Configuration</em> &gt; <em>Region and language</em> &gt; <em>@config_translation_link</em>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9548, 'Both personal and site-wide contact forms will always have <em>Subject</em> and <em>Message</em> fields. You can add additional fields for users to fill out if desired. Note that if you want to display other content on a form page, such as text or images, you can use a content block.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9549, 'Users with <em>content moderation permissions</em> can change workflow states. There are separate permissions for each transition. See Permissions &gt; <em>@content_moderation_permissions_link</em> to configure content moderation permissions.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9550, 'Find the entity that you want to moderate in either the content moderation view page, if you created one, or the appropriate administrative page for managing that type of entity (such as the administration page for content items; see @content_link).', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9551, 'Users with <em>workflows permissions</em> (typically administrators) can configure workflows. See Permissions &gt; <em>@workflows_permissions_link</em> to configure workflows permissions.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9552, 'To implement your plan, in the <em>Manage</em> administrative menu, navigate to <em>Configuration</em> &gt; <em>Workflow</em> &gt; <em>@workflows_link</em>. A list of workflows is shown, including the default workflow <em>Editorial</em> that you can adapt.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9553, 'Under <em>This workflow applies to:</em>, find the entity type that you want this workflow to apply to, such as Content revisions, Content block revisions, or Taxonomy term revisions. Click <em>Select</em>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9554, 'Follow the steps in @user_permissions_topic to assign permissions for each transition to roles. The permissions are listed under the <em>@content_moderation_permissions_link</em> section; there is one permission for each transition in each workflow.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9555, 'In the <em>Manage</em> administrative menu, navigate to <em>Configuration</em> &gt; <em>Region and language</em> &gt; <em>@translation_settings_link</em>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9728, 'Composer cannot be used because the <code>proc_open()</code> function is disabled.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9562, 'In the <em>Manage</em> administrative menu, navigate to <em>Configuration</em> &gt; <em>Region and language</em> &gt; @language_link.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9537, 'Creating a content block', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9538, 'Create a content block, which can later be placed on the site.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9539, 'In the <em>Manage</em> administrative menu, navigate to <em>Content</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9540, 'Open the @library_link tab.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9541, 'Click <em>Add content block</em>. If you have more than one block type defined on your site, click the name of the type you want to create.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9565, 'In the <em>Manage</em> administrative menu, navigate to <em>Configuration</em> &gt; <em>System</em> &gt; <em>@information_link</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9558, 'In the <em>Manage</em> administrative menu, navigate to <em>Configuration</em> &gt; <em>Region and language</em> &gt; @languages_link.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9561, 'In the <em>Manage</em> administrative menu, navigate to <em>Configuration</em> &gt; <em>Region and language</em> &gt; @translate_link.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9564, 'In the <em>Manage</em> administrative menu, navigate to <em>Configuration</em> &gt; <em>Development</em> &gt; <em>@performance_link</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9566, 'In the <em>Manage</em> administrative menu, navigate to <em>Configuration</em> &gt; <em>Region and language</em> &gt; <em>@regional_link</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9567, 'In the <em>Manage</em> administrative menu, navigate to <em>Configuration</em> &gt; <em>Region and language</em> &gt; <em>@datetime_link</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9557, 'Depending on the core and contributed modules that you currently have installed on your site, the related topics below and other topics listed on the main help page (see @help_link) will help you with tasks related to content structure.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9559, 'In the <em>Manage</em> administrative menu, navigate to <em>Configuration</em> &gt; <em>Region and language</em> &gt; <em>Languages</em> &gt; @detection_link.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9533, 'What are content blocks?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9534, 'Content blocks are blocks whose content you can edit. You can define one or more <em>block types</em>, and attach fields to each block type. Content blocks can be placed just like blocks provided by other modules.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9535, 'Overview for managing blocks', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9536, 'The <em>Block</em> module allows you to place blocks in regions of your installed themes, and configure block settings. The <em>Block Content</em> module allows you to manage block types and content blocks. See the related topics listed below for specific tasks.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9563, 'When users visit the main search page (see @search_link), they will see the configured search pages that they have access to. Each search page has a search form on it, and the page will display search results after the user enters keywords into the form and clicks the search button.', '', '11.3.2');
