INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9568, 'In the <em>Error pages</em> section, enter the URL for your 403/404 pages, starting after the site home page URL. For example, if your site URL is <em>https://example.com</em> and your 404 page is <em>https://example.com/not-found</em>, you would enter <em>/not-found</em>.', '', '11.3.2');
