INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9576, 'Taxonomy reference fields can be added to any entity, such as user accounts, content blocks, or regular content items. If you use them to classify regular content items, your site will automatically be set up with taxonomy listing pages for each term; each of these pages lists all of the content items that are classified with that term.', '', '11.3.2');
