INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9573, 'In the <em>Manage</em> administrative menu, navigate to <em>Reports</em> &gt; <em>@status_link</em> to see a report that summarizes the health and status of your site. If there are any warnings or errors, you will need to fix them. Take note of any upcoming highly critical security releases that may impact your site.', '', '11.3.2');
