INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9628, 'In order to use REST on a website, you need to install modules that provide serialization and authentication services. You can use the Core module <a href=":serialization">serialization</a> for serialization and <a href=":basic_auth">HTTP Basic Authentication</a> for authentication, or install a contributed or custom module.', '', 'none');
