INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9669, 'Permissions let you control what users can do and see on your site. You can define a specific set of permissions for each role. (See the <a href=":role">Roles</a> page to create a role.) Any permissions granted to the Authenticated user role will be given to any user who is logged in to your site. On the <a href=":settings">Role settings</a> page, you can make any role into an Administrator role for the site, meaning that role will be granted all permissions. You should be careful to ensure that only trusted users are given this access and level of control of your site.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9671, 'This role will be automatically granted all permissions.', '', 'none');
