INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9708, 'Your Drupal site''s <code>composer.json</code> file must be valid according to <code>composer validate</code>. See <a href=":url">Composer''s documentation</a> for more information.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9709, 'Composer must be configured for secure downloads. This means that <a href=":disable-tls">the <code>disable-tls</code> option</a> must be <code>false</code>, and <a href=":secure-http">the <code>secure-http</code> option</a> must be <code>true</code> in the <code>config</code> section of your <code>composer.json</code> file. If these options are not set in your <code>composer.json</code>, Composer will behave securely by default. To set these values at the command line, run the following commands:', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9710, 'For more information, see the <a href=":url">online documentation for the Package Manager module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9711, 'FAQs related to Composer', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9712, 'What if it says the <code>proc_open()</code> function is disabled on your PHP installation?', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9713, 'Ask your system administrator to remove <code>proc_open()</code> from the <a href=":url">disable_functions</a> setting in <code>php.ini</code>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9714, 'What if it says the <code>composer</code> executable cannot be found?', '', 'none');
