INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9717, 'Composer detected problems with your <code>composer.json</code> and/or <code>composer.lock</code> files, and the project is not in a completely valid state. See <a href=":url">the Composer documentation</a> for more information.', '', 'none');
