INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9720, 'Package Manager requires <a href=":php-tuf">PHP-TUF</a>, which implements <a href=":tuf">The Update Framework</a> as a way to help secure Composer package downloads via the <a href=":php-tuf-plugin">PHP-TUF Composer integration plugin</a>. This plugin must be installed and configured properly in order to use Package Manager.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9721, 'To install and configure the plugin as needed, you can run the following commands:', '', 'none');
