INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9866, 'Working with help topics', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9867, 'What is a help topic?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9869, 'Where are help topics listed?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9870, 'The top-level help topics are listed at @help_link. Links to other topics, including non-top-level help topics, can be found under the "Related" heading when viewing a topic page.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9871, 'How are help topics provided?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9873, 'How are help topics translated?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9874, 'The title and body text of help topics provided by contributed modules and themes are translatable using @translate_link (provided by Interface Translation module). Topics provided by custom modules and themes are also translatable if they have been viewed at least once in a non-English language, which triggers putting their translatable text into the translation database.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9875, 'How can users search for help topics?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9876, 'To enable users to search help, including help topics, you will need to install the core Search module, configure a search page, and add a search block to the Help page or another administrative page. (A search page is provided automatically, and if you use the core Claro administrative theme, a help search block is shown on the main Help page.) Then users with search permissions, and permission to view help, will be able to search help. See the related topic, @help_search_topic, for step-by-step instructions.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9877, 'Help Topics Standards', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9865, 'In the <em>Manage</em> administrative menu, navigate to <em>@extend_link</em>. Verify that the Search, Help, and Block modules are installed (or install them if they are not already installed).', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9894, 'Displays on the <em>Content types</em> page.', '', '11.3.5');
