INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9949, 'CKEditor 5 has to be installed and configured separately for individual text formats from the <a href=":formats">Text formats and editors page</a> because the filter settings for each text format can be different. For more information, see the <a href=":text_editor">Text Editor help page</a> and <a href=":filter">Filter help page</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9950, 'The <code>@tag</code> tag is not yet supported by the Style plugin.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9951, 'Comment functionality can be enabled for any entity sub-type (for example, a <a href=":content-type">content type</a>) by adding a <em>Comments</em> field on its <em>Manage fields page</em>. Adding or removing commenting for an entity through the user interface requires the <a href=":field_ui">Field UI</a> module to be installed, even though the commenting functionality works without it. For more information on fields and entities, see the <a href=":field">Field module help page</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9952, 'Commenting settings can be configured by editing the <em>Comments</em> field on the <em>Manage fields page</em> of an entity type if the <em>Field UI module</em> is installed. Configuration includes the label of the comments field, the number of comments to be displayed, and whether they are shown in threaded list. Commenting can be configured as: <em>Open</em> to allow new comments, <em>Closed</em> to view existing comments, but prevent new comments, or <em>Hidden</em> to hide existing comments and prevent new comments. Changing this configuration for an entity type will not change existing entity items.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9953, 'If you have the <a href=":toolbar">Toolbar module</a> installed, clicking the contextual links button in the toolbar (which looks like a pencil) will make all contextual links buttons on the page visible. Clicking this button again will toggle them to invisible.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9977, 'You need to install all modules on this site that are installed on the previous site. For example, if you have used the Book module on the previous site then you must install the Book module on this site for that data to be available on this site.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (10020, 'The @name config object does not contain any translatable values, so it should not specify a language code.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9912, '<a href="https://www.drupal.org/docs/user_guide/en/prevent-cache.html">Concept: Cache (Drupal User Guide)</a>', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9924, 'Setting Up a Taxonomy (Drupal User Guide)', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9925, 'Concept: Taxonomy (Drupal User Guide)', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9907, 'Make sure that the core Shortcut module is installed, and that you have a role with <em>Edit current shortcut set</em> or <em>Administer shortcuts</em> permission. Also, make sure that a toolbar module is installed (either the core Toolbar module or a contributed module replacement).', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9937, 'This will appear in the URL after the ? to identify this filter. Cannot be blank. Only letters, digits and the dot ("."), hyphen ("-"), underscore ("_"), and tilde ("~") characters are allowed. @reserved_identifiers are reserved words and cannot be used.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9947, 'Sark', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9948, 'Türkiye', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9915, 'Note that the administration theme is still set to the %admin_theme theme; consequently, the theme on this page remains unchanged. All non-administrative sections of the site, however, will show the selected %selected_theme theme by default.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9917, 'Success (@status_code)', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9918, 'Access denied (@status_code)', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9919, 'Page not found (@status_code)', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9920, 'Shows the block on pages with any matching response status. If nothing is checked, the block is shown on all pages. Other response statuses are not used.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9936, 'If checked, multiple values for this field will be shown in the same row. If not checked, each value in this field will create a new row. If using group by, make sure to group by "Entity ID" for this setting to have any effect.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9938, 'Negated regular expression', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9928, 'Another user (%other_user) is already logged into the site on this computer, but you tried to use a one-time link for user %resetting_user. <a href=":logout">Log out</a> and try using the link again.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9954, 'The Field module provides the infrastructure for fields; the field types, formatters, and widgets are provided by Drupal core or additional modules. Some of the modules are required; the optional modules can be installed from the <a href=":modules">Extend administration page</a>. Additional fields, formatters, and widgets may be provided by contributed modules, which you can find in the <a href=":contrib">contributed module section of Drupal.org</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9955, 'Here is a list of the currently installed field, formatter, and widget modules:', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9956, 'The Field UI module provides an administrative user interface (UI) for managing and displaying fields. Fields can be attached to most content entity sub-types. Different field types, widgets, and formatters are provided by the modules installed on your site, and managed by the Field module. For background information and terminology related to fields and entities, see the <a href=":field">Field module help page</a>. For more information about the Field UI, see the <a href=":field_ui_docs">online documentation for the Field UI module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9957, 'There are two reports available that list the fields defined on your site. The <a href=":entity-list" title="Entities field list report">Entities</a> report lists all your fields, showing the field machine names, types, and the entity types or sub-types they are used on (each sub-type links to the Manage fields page). If the <a href=":views">Views</a> and <a href=":views-ui">Views UI</a> modules are installed, the <a href=":views-list" title="Used in views field list report">Used in views</a> report lists each field that is used in a view, with a link to edit that view.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9958, 'You can create and edit text formats on the <a href=":formats">Text formats page</a> (if the Text Editor module is installed, this page is named Text formats and editors). One text format is included by default: Plain text (which removes all HTML tags). Additional text formats may be created during installation. You can create a text format by clicking "<a href=":add_format">Add text format</a>".', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9959, '<strong>Enable additional functionality</strong> Next, visit the <a href=":modules">Extend page</a> and install modules that suit your specific needs. You can find additional modules at the <a href=":download_modules">Drupal.org modules page</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9960, 'Help topics provided by modules and themes are also part of the Help module. If the core Search module is installed, these topics are searchable. For more information, see the <a href=":online">online documentation, Help Topic Standards</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9961, 'A few of the settings for image fields are defined once when you create the field and cannot be changed later; these include the choice of public or private file storage and the number of images that can be stored in the field. The rest of the settings can be edited later; these settings include the field label, help text, allowed file extensions, image dimensions restrictions, and the subdirectory in the public or private file storage where the images will be stored. The editable settings can also have different values for different entity sub-types; for instance, if your image field is used on both Page and Article content types, you can store the files in a different subdirectory for the two content types.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9962, 'You can also configure a minimum and/or maximum dimensions for uploaded images. Images that are too small will be rejected. Images that are to large will be resized. During the resizing the <a href="http://wikipedia.org/wiki/Exchangeable_image_file_format">EXIF data</a> in the image will be lost.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9964, 'The Language module allows you to configure the languages used on your site, and provides information for the <a href=":content">Content Translation</a>, <a href=":interface">Interface Translation</a>, and <a href=":configuration">Configuration Translation</a> modules, if they are installed. For more information, see the <a href=":doc_url">online documentation for the Language module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9965, 'You can add languages on the <a href=":language_list">Languages</a> page by selecting <em>Add language</em> and choosing a language from the drop-down menu. This language is then displayed in the languages list, where it can be configured further. If the <a href=":interface">Interface translation module</a> is installed, and the <em>translation server</em> is set as a translation source, then the interface translation for this language is automatically downloaded as well.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9966, 'If the Block module is installed, then you can add a language switcher block on the <a href=":blocks">Block layout</a> page to allow users to switch between languages.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9967, 'If the Block module is installed, then the Language module allows you to set the visibility of a block based on selected languages on the <a href=":blocks">Block layout</a> page.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9968, 'Translation files with translated interface text are imported automatically when languages are added on the <a href=":languages">Languages</a> page, or when modules or themes are installed. On the <a href=":locale-settings">Interface translation settings</a> page, the <em>Translation source</em> can be restricted to local files only, or to include the <a href=":server">Drupal translation server</a>. Although modules and themes may not be fully translated in all languages, new translations become available frequently. You can specify whether and how often to check for translation file updates and whether to overwrite existing translations on the <a href=":locale-settings">Interface translation settings</a> page. You can also manually import a translation file on the <a href=":import">Interface translation import</a> page.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9969, 'Interface translations are automatically imported when a language is added, or when new modules or themes are installed. The report <a href=":update">Available translation updates</a> shows the status. Interface text can be customized in the <a href=":translate">user interface translation</a> page.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9970, 'Translation files are automatically downloaded and imported when <a title="Languages" href=":language">languages</a> are added, or when modules or themes are installed.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9971, 'Use <em>Media</em> reference fields for most files, images, audio, videos, and remote media. Use <em>File</em> or <em>Image</em> reference fields when creating your own media types, or for legacy files and images created before installing the Media module.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9972, '%type_name: View any media revision pages', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9973, 'Revert %type_name: Revert media revisions', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9974, 'Delete %type_name: Delete media revisions', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9975, 'For more information, see the <a href=":drupal-org-help">online documentation for the Custom Menu Links module</a>. If you install the Menu UI module, it provides an interface for managing menus and menu links.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9976, 'If you have the Block module installed, then each menu that you create is rendered in a block that you enable and position on the <a href=":blocks">Block layout page</a>. In some <a href=":themes">themes</a>, the main menu and possibly the secondary menu will be output automatically; you may be able to disable this behavior on the <a href=":themes">theme''s settings page</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9963, 'Minimum image dimensions', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9978, 'The RESTful Web Services module provides a framework for exposing REST resources on your site. It provides support for content entity types such as the main site content, comments, content blocks, taxonomy terms, and user accounts, etc. (see the <a href=":field">Field module help page</a> for more information about entities). REST support for content items of the Node module is installed by default, and support for other types of content entities can be enabled. Other modules may add support for other types of REST resources. For more information, see the <a href=":rest">online documentation for the RESTful Web Services module</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9979, 'Modules providing search page plugins generally ensure that content-related actions on your site (creating, editing, or deleting content and comments) automatically cause affected content items to be marked for indexing or reindexing at the next cron run. When content is marked for reindexing, the previous content remains in the index until cron runs, at which time it is replaced by the new content. However, there are some actions related to the structure of your site that do not cause affected content to be marked for reindexing. Examples of structure-related actions that affect content include deleting or editing taxonomy terms, installing or uninstalling modules that add text to content (such as Taxonomy, Comment, and field-providing modules), and modifying the fields or display parameters of your content types. If you take one of these actions and you want to ensure that the search index is updated to reflect your changed site structure, you can mark all content for reindexing by clicking the "Re-index site" button on the <a href=":search-settings">Search pages page</a>. If you have a lot of content on your site, it may take several cron runs for the content to be reindexed.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9980, 'The Search module includes a block, which can be enabled and configured on the <a href=":blocks">Block layout page</a>, if you have the Block module installed; the default block title is Search, and it is the Search form block in the Forms category, if you wish to add another instance. The block is available to users with the <a href=":search_permission">Use search</a> permission, and it performs a search using the configured default search page.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9987, 'The installed version of at least one of your modules or themes has been revoked and is no longer available for download. Upgrading or uninstalling is strongly recommended!', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9988, 'The installed version of at least one of your modules or themes is no longer supported. Upgrading or uninstalling is strongly recommended. See the project homepage for more details.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9989, '<em>Roles</em> are used to group and classify users; each user can be assigned one or more roles. Typically there are two pre-defined roles: <em>Anonymous user</em> (users that are not logged in), and <em>Authenticated user</em> (users that are registered and logged in). Depending on how your site was set up, an <em>Administrator</em> role may also be available: users with this role will automatically be assigned any new permissions whenever a module is installed. You can create additional roles on the <a href=":roles">Roles administration page</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9990, 'The <a href=":accounts">Account settings page</a> allows you to manage settings for the displayed name of the Anonymous user role, personal contact forms, user registration settings, and account cancellation settings. On this page you can also manage settings for account personalization, and adapt the text for the email messages that users receive when they register or request a password recovery. You may also set which role is automatically assigned new permissions whenever a module is installed (the Administrator role).', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9991, 'In order to create and modify your own views using the administration and configuration user interface, you will need to install either the Views UI module in core or a contributed module that provides a user interface for Views. See the <a href=":views-ui">Views UI module help page</a> for more information.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9992, 'Stage directory cleaner', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9993, 'The following @element_type(s) can optionally be supported by enabled plugins and should not be added to the Source Editing "Manually editable HTML tags" field: %overlapping_tags.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9994, 'Include unrecognized files and directories in the project root in staging operations', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9995, 'The following paths in @project_root aren''t recognized as part of your Drupal site, so to be safe, Package Manager is excluding them from all stage operations. If these files are not needed for Composer to work properly in your site, no action is needed. Otherwise, you can disable this behavior by setting the <code>package_manager.settings:include_unknown_files_in_project_root</code> config setting to <code>TRUE</code>.
