INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (10285, 'The Workflows module provides an API and an interface to create workflows with transitions between different states (for example publication or user status). These have to be provided by other modules such as the Content Moderation module. For more information, see the <a href=":workflow">online documentation for the Workflows module</a>.', '', 'none');
