INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (10292, 'A transition defines in which state an item can be save as next. It has one destination state, but can have several states <em>from</em> which the transition can be applied. Transitions can be added when you add or edit a workflow on the <a href=":workflows">Workflows page</a>.', '', 'none');
