INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5259, 'Automated emails, such as registration information, will be sent from this address. Use an address ending in your site''s domain to help prevent these emails from being flagged as spam.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (2412, 'Site maintenance account', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (1120, 'Default time zone', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (1978, 'Check for updates automatically', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (10730, 'When checking for updates, your site automatically sends anonymous information to Drupal.org. See the <a href="@update-status-module-docs" target="_blank">Update Status module documentation</a> for details.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (10006, 'New administration navigation', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8934, 'Configuring aliases for URLs', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8936, 'URL is the abbreviation for "Uniform Resource Locator", which is the page''s address on the web. It is the "name" by which a browser identifies a page to display. In the example "Visit us at <em>example.com</em>.", <em>https://example.com</em> would be the URL for the home page of your website. Users use URLs to locate content on the web.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (3950, 'Additional resources', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9902, 'Concept: Paths, Aliases, and URLs (Drupal User Guide)', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8334, 'Using contextual links', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7902, 'Use contextual links to access administrative tasks without navigating the administrative menu.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7904, '<em>Contextual links</em> give users with the <em>Use contextual links</em> permission quick access to administrative tasks related to areas of non-administrative pages. For example, if a page on your site displays a block, the block would have a contextual link that would allow users with permission to configure the block. If the block contains a menu or a view, it would also have a contextual link for editing the menu links or the view. Clicking a contextual link takes you to the related administrative page directly, without needing to navigate through the administrative menu system.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8096, 'What is a module?', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8097, 'A <em>module</em> is a set of PHP, JavaScript, and/or CSS files that extends site features and adds functionality. A set of <em>Core modules</em> is distributed as part of the core software download. Additional <em>Contributed modules</em> can be downloaded separately from the <a href="https://www.drupal.org/project/project_module">Download &amp; Extend page on drupal.org</a>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9855, '<a href="https://www.drupal.org/docs/user_guide/en/understanding-modules.html">Concept: Modules (Drupal User Guide)</a>', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7656, 'Managing content', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8918, 'The core Node module allows you to define content types, and add and edit content items. The core Field UI module allows you to attach fields to each content type and manage the edit form and display for each content type. See the related topics listed below for specific tasks. Many other core and contributed modules and installation profiles provide pre-defined content types, modify the permission structure for content items, and provide other functionality.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7876, 'Configure the settings of a block that was previously placed in a region of a theme.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9312, 'In the <em>Manage</em> administrative menu, navigate to <em>Structure</em> &gt; <em>@layout_link</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7879, 'If you only want to change the region where a block is located, or the ordering of blocks within a region, drag blocks to their desired positions and click <em>Save blocks</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8465, 'Reordering and disabling menu links', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8466, 'Disable menu links or change the order and hierarchy of menu links.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8136, 'Put your site in maintenance mode to perform maintenance operations, and then return to normal mode when finished.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (1081, 'Enter the terms you wish to search for.', '', '11.3.5');
