INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (3675, 'Powered by', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5674, 'Drupal Logo', '', '11.3.5');
