INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (4494, 'Block layout', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5961, 'Inaccessible', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (2762, 'Maintenance mode', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (352, 'Breadcrumb', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (3417, 'Close message', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (1443, 'Confirm password', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (1065, 'Passwords match:', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6850, 'Recommendations to make your password stronger:', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6423, 'Make it at least 12 characters', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (2836, 'Add lowercase letters', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (2023, 'Strong', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (547, 'Log in', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (1474, 'Save and continue', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8138, 'When your site is in maintenance mode, most site visitors will see a simple maintenance mode message page, rather than being able to use the full functionality of the site. Users with <em>Use the site in maintenance mode</em> permission who are already logged in will be able to use the full site, and the log in page at <em>/user</em> will also be accessible to anyone.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9570, 'In the <em>Manage</em> administrative menu, navigate to <em>Configuration</em> &gt; <em>Development</em> &gt; <em>@maintenance_link</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9014, 'Clear the site cache. See @cache_topic for instructions.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8804, 'Configuring comments', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8820, 'Creating a comment type', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8805, 'Configure a content entity type/subtype to allow commenting, using a comment type that you have configured. See @content_structure_topic for more about content entities and fields, and @comment_type_topic to configure a comment type.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8807, 'In order to follow these steps, the Field UI module must be installed. You''ll need the Comment module''s <em>@comment_permissions_link</em> permission, in order to change comment settings for a comment field. You''ll also need to have the appropriate permission for adding fields to the entity type or subtype that the comments are attached to. For example, to add a comment field to content items provided by the Node module, you would need the Node module''s <em>Administer content types</em> permission.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8809, 'On the first field settings page, choose the <em>Comment type</em> to use for this entity type or sub-type. You''ll also notice that the <em>Allowed number of values</em> field cannot be changed for comment fields.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8810, 'On the next field settings page, enter the desired settings for the comment field:', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8811, '<em>Threading</em>: whether or not the comments are collected by threads, with people able to reply to particular comments instead of to the content entity itself.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (10731, '<em>Show reply form on the same page as comments</em>: whether the comment reply form is displayed on the same page as the comments. If this is not selected, clicking <em>Reply</em> will open a new page with the reply form.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8878, 'Creating a content item', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8879, 'Create and publish a content item. See @content_overview_topic for more about content types and content items.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8881, 'Users with the <em>@content_permissions_link</em> permission can visit the <em>Content</em> page as described in this topic. Each content type has its own create permissions. For example, to create content of type Article, a user would need the Article: Create new content permission. In addition, users with the <em>Bypass content access control</em> or <em>Administer content</em> permission can create content items of all types. Some contributed modules change the permission structure for creating content.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9582, 'If you are not already editing your view, in the <em>Manage</em> administrative menu, navigate to <em>Structure</em> &gt; <em>@views_link</em>. Find the view you want to edit, and click its <em>Edit</em> link.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9017, 'Find the section whose settings you want to change, such as <em>Format</em> or <em>Filter criteria</em>. (See @views_overview_topic for more information.)', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8506, 'For sections containing lists (such as <em>Fields</em> and <em>Filter criteria</em>), to modify or delete an existing item, click the name of the item. To add a new item, click <em>Add</em> in the drop-down list. To change the order of items, click <em>Rearrange</em> in the drop-down list.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8507, 'For sections containing individual settings (such as <em>Title</em> and <em>Format</em>), there are often two links for each setting. The first link shows the current value; click that link to change the value. If there is a second link called <em>Settings</em>, click that link to change the settings details. For example, if your <em>Format</em> is currently shown as <em>Unformatted list</em>, click <em>Unformatted list</em> to switch to using a <em>Grid</em> or <em>Table</em> format. Click <em>Settings</em> next to your format type to change the settings for your chosen format.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9933, '<a href="https://www.drupal.org/docs/user_guide/en/views-chapter.html">Creating Listings with Views (Drupal User Guide)</a>', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8362, 'Managing user accounts and site visitors', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9546, 'A comment is a piece of content, typically posted by a website visitor, which provides discussion or commentary on other content like blog posts and news articles. Comments are a type of content entity, and can have fields that store text, HTML markup, and other data. Comments are attached to other content entities via Comment fields. See @content_structure_topic for more about content entities and fields.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8849, 'Comments are divided into <em>comment types</em>, which are the entity sub-types for the comment entity type. Each comment type has its own fields and its own form and display settings; each type can be used to comment on a single entity type. You can set up different comment types for different commenting purposes on your web site; for example, you might set up a comment type for recipes that has fields "How did it taste?" and "Did the instructions work?", and another comment type for blog entries that has only a generic comment body field.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8441, 'Adding a link to a menu', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8442, 'Add a link to a menu. Note that you can also add a link to a menu from the content edit page if menu settings have been configured for the content type.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9331, 'In the <em>Manage</em> administrative menu, navigate to <em>Reports</em> &gt; <em>@translation_updates_link</em>. This report is only available if the core Update Status module is installed.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8563, 'Exporting your complete site configuration', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8576, 'Managing and deploying configuration', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8977, 'Create and download an archive containing all your site''s configuration, exported as YAML files. See @config_overview_topic for more information about configuration.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8278, 'Install a core theme, or a contributed theme that has already been downloaded. Choose the default themes to use for the site and for administrative pages.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8280, 'For each of these themes, if the theme is in the <em>Uninstalled themes</em> section, click the <em>Install</em> link to install the theme. Wait for the theme to be installed (translations might be downloaded). You should be returned to the <em>Appearance</em> page.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8155, 'Enter the <em>Email address</em>, <em>Username</em>, and <em>Password</em> (twice) for the new user.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (4697, 'Click <em>Save</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7942, 'Set up your site to respond appropriately to site errors, including 403 and 404 page responses.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6736, 'Basic site settings', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (95, 'Content', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (869, 'Languages', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (4188, 'Access the Content overview page', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7944, 'When a user visits a web page, the web server sends a response code in addition to the page content. A normal, non-error response has code 200. If the page does not exist on the site, the response code is 404. If the page exists, but the user is not authorized to visit the page, the response code is 403. The core software provides default responses for both 403 and 404 codes, but if you prefer, you can create your own pages for each.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5468, 'Configuring search pages', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9338, 'In the <em>Manage</em> administrative menu, navigate to <em>Configuration</em> &gt; <em>Search and Metadata</em> &gt; <em>@search_settings_link</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8295, 'Optionally, disable or delete any search pages that you do not want to have available on the site (disabling is temporary, while deleting is permanent).', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8725, 'If your language is not in the list, select <em>Custom language...</em> and enter the <em>Language code</em>, <em>Language name</em>, and <em>Direction</em> for the language. Click <em>Add custom language</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (10732, 'Wait for the translation system to be updated. Also, if you have the core Update Status module installed and translations are available for your language, wait for translations to be downloaded. You should be returned to the <em>Languages</em> page when this completes.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9173, 'Using in-line (quick) settings editing', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5436, 'Manage form and displays settings of comments.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9180, 'In-place or <em>quick</em> editing. In-place editing of configuration is provided by the core Settings Tray module. See @settings_tray_topic for more information.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8437, 'For an existing content type, configure the available menus that will be shown as options on content editing screens; links to content items of this type can be added to these menus during editing.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8394, 'A menu is a collection of <em>menu links</em> used to navigate a web site. Menus and menu links can be provided by modules or site administrators.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8396, 'The core Menu UI module provides a user interface for managing menus, including creating new menus, reordering menu links, and disabling links provided by modules. It also provides the ability for links to content items to be added to menus while editing, if configured on the content type. The core Custom Menu Links module provides the ability to add custom links to menus. Each menu can be displayed by placing a block in a theme region; some themes also can display a menu outside of the block system. See the related topics listed below for specific tasks.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7742, 'Additional Resources', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (10733, 'Adding an image style', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8614, 'Click <em>Add image style</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8615, 'Enter a descriptive <em>Image style name</em>, and click <em>Create new style</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8617, 'Configure the effect on the next page. Most effects require some additional configuration after they are added.  For example, for the <em>Crop</em> effect, enter the <em>Width</em> and <em>Height</em> to crop the image to, and choose the <em>Anchor</em> point. Click <em>Add effect</em>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8418, 'A text filter is a processing step that can be applied to text, either to transform it in some way (such as converting URLs in the text into HTML links), or to defend against potentially-dangerous input from site users. A text format is an ordered sequence of text filters. Text filters are provided by modules; text formats are managed by the core Filter module.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6237, 'Limit allowed HTML tags and correct faulty HTML', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (3215, 'Convert line breaks into HTML', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (2517, 'Convert URLs into links', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (3558, 'Restrict images to this site', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8088, 'To ensure that your site and its modules continue to function well, a group of administrative operations should be run periodically. These operations are called <em>cron</em> tasks, and running the tasks is known as <em>running cron</em>. Depending on how often content is updated on your site, you might need to run cron on a schedule ranging from hourly to weekly to keep your site running well.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9853, '<a href="https://www.drupal.org/docs/user_guide/en/security-cron-concept.html">Concept: Cron (Drupal User Guide)</a>', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8176, 'Enter all or part of the user name or email address of the user account you want to update or delete, and click <em>Filter</em>. A short list of user accounts, including the account of interest, should be shown in the table; if not, modify the filter text until you can find the account of interest.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6183, 'Single item', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9452, 'Displays announcements from the Drupal community.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (2760, 'Administer blocks, content types, menus, etc.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9471, 'Create and manage fields, forms, and display settings for your content blocks.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (4413, 'Configure what displays are available for your content and forms.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6511, 'Manage menus and menu links.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6700, 'Create and manage fields, forms, and display settings for your content.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (1470, 'Manage tagging, categorization, and classification of your content.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (10126, 'Add and install modules to extend site functionality.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (2573, 'Configure styles that can be used for resizing or adjusting images on display.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6738, 'Configure the location of uploaded files and how they are accessed.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (2117, 'Choose which image toolkit to use if you have installed optional toolkits.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9647, 'Enable or disable the menu linkset endpoint', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6040, 'Import and export your configuration.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9700, 'Configure theme development settings', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6507, 'Configure languages for content, interface, and configuration.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (4545, 'Configure language support for content.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5084, 'Configure search pages and search indexing options.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (3071, 'Manage automatic site maintenance tasks.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (2952, 'Add and modify shortcut sets.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6750, 'Configure content formatting and authoring.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (2916, 'Overview of fields on all entity types.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (3934, 'Get a status report about available interface translations for your installed modules and themes.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (3745, 'Overview of plugins used in all views.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (3891, 'User interface translation', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (3040, 'Search pages', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (4097, 'Text formats and editors', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (2642, 'Administer content types', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8567, 'Paste the copied text into a plain-text editor on your computer or other device, and save it using the suggested file name below the text box.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9254, 'Find the view that you would like to edit, and click <em>Edit</em> from the dropdown button. Note that bulk operations work best in a view with a Page display, and a Table format.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8973, 'If there is not already an <em>Operations bulk form</em> in the <em>Fields</em> list for the view, click <em>Add</em> in the <em>Fields</em> section to add it. (The exact name of the bulk form field will vary, and may contain keywords like "bulk update", "form element" or "operations" -- not to be confused with <em>operations links</em>, which are applied to each item in a row.) If the bulk operations field already exists, click the field name to edit its settings.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8134, 'Some of the calculations that are done when your site loads a page take a long time to run. To save time when these calculations would need to be done again, their results can be <em>cached</em> in your site''s database. There are internal mechanisms to <em>clear</em> cached data when the conditions or assumptions that went into the calculation have changed, but you can also clear cached data manually. When your site is misbehaving, a good first step is to clear the cache and see if the problem goes away.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8364, 'Configuring how user accounts are created and deleted', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9012, 'The <em>Content</em> and <em>Help</em> search types provided by the core software pre-index their content and store the results in several database tables that are collectively called the <em>search index</em>. The process of indexing renders the content and breaks it up into words, which can then be matched more efficiently with keyword queries when users perform searches. Search indexing happens during cron runs; see @cron_topic for more information about cron.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8298, 'Under <em>Indexing throttle</em>, select the <em>Number of items to index per cron run</em>. A smaller number will make cron faster and reduce the possibility of timeout; a larger number will make sure more of your site is indexed in fewer cron runs.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8232, 'Breakpoints are the point at which your site''s content will respond to provide the user with the best possible layout to consume the information. A breakpoint separates the height or width of viewports (screens, printers, and other media output types) into steps. For instance, a width breakpoint of 40em creates two steps: one for widths up to 40em and one for widths above 40em. Breakpoints can be used to define when layouts should shift from one form to another, when images should be resized, and other changes that need to respond to changes in viewport height or width.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (4736, 'Resolution multipliers are a measure of the viewport''s device resolution, defined to be the ratio between the physical pixel size of the active device and the <a href="http://en.wikipedia.org/wiki/Device_independent_pixel">device-independent pixel</a> size. The Breakpoint module defines multipliers of 1, 1.5, and 2; when defining breakpoints, modules and themes can define which multipliers apply to each breakpoint.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (3924, 'Breakpoints can be organized into groups. Modules and themes should use groups to separate out breakpoints that are meant to be used for different purposes, such as breakpoints for layouts or breakpoints for image sizing.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9581, 'Views using a table display format can include a bulk operations form, which allows users with sufficient permission to select one or more items from the view and apply an administrative action to them. The bulk actions available are specific to the base data type of the view; for example, a view of content items could support bulk publishing and unpublishing actions. If you have the core Actions UI module installed, see the related topic "Configuring actions" for more about actions.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (10735, 'The core User module allows users to register, log in, and log out, and administrators to manage user roles and permissions. Depending on which modules you have installed on your site, the related topics below will help you with tasks related to managing user accounts and visitors.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (10736, 'Connecting text editors to text formats', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9280, 'A text editor is software (typically, a JavaScript library) that provides buttons and other command mechanisms to make editing HTML text easier. Some editors are called <em>visual</em> or <em>WYSIWYG (What You See Is What You Get)</em> editors; these editors hide the details of HTML from the user, and instead show formatted output on the screen. The core Text Editor module provides a framework for deploying text editors on your site. The core CKEditor 5 module provides CKEditor 5, which is a widely-used JavaScript text editor that creates clean and valid HTML; the module also enforces the HTML tag restrictions in the associated text format. Various contributed modules provide other editors; to install a new editor, besides installing the module, you may need to download the editor library from a third-party site.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9556, 'A <em>content entity</em> (or more commonly, <em>entity</em>) is an item of content data, which can consist of text, HTML markup, images, attached files, and other data. Content entities are grouped into <em>entity types</em>, which have different purposes and are displayed in very different ways on the site. Most entity types are also divided into <em>entity sub-types</em>, which are divisions within an entity type to allow for smaller variations in how the entities are used and displayed. For example, the <em>Content item</em> entity type that stores page-level content is divided into <em>content type</em> sub-types; the <em>Content block</em> entity type has <em>block types</em>; but the <em>User</em> entity type (for user profile information) does not have sub-types.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8392, 'There are several types of text fields, with different characteristics. Text fields can be either <em>plain</em> or <em>formatted</em>: plain text fields do not contain HTML, while formatted fields can contain HTML and are processed through <em>text filters</em> (these are provided by the core Filter module; if you have that module enabled, see the related topic below on filters for more information). Text fields can also be regular-length (with a limit of 255 characters) or <em>long</em> (with a very large character limit), and long formatted text fields can include a <em>summary</em> attribute. All possible combinations of these characteristics exist as text field types; for example, <em>Text (plain)</em> and <em>Text (formatted, long, with summary)</em> are two examples of text field types.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (10737, 'The core Node, Comment, Content Block, Custom Menu Links, User, File, Image, Media, and Taxonomy modules all provide content entity types.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9852, '<a href="https://www.drupal.org/docs/user_guide/en/structure-reference-fields.html">Concept: Reference Fields (Drupal User Guide)</a>', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (10762, 'Configure the Admin Toolbar Search module.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (10763, 'Configure the Admin Toolbar Tools module.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (306, 'Files', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (1224, 'Account settings', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (571, 'Uninstall', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (1351, 'Enables the categorization of content.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (10738, 'The core Language module lets you add new languages to your site, provides the <em>Language switcher</em> block, and provides the ability to configure block visibility by language; the block and block visibility settings are only available if you have multiple languages configured. The core Content Translation, Configuration Translation, and Interface Translation modules let you translate content, configuration, and the built-in user interface, respectively. The core Locale module manages automatic downloads of community-provided translations of default configuration and user-interface text if the core Update Status module is installed. See the related topics listed below for specific tasks.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8729, 'A language detection method is a way for your site to decide what language should be used to display text. This decision is made by evaluating a series of detection methods for languages; the first detection method that gets a result will determine which language is used. If you have more than one language on your site, you can configure the detection methods that are used and the order they are evaluated, for both user interface text and content text. Configuration text always uses the interface text method, and most sites use the same detection methods for all types of text.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8578, 'The configuration system provides the ability for administrators to customize the site, and to move and synchronize configuration changes between development sites and the live site. It does this in 2 ways:', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (4598, 'Simple configuration', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8588, 'Default configuration can be defined by a module, theme, or installation profile in its <em>config/install</em> or <em>config/optional</em> directories. Configuration is provided in YAML files (file extension .yml); YAML is a human-readable data serialization standard that is used by the core software for several purposes. Once the default configuration has been imported into the site''s active configuration (through installing the extension), that configuration is owned by the site, not the extension. This means that future updates of the extension will not override the site''s active configuration for that extension.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8959, '<em>Taxonomy</em> is used to classify website content. One common example of taxonomy is the tags used to classify or categorize posts in a blog website; a cooking website could use an ingredients taxonomy to classify recipes. Individual taxonomy items are known as <em>terms</em> (the blog tags or recipe ingredients in these examples); and a set of terms is known as a <em>vocabulary</em> (the set of all blog post tags, or the set of all recipe ingredients in these examples). Technically, taxonomy terms are an entity type and the entity subtypes are the vocabularies; see @content_structure_topic for more on content entities. Like other entities, taxonomy terms can have fields attached; for instance, you could set up an image field to contain an icon for each term.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (192, 'Free tagging', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9177, 'In order to follow these steps to edit settings in place, the core Settings Tray module must be installed. Also, either the core Toolbar module or a contributed replacement must be installed. You will need to have <em>Use contextual links</em> permission, as well as permission to edit the particular content or settings.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8173, 'Review the permissions for the role, paying particular attention to the permissions marked with <em>Warning: Give to trusted roles only; this permission has security implications.</em> Uncheck permissions that this role should not have, in the row of the permission and the column of the role; check permissions that this role should have.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9793, '<a href="https://www.drupal.org/docs/user_guide/en/blocks-chapter.html">Blocks (Drupal User Guide)</a>', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5613, 'Disabling drag-and-drop functionality', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (10739, 'If you have the core Update Status module installed, in the <em>Manage</em> administrative menu, navigate to <em>Reports</em> &gt; <em>Available updates</em> to see a report of the updates that are available for your site software. If <em>Last checked</em> is far in the past, click <em>Check manually</em> to update the report. Scan the report; if the core software or any modules or themes have security updates available, you should update them as soon as possible.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9913, '<a href="https://www.drupal.org/docs/user_guide/en/security-chapter.html">Security and Maintenance (Drupal User Guide)</a>, which includes information on how to update your site''s core software, modules, and themes.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9868, 'A help topic describes a concept, or steps to accomplish a task, related to a feature provided by one or more modules or themes. If the core Search module is enabled, these topics are also searchable.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9872, 'Modules and themes can provide help topics as Twig-file-based plugins in a project sub-directory called <em>help_topics</em>; plugin metadata is provided in YAML front matter within each Twig file. Plugin-based help topics provided by modules and themes will automatically be updated when a module or theme is updated. Use the plugins in <em>core/modules/help/help_topics</em> as a guide when writing and formatting a help topic plugin for your theme or module.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8305, 'The core Search module organizes site search into <em>pages</em>. Each page allows users to search a particular type of content with a particular configuration. The configuration includes specifying a URL that starts with <em>search</em>, a name for the page, and additional options for some search page types.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (8313, 'There are two main limitations of the core Search module. First, it is not appropriate for very large sites -- if you have a large site, look into other search technologies like Apache Solr. Second, the Node search page type only supports exact keyword matching, which is not the behavior that most users will expect. You can improve this by installing a language-specific stemming module for your language (such as <a href="https://www.drupal.org/project/porterstemmer">Porter Stemmer</a> for American English), which makes it so that, for example, a search for the word walk would match pages containing the words walk, walking, and walked.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (10740, 'In order to configure site search using the core Search module, you will need to configure one or more search pages. You will also need to verify or alter permissions so that the desired user roles can search the site. (See @user_overview_topic for more information about roles and permissions.) For content search, you will also need to make sure that the search index is configured and that the site is fully indexed. Finally, you may wish to place the <em>Search form</em> block on pages of your site, or add the search page to a navigation menu, to give users easy access to search. See the related topics listed below for specific tasks.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9688, 'A feed of announcements about the Drupal project and Drupal Association programs.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9689, 'The purpose of this feed is to provide a channel for outreach directly to Drupal site owners. This content must be highly relevant to site owners interests, serve the strategic goals of the project, and/or promote the sustainability of the project and the Drupal Association.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (10764, 'Uninstall module', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (10765, 'Admin Toolbar', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (10766, 'Admin Toolbar Search', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7928, '<em>Shortcuts</em> are quick links to administrative pages; they are managed by the core Shortcut module. A site can have one or more <em>shortcut sets</em>, which can be shared by one or more users (by default, there is only one set shared by all users); each set contains a limited number of shortcuts. Users need <em>Use shortcuts</em> permission to view shortcuts; <em>Edit current shortcut set</em> permission to add, delete, or edit the shortcuts in the set assigned to them; and <em>Select any shortcut set</em> permission to select a different shortcut set when editing their user profile. There is also an <em>Administer shortcuts</em> permission, which allows an administrator to do any of these actions, as well as select shortcut sets for other users.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (9322, 'A security advisory is a public announcement about a reported security problem in the core software. Contributed projects with a shield icon and "Stable releases for this project are covered by the security advisory policy" on their project page are also covered by Drupal''s security advisory policy. Security advisories are managed by the <a href="https://www.drupal.org/drupal-security-team">Drupal Security Team</a>.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6119, 'Basic block', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6120, 'A basic block contains a title and a body.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (2181, 'Java', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (2205, 'Your virtual face or picture.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (2987, 'Use <em>articles</em> for time-sensitive content like news, press releases or blog posts.', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (10743, 'Tabbing is no longer constrained by the Contextual module.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (2654, 'Promote content to front page', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (4606, 'Fallback date format', '', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (10299, 'l, j F Y - H:i', 'PHP date format', '11.3.2');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (559, '@site is currently under maintenance. We should be back shortly. Thank you for your patience.', '', '11.3.2');
