INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (10812, 'The Admin Toolbar module enhances the <a href=":toolbar">Toolbar</a> module by providing fast access to all the administrative links at the top of your site. Admin Toolbar remains a very "lightweight" module by closely integrating with all Toolbar functionality. It can be used in conjunction with all the sub modules included on Admin Toolbar, for quick access to system commands such as Flush all caches, <a href=":automated_cron">Run cron</a>, Run Updates, etc.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (10813, 'The Admin Toolbar greatly improves the user experience for those who regularly interact with the site Toolbar by providing fast, full access to all links in the site Toolbar without having to click to get there.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (10814, 'The Admin Toolbar Links Access Filter module provides a workaround for the common problem that users with <em>Use the administration pages and help</em> permission see menu links they done not have access permission for.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (10815, 'To use Admin Toolbar Extra Tools just install it like any other module. There is no other configuration required.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (10816, 'Twig cache cleared.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (10817, 'The Admin Toolbar Extra Tools module comes packaged with the <a href=":admin-toolbar">Admin Toolbar</a> module and adds functionality to it. The additional functionality is accessed through extra links on the main administration Toolbar. Some links to Admin Toolbar Extra Tools administration pages are located at the bottom of this page.</a>', '', 'none');
