INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (10938, 'Allows assigning meta tags to be used on custom routes, equivalent to custom paths.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (10939, 'Adds individual permissions for each meta tag, allowing for fine-grained access to the meta tags. Note: this may lead to performance issues on the permissions admin page, please see the included README.txt file for details.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (10940, 'Provides support for applinks.org meta tags.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (10941, 'Provides support to define and manage custom meta tags.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (10942, 'Provides the fifteen <a href="https://dublincore.org/documents/dces/">Dublin Core Metadata Element Set 1.1</a> meta tags from the <a href="https://dublincore.org/">Dublin Core Metadata Institute</a>.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (10943, 'Provides forty additional meta tags from the <a href="https://dublincore.org/">Dublin Core Metadata Institute</a>.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (10944, 'A set of meta tags specially for controlling advanced functionality with Facebook.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (10945, 'Provides support for many different favicons.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (10946, 'Provides support for meta tags used for Google Custom Search Engine.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (10947, 'Provides support for the hreflang meta tag with some extra logic to simplify it.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (10948, 'Provides support for meta tags used to control the mobile browser experience.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (10949, 'Provides support for Open Graph Protocol meta tags.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (10950, 'Provides additional Open Graph Protocol meta tags for describing products.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (10951, 'Provides metatag support for Page Manager variants.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (10952, 'Provides support for Pinterest''s custom meta tags.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (10953, 'Provides support for Twitter''s Card meta tags.', '', '11.3.5');
