INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11295, 'The Pathauto module provides a mechanism to automate the creation of <a href="path">path</a> aliases. This makes URLs more readable and helps search engines index content more effectively.  For more information, see the <a href=":online">online documentation for Pathauto</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11296, 'Pathauto is accessed from the tabs it adds to the list of <a href=":aliases">URL aliases</a>.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11297, 'Creating Pathauto Patterns', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11298, 'The <a href=":pathauto_pattern">"Patterns"</a> page is used to configure automatic path aliasing.  New patterns are created here using the <a href=":add_form">Add Pathauto pattern</a> button which presents a form to simplify pattern creation thru the use of <a href="token">available tokens</a>. The patterns page provides a list of all patterns on the site and allows you to edit and reorder them. An alias is generated for the first pattern that applies.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11299, 'The <a href=":settings">"Settings"</a> page is used to customize global Pathauto settings for automated pattern creation.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11300, 'Bulk Generation', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11301, 'The <a href=":pathauto_bulk">"Bulk Generate"</a> page allows you to create URL aliases for items that currently have no aliases. This is typically used when installing Pathauto on a site that has existing un-aliased content that needs to be aliased in bulk.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11302, 'Delete Aliases', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11303, 'The <a href=":pathauto_delete">"Delete Aliases"</a> page allows you to remove URL aliases from items that have previously been assigned aliases using pathauto.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11304, 'You need to select a pattern type, then a pattern and filter, and a label. Additional types can be enabled on the <a href=":settings">Settings</a> page.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11305, 'Enabled entity types', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11306, 'Enable to add a path field and allow to define alias patterns for the given type. Disabled types already define a path field themselves or currently have a pattern.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11307, 'Broken type', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11308, 'AliasType', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11309, 'Bulk generation can be used to generate URL aliases for items that currently have no aliases. This is typically used when installing Pathauto on a site that has existing un-aliased content that needs to be aliased in bulk.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11310, 'It can also be used to regenerate URL aliases for items that have an old alias and for which the Pathauto pattern has been changed.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11311, 'Note that this will only affect items which are configured to have their URL alias automatically set. Items whose URL alias is manually set are not affected.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11312, 'The %element-title doesn''t allow the patterns ending with whitespace.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11313, 'Select the types of paths for which to generate URL aliases', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11314, 'Select which URL aliases to generate', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11315, 'Generate a URL alias for un-aliased paths only', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11316, '<a href=":url">Pathauto settings</a> are set to ignore paths which already have a URL alias. You can only create URL aliases for paths having none.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11317, 'Update the URL alias for paths having an old URL alias', '', 'none');
