INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11320, 'Only delete automatically generated aliases', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11321, 'When checked, aliases which have been manually set are not affected by this mass-deletion.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11322, 'Bulk deleting URL aliases', '', 'none');
