INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11338, 'The <strong>maximum alias length</strong> and <strong>maximum component length</strong> values default to 100 and have a limit of @max from Pathauto. You should enter a value that is the length of the "alias" column of the path_alias database table minus the length of any strings that might get added to the end of the URL. The recommended and default value is 100.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11339, '<strong>Note:</strong> there is no confirmation. Be sure of your action before clicking the "Delete aliases now!" button.<br />You may want to make a backup of the database and/or the path_alias and path_alias_revision tables prior to using this feature.', '', 'none');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11340, 'Provides some extra Twig functions and filters.', '', '11.3.5');
