INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11341, 'Enables the creation of webforms and questionnaires.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11342, 'Provides webform access controls for webform nodes.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11343, 'Provides an element that generates or loads a file that can be attached to a submission or email.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11344, 'Note: This is only to be used with the Drupal Bootstrap Theme, NOT with other Bootstrap Framework related Themes (like Radix).', '', '11.3.5');
