INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11345, 'Provides a ''Card'' container element for fast clientside multistep form pagination.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11346, 'Helps support Webform Clientside Validation integration.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11347, 'Provides an example of custom configuration form built using the Webform module.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11348, 'Provides a webform element for converting HTML or SVG markup into a selectable single or multiple options input.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11349, 'Demonstrates how to use the Webform module to build an application/evaluation system.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11350, 'Demonstrates how to use the Webform module to build an event registration system with email reminders.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11351, 'Demonstrates how to use the Webform module to build a region based contact system.', '', '11.3.5');
