INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11353, 'Provides an example that shows how to create a Webform element.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11354, 'Provides an example that shows how to add custom properties to Webform elements.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11355, 'Provides Entity Print (PDF) integration and allows site builders to download, export, and email PDF copies of webform submissions.', '', '11.3.5');
