INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11361, 'Provides a webform element for a selecting an image.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11362, 'Provides a group of multiple buttons used for selecting a value. jQueryUI is no longer maintained.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11363, 'Provides jQueryUI datepicker support for date and datetime elements. jQueryUI is no longer maintained.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11364, 'Provides a Webform content type which allows webforms to be integrated into a website as nodes.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11365, 'Allows elements with options (i.e. select, checkboxes, and radios) to have option specific submission limits.', '', '11.3.5');
