INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11608, 'Omit the ''?'' to output all values. Output all values as HTML using [webform_submission:values:html].', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11609, 'To output individual elements, replace the ''?'' with…', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11610, 'All items after the ''element_key'' are optional.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11611, 'The ''delta'' is the numeric index for specific value', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11612, 'The ''sub_element_key'' is a composite element''s sub element key.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11613, 'The ''checked''  or ''selected'' looks to see if an ''option_value'' is checked or selected for an options element (select, checkboxes, or radios)', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11614, 'The ''option_value'' is options value for an options element (select, checkboxes, or radios).', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11615, 'The ''format'' can be ''value'', ''raw'', or custom format specifically associated with the element', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11616, 'The ''items'' can be ''comma'', ''semicolon'', ''and'', ''ol'', ''ul'', or custom delimiter', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11617, 'The ''entity:*'' applies to the referenced entity', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11618, 'Add ''html'' at the end of the token to return HTML markup instead of plain text.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11619, 'For example, to display the Contact webform''s ''Subject'' element''s value you would use the [webform_submission:values:subject] token.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11620, 'Learn about submission value tokens', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11621, 'Webform tokens from submitted data.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11622, 'Learn about Webform settings tokens', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11623, 'Webform settings tokens.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11624, 'Replace the ''?'' with…', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11625, 'For example, to display an email element''s title (aka #title) you would use the [webform:element:email:title] token.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11626, 'Learn about element property tokens', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11627, 'Webform element property tokens.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11628, 'For example, to display a remote post''s confirmation number you would use the [webform:handler:remote_post:completed:confirmation_number] token.', '', '11.3.5');
