INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11679, 'Code Mirror is used to provide a text editor for YAML, HTML, CSS, and JavaScript configuration settings and messages.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11680, 'jQuery: Input Mask', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11681, 'Input masks are used to ensure predefined and custom formats for text fields.', '', '11.3.5');
