INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11684, 'jQuery: RateIt', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11685, 'RateIt is used to provide a customizable rating element.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11686, 'jQuery: Select2', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11687, 'Select2 is used to improve the user experience for select menus. Select2 is the recommended select menu enhancement library.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11688, 'jQuery: Text Counter', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11689, 'Word or character counting, with server-side validation, is available for text fields and text areas.', '', '11.3.5');
