INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6372, 'The trusted_host_patterns setting is not configured in settings.php. This can lead to security vulnerabilities. It is <strong>highly recommended</strong> that you configure this. See <a href=":url">Protecting against HTTP HOST Header attacks</a> for more information.', '', '11.3.5');
