INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6302, 'If the site is experiencing problems with permissions to content, you may have to rebuild the permissions cache. Rebuilding will remove all privileges to content and replace them with permissions based on the current modules and settings. Rebuilding may take some time if there is a lot of content or complex permission settings. After rebuilding has completed, content will automatically use the new permissions. <a href=":rebuild">Rebuild permissions</a>', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11729, 'Your server is capable of displaying file upload progress, but does not have the required libraries. It is recommended to install the <a href="https://github.com/php/pecl-php-uploadprogress#installation">PECL uploadprogress library</a>.', '', '11.3.5');
