INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12119, 'Metatag values for the current page.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12120, 'The number of seconds to wait before refreshing the page. May also force redirect to another page using the format ''5; url=https://example.com/'', which would be triggered after five seconds.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12121, 'Define the author of a page.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12122, 'Used to rate content for audience appropriateness. This tag has little known influence on search engine rankings, but can be used by browsers, browser extensions, and apps. The <a href=''https://www.metatags.org/meta_name_rating''>most common options</a> are general, mature, restricted, 14 years, safe for kids. If you follow the <a href=''https://www.rtalabel.org/index.php?content=howto''>RTA Documentation</a> you should enter RTA-5042-1996-1400-1577-RTA', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12123, 'Used to control whether a browser caches a specific page locally. Not commonly used. Should be used in conjunction with the Pragma meta tag.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12124, 'Control when the browser''s internal cache of the current page should expire. The date must to be an <a href=''https://www.csgnetwork.com/timerfc1123calc.html''>RFC-1123</a>-compliant date string that is represented in Greenwich Mean Time (GMT), e.g. ''Thu, 01 Sep 2016 00:12:56 GMT''. Set to ''0'' to stop the page being cached entirely.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12125, 'A location''s formal name.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12126, 'Geo-spatial information in ''latitude; longitude'' format, e.g. ''50.167958; -97.133185''; <a href=''https://en.wikipedia.org/wiki/Geographic_coordinate_system'' aria-label=''see Wikipedia for details on the geographic coordinate system''>see Wikipedia for details</a>.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12127, 'A location''s two-letter international country code, with an optional two-letter region, e.g. ''US-NH'' for New Hampshire in the USA.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (11147, 'Describes the name and version number of the software or publishing tool used to create the page.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12128, 'This meta tag communicates with Google. There are currently two directives supported: ''nositelinkssearchbox'' to not to show the sitelinks search box, and ''notranslate'' to ask Google not to offer a translation of the page. Both options may be added, just separate them with a comma. See <a href=''https://support.google.com/webmasters/answer/79812?hl=en''>meta tags that Google understands</a> for further details.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12129, 'Geo-spatial information in ''latitude, longitude'' format, e.g. ''50.167958, -97.133185''; <a href=''https://en.wikipedia.org/wiki/ICBM_address'' aria-label=''see Wikipedia for details on ICBM addresses''>see Wikipedia for details</a>.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12130, 'An image associated with this page, for use as a thumbnail in social networks and other services.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12131, 'A brief URL, often created by a URL shortening service.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12132, 'Used for paginated content by providing URL with rel=''next'' link.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12133, 'Used to indicate the URL that broke the story, and can link to either an internal URL or an external source. If the full URL is not known it is acceptable to use a partial URL or just the domain name.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12134, 'Used to control whether a browser caches a specific page locally. Not commonly used. Should be used in conjunction with the Cache-Control meta tag.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12135, 'Used for paginated content by providing URL with rel=''prev'' link.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12136, 'Indicate to search engines and other page scrapers whether or not links should be followed. See <a href=''https://w3c.github.io/webappsec/specs/referrer-policy/''>the W3C specifications</a> for further details. Note: this serves the same purpose as the HTTP header by the same name.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12137, 'Tell search engines when to index the page again. Very few search engines support this tag, it is more useful to use an <a href=''https://www.drupal.org/project/xmlsitemap''>XML Sitemap</a> file.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12138, 'Details about intellectual property, such as copyright or trademarks; does not automatically protect the site''s content or intellectual property.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12139, '<a href=''https://www.metatags.org/meta_http_equiv_set_cookie''>Sets a cookie</a> on the visitor''s browser. Can be in either NAME=VALUE format, or a more verbose format including the path and expiration date; see the link for full details on the syntax.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12140, 'A link to the preferred page location or URL of the content of this page, to help eliminate duplicate content penalties from search engines.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12141, 'A brief and concise summary of the page''s content, preferably 150 characters or less. Where as the description meta tag may be used by search engines to display a snippet about the page in search results, the abstract tag may be used to archive a summary about the page. This meta tag is <em>no longer</em> supported by major search engines.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12142, 'A brief and concise summary of the page''s content that is a maximum of 160 characters in length. The description meta tag may be used by search engines to display a snippet about the page in search results.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12143, 'A comma-separated list of keywords about the page. This meta tag is <em>no longer</em> supported by most search engines.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12144, 'The text to display in the title bar of a visitor''s web browser when they view this page. This meta tag may also be used as the title of the page when a visitor bookmarks or favorites this page, or as the page title in a search engine result. It is common to append ''[site:name]'' to the end of this, so the site''s name is automatically added. It is recommended that the title is no greater than 55 - 65 characters long, including spaces.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12145, 'A comma-separated list of Facebook user IDs of people who are considered administrators or moderators of this page.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12146, 'Facebook Instant Articles claim URL token.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12147, 'A comma-separated list of Facebook Platform Application IDs applicable for this site.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12148, 'The roles of the actor(s).', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12149, 'Links to the Facebook profiles for actor(s) that appear in the video.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12320, 'Duração do curso (semestres)', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12151, 'The height of the above video(s). Note: if both the unsecured and secured videos are provided, they should both be the same size.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12152, 'Links an article to an author''s Facebook profile, should be either URLs to the author''s profile page or their Facebook profile IDs.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12153, 'The date this content will expire, with an optional time value. Needs to be in <a href=''https://en.wikipedia.org/wiki/ISO_8601''>ISO 8601</a> format.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12154, 'The date this content was last modified, with an optional time value. Needs to be in <a href=''https://en.wikipedia.org/wiki/ISO_8601''>ISO 8601</a> format.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12155, 'The date this content was published on, with an optional time value. Needs to be in <a href=''https://en.wikipedia.org/wiki/ISO_8601''>ISO 8601</a> format.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12156, 'Links an article to a publisher''s Facebook page.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12157, 'The primary section of this website the content belongs to.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12158, 'Appropriate keywords for this content.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12159, 'The secure URL to an audio file that complements this object. All ''http://'' URLs will automatically be converted to ''https://''.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12160, 'The MIME type of the audio file. Examples include ''application/mp3'' for an MP3 file.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12161, 'The URL to an audio file that complements this object.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12162, 'Links a book to an author''s Facebook profile, should be either URLs to the author''s profile page or their Facebook profile IDs.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12163, 'The date this content was last modified, with an optional time value. Needs to be in <a href=''https://en.wikipedia.org/wiki/ISO_8601''>ISO 8601</a> format. Can be the same as the ''Article modification date'' tag.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12164, 'The fediverse @username for the content creator / author for this page, including the first @ symbol.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12165, 'The date the book was released.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12166, 'A one to two sentence description of the content.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12167, 'The word that appears before the content''s title in a sentence. The default ignores this value, the ''Automatic'' value should be sufficient if this is actually needed.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12168, 'Links to the Facebook profiles for director(s) that worked on the video.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12169, 'Any of Facebook''s gender values should be allowed, the initial two being ''male'' and ''female''.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12170, 'The locale these tags are marked up in, must be in the format language_TERRITORY. Default is ''en_US''.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12171, 'A description of what is in the image, not a caption. If the page specifies an og:image it should specify og:image:alt.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12172, 'The height of the above image(s). Note: if both the unsecured and secured images are provided, they should both be the same size.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12173, 'The URL of an image which should represent the content. The image must be at least 200 x 200 pixels in size; 600 x 316 pixels is a recommended minimum size, and for best results use an image least 1200 x 630 pixels in size. Supports PNG, JPEG and GIF formats. Should not be used if og:image:url is used. Note: if multiple images are added many services (e.g. Facebook) will default to the largest image, not specifically the first one.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12174, 'The secure URL (HTTPS) of an image which should represent the content. The image must be at least 200 x 200 pixels in size; 600 x 316 pixels is a recommended minimum size, and for best results use an image least 1200 x 630 pixels in size. Supports PNG, JPEG and GIF formats.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12175, 'A alternative version of og:image and has exactly the same requirements; only one needs to be used.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12176, 'The width of the above image(s). Note: if both the unsecured and secured images are provided, they should both be the same size.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12177, 'The Book''s ISBN', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12178, 'The first name of the person who''s Profile page this is.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12179, 'A pseudonym / alias of this person.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12180, 'A human-readable name for the site, e.g., <em>IMDb</em>.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12181, 'Preferred page location or URL to help eliminate duplicate content for search engines, e.g., <em>https://www.imdb.com/title/tt0117500/</em>.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12182, 'The date the video was released.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12183, 'Links to the Facebook profiles for scriptwriter(s) for the video.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12184, 'URLs to related content', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12185, 'The TV show this series belongs to.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12186, 'The person''s last name.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12187, 'Tag words associated with this video.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12188, 'The type of the content, e.g., <em>movie</em>.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12189, 'The type of image referenced above. Should be either ''image/gif'' for a GIF image, ''image/jpeg'' for a JPG/JPEG image, or ''image/png'' for a PNG image. Note: there should be one value for each image, and having more than there are images may cause problems.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12190, 'The title of the content, e.g., <em>The Rock</em>.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12191, 'The URL of an video which should represent the content. For best results use a source that is at least 1200 x 630 pixels in size, but at least 600 x 316 pixels is a recommended minimum. Object types supported include video.episode, video.movie, video.other, and video.tv_show.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12192, 'The length of the video in seconds', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12193, 'The secure URL (HTTPS) of an video which should represent the content.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12194, 'The type of video referenced above. Should be either  video.episode, video.movie, video.other, and video.tv_show. Note: there should be one value for each video, and having more than there are videos may cause problems.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (1559, 'The MIME type of the file.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12195, 'Content Full', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12196, 'output as', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (604, 'fields', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (4496, 'Hide block if the view output is empty', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (1874, 'This title will be displayed with the view, wherever titles are normally displayed; i.e, as the page title, block title, etc.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (4455, 'Alter the HTTP response status code used by this view, mostly helpful for empty results.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (4931, 'Displays messages in an area.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (10756, 'Enable this to use tokens from fields in the first result row, if present. Global tokens (e.g., site name) and contextual argument tokens are always available.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12197, 'Webform submission limits', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6439, 'Changing the title here means it cannot be dynamically altered anymore. (Try changing it directly in <a href=":url">@name</a>.)', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12321, 'Previsão de formatura', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12322, 'Disponibilidade para estágio', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12323, 'Número de matrícula', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (4460, 'You must add some additional fields to this display before using this field. These fields may be marked as <em>Exclude from display</em> if you prefer. Note that due to rendering order, you cannot use fields that come after this field; if you need a field not listed here, rearrange your fields.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5852, 'The following replacement tokens are available for this field. Note that due to rendering order, you cannot use fields that come after this field; if you need a field not listed here, rearrange your fields.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (3270, 'Enable to load this field as hidden. Often used to group fields, or to use as token in another field.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (4103, 'If checked, field api classes will be added by field templates. This is not recommended unless your CSS depends upon these classes. If not checked, template will not be used.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7654, 'The text to display for this field. You may enter data from this view as per the "Replacement patterns" below. You may include <a href="@twig_docs">Twig</a> or the following allowed HTML tags: <code>@tags</code>', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (1656, 'The Drupal path or absolute URL for this link. You may enter data from this view as per the "Replacement patterns" below.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (3617, 'Text to place as "title" text which most browsers display as a tooltip when hovering over the link.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (1663, 'If checked, this field be trimmed only on a word boundary. This is guaranteed to be the maximum characters stated or less. If there are no word boundaries this could trim a field to nothing.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (5993, 'This can be an internal Drupal path such as node/add or an external URL such as "https://www.drupal.org". You may use the "Replacement patterns" above.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (3158, 'List the tags that need to be preserved during the stripping process. example &quot;&lt;p&gt; &lt;br&gt;&quot; which will preserve all p and br elements', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (7306, 'Provide text to display if this field contains an empty result. You may include HTML. You may enter data from this view as per the "Replacement patterns" in the "Rewrite Results" section above.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (3618, 'Enable to hide this field if it is empty. Note that the field label or rewritten output may still be displayed. To hide labels, check the style or row style settings for empty fields. To hide rewritten content, check the "Hide rewriting if empty" checkbox.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (1804, 'The score of the search item. This will not be used if the search filter is not also present.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (3347, 'Provide a simple link to delete the content revision.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12198, '<em class="placeholder">Tecnologias</em>: este campo não aceita mais de 1 valores.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (6859, 'Add the default row classes like @classes to the output. You can use this to quickly reduce the amount of markup the view provides by default, at the cost of making it more difficult to apply CSS.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12199, 'Meta Tags:', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12200, 'length', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12201, 'Separator used with multiple values', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12202, 'Controls the separator used when a meta tag allows multiple values. Multiple characters can be used together, it does not have to be one single character long. Defaults to ":default".', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12203, 'Entity type / Group Mapping', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12204, 'Identify which metatag groups should be available on which entity type / bundle combination. Unselected groups will not appear on the configuration form for that entity type, reducing the size of the form and increasing performance. If no groups are selected for a type, all groups will appear.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12205, 'Use Maxlength module to force these limits?', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12206, 'Install the Maxlength module to enable this option.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12207, 'Trim the Meta Tag after the word on the given value', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12208, 'Trim the Meta Tag on the given value', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12209, 'Trim the Meta Tag before the word on the given value', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12210, 'Trimming options', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12211, 'Characters to trim', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12212, 'A list of characters to trim at the end of all metatags. Provide a single string without any separators, e.g. "|,." (instead of "| , ."). Note that spaces, tabs, new lines, carriage returns and vertical tabs (" \n\r\t\v") will be trimmed automatically and do not need to be listed in this field. The trimming is applied at the very end after the tag is trimmed for length, and after the trimming option was executed.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12213, 'Optional suffix to add', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12214, 'If provided this string will be added at the end of all meta tags that are trimmed to length.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12215, 'Metatag Trimming Options', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12216, 'Many Meta-Tags can be trimmed on a specific length for search engine optimization.<br/>If the value is set to ''0'' or left empty, the whole Metatag will be untrimmed.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12217, 'eg 500px or 8rem', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12218, 'Scroll maximum height', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12219, 'To enable scrolling please enter a value and its units, e.g. 500px, 8rem, etc. Removing this value will remove the scroll.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12220, 'Metatag widget options', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12221, 'Various options for the field widget used on entity forms, e.g. on content type forms.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12222, 'Configure the Metatag module', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12223, 'Inherits meta tags from: @inherits', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12224, 'Add meta tag for custom route', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12225, 'Use tokens to avoid redundant meta data and search engine penalization. For example, a ''keyword'' value of "example" will be shown on all content using this configuration, whereas using the [node:field_keywords] automatically inserts the "keywords" values from the current entity (node, term, etc).', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12226, 'Configure the meta tags below.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12227, 'To use tokens to image fields, the image field on that entity bundle (content type, term, etc) must have the "Token" display settings enabled, the image field must not be hidden, and it must be set to output as an image, e.g. using the "Thumbnail" field formatter. It is also recommended to use an appropriate image style that resizes the image rather than output the original image; see individual meta tag descriptions for size recommendations.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12228, 'Set to %none to disable inheritance of the parent value and prevent the output of this metatag entirely.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12229, 'This will be able to extract the URL from an image field if the field is configured properly.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12230, 'Multiple values may be used, separated by `:delimiter`. Note: Tokens that return multiple values will be handled automatically.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12231, 'Any URLs which start with "http://" will be converted to "https://".', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12232, 'Simple meta tags.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12233, 'index - Allow search engines to index this page (assumed).', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12234, 'follow - Allow search engines to follow links on this page (assumed).', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12235, 'noindex - Prevents search engines from indexing this page.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12236, 'nofollow - Prevents search engines from following links on this page.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12237, 'noarchive - Prevents cached copies of this page from appearing in search results.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12238, 'nosnippet - Prevents descriptions from appearing in search results, and prevents page caching.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12239, 'noimageindex - Prevent search engines from indexing images on this page.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12240, 'notranslate - Prevent search engines from offering to translate this page in search results.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12241, 'Max Snippet', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12242, 'Use a number character as a textual snippet for this search result. "0" equals "nosnippet". "-1" will let the search engine decide the most effective length.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12243, 'Max Video Preview', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12244, 'Use a maximum of number seconds as a video snippet for videos on this page in search results. "0" will use a static a image. "-1" means there is no limit.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12245, 'None - no image preview is to be shown.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12246, 'Standard - a default image preview may be shown.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12247, 'Large - a larger image preview, up to the width of the viewport, may be shown.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12248, 'Max Image Preview', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12249, 'Set the maximum size of an image preview for this page in a search results.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12250, 'Unavailable after date', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12251, 'Do not show this page in search results after the specified date', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12252, 'No Referrer', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12253, 'No Referrer When Downgrade', '', '11.3.5');
