INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12259, 'Meta tags that might not be needed by many sites.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12260, 'The <a href=''https://ogp.me/''>Open Graph meta tags</a> are used to control how Facebook, Pinterest, LinkedIn and other social networking sites interpret the site''s content.<br><br>The Facebook <a href=''https://developers.facebook.com/tools/debug/''>Sharing Debugger</a> lets you preview how your content will look when it''s shared to Facebook and debug any issues with your Open Graph tags.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12261, 'A set of meta tags specially for controlling advanced functionality with <a href='':fb''>Facebook</a>.<br><br>The Facebook <a href=''https://developers.facebook.com/tools/debug/''>Sharing Debugger</a> lets you preview how your content will look when it''s shared to Facebook and debug any issues with your Open Graph tags.', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12262, 'Edit default meta tags for @path', '', '11.3.5');
INSERT INTO public.drupal_locales_source (lid, source, context, version) VALUES (12263, 'Warning: disabling the Global default metatag will prevent any metatags from being used.', '', '11.3.5');
